"use client"

import * as React from 'react'
import { useState, useEffect, useCallback } from 'react'
import { subDays } from "date-fns"
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card'
import { Button } from '@/components/ui/button'

import {
    BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer,
    PieChart, Pie, Cell, AreaChart, Area
} from 'recharts'
import {
    Loader2, TrendingUp, Users, DollarSign, Briefcase, GraduationCap, MapPin
} from 'lucide-react'
import api from '@/lib/api'

const COLORS = ['#0088FE', '#00C49F', '#FFBB28', '#FF8042', '#8884d8', '#82ca9d'];

interface AnalyticsData {
    summary: {
        totalLeads: number
        totalRevenue: number
    }
    charts: {
        status: { status: string; _count: number }[]
        source: { source: string; _count: number }[]
        college: { college: string; _count: number }[]
        location: { location: string; _count: number }[]
    }
}

export default function AnalyticsPage() {
    const [data, setData] = useState<AnalyticsData | null>(null)
    const [isLoading, setIsLoading] = useState(true)
    const [dateRange, _setDateRange] = useState({
        from: subDays(new Date(), 30),
        to: new Date()
    })

    // ✅ FIX: moved above useEffect
    const fetchAnalytics = useCallback(async () => {
        setIsLoading(true)
        try {
            const params = new URLSearchParams({
                startDate: dateRange.from.toISOString(),
                endDate: dateRange.to.toISOString()
            })

            const res = await api.get(`/leads/analytics?${params.toString()}`)
            setData(res.data)
        } catch (error) {
            console.error(error)

            // fallback mock data
            setData({
                summary: { totalLeads: 1250, totalRevenue: 450000 },
                charts: {
                    status: [
                        { status: 'NEW', _count: 450 },
                        { status: 'CONTACTED', _count: 300 },
                        { status: 'INTERESTED', _count: 200 },
                        { status: 'CONVERTED', _count: 150 },
                        { status: 'LOST', _count: 150 }
                    ],
                    source: [
                        { source: 'Website', _count: 600 },
                        { source: 'Google Ads', _count: 300 },
                        { source: 'Referral', _count: 200 },
                        { source: 'LinkedIn', _count: 150 }
                    ],
                    college: [
                        { college: 'IIT Delhi', _count: 45 },
                        { college: 'BITS Pilani', _count: 38 },
                        { college: 'Delhi University', _count: 120 },
                        { college: 'Amity University', _count: 85 },
                        { college: 'Thapar University', _count: 60 }
                    ],
                    location: [
                        { location: 'Delhi', _count: 400 },
                        { location: 'Mumbai', _count: 350 },
                        { location: 'Bangalore', _count: 300 },
                        { location: 'Pune', _count: 150 },
                        { location: 'Hyderabad', _count: 50 }
                    ]
                }
            })
        } finally {
            setIsLoading(false)
        }
    }, [dateRange])

    useEffect(() => {
        fetchAnalytics()
    }, [fetchAnalytics])

    if (isLoading) {
        return (
            <div className="flex h-[50vh] items-center justify-center">
                <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
            </div>
        )
    }

    const statusData = data?.charts?.status?.map((item) => ({
        name: item.status,
        value: item._count
    })) || []

    const sourceData = data?.charts?.source?.map((item) => ({
        name: item.source,
        value: item._count
    })) || []

    const collegeData = data?.charts?.college?.map((item) => ({
        name: item.college,
        value: item._count
    })) || []

    const locationData = data?.charts?.location?.map((item) => ({
        name: item.location,
        value: item._count
    })) || []

    return (
        <div className="space-y-6">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                    <h1 className="text-3xl font-bold tracking-tight">Advanced Analytics</h1>
                    <p className="text-muted-foreground">Deep dive into business performance and demographics.</p>
                </div>
                <div className="flex items-center gap-2">
                    <div className="border rounded-md px-3 py-2 text-sm">
                        Last 30 Days
                    </div>
                    <Button onClick={fetchAnalytics}>
                        Refresh
                    </Button>
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                <Card>
                    <CardHeader>
                        <CardTitle>Total Leads</CardTitle>
                    </CardHeader>
                    <CardContent>
                        {data?.summary?.totalLeads}
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader>
                        <CardTitle>Total Revenue</CardTitle>
                    </CardHeader>
                    <CardContent>
                        ₹{data?.summary?.totalRevenue?.toLocaleString()}
                    </CardContent>
                </Card>
            </div>
        </div>
    )
}

"use client"

import * as React from 'react'
import { useState, useEffect, useCallback } from 'react'
import { useRouter } from 'next/navigation'
import { Card, CardContent } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Textarea } from '@/components/ui/textarea'
import { Badge } from '@/components/ui/badge'
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
} from "@/components/ui/dialog"
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table"
import {
    Eye,
    CheckCircle,
    XCircle,
    Clock,
    Archive,
    Loader2,
    BookOpen,
    Video,
    Users
} from 'lucide-react'
import api from '@/lib/api'

interface PendingCourse {
    id: string
    title: string
    description: string
    category: string
    courseType: 'RECORDED' | 'LIVE' | 'HYBRID'
    difficulty: string
    publishStatus: 'DRAFT' | 'IN_REVIEW' | 'PUBLISHED' | 'ARCHIVED'
    submittedForReviewAt?: string
    instructorId: string
    price: number
    _count?: {
        modules: number
        enrollments: number
    }
}

export default function CourseReviewPage() {
    const router = useRouter()
    const [courses, setCourses] = useState<PendingCourse[]>([])
    const [isLoading, setIsLoading] = useState(true)
    const [selectedCourse, setSelectedCourse] = useState<PendingCourse | null>(null)
    const [isDialogOpen, setIsDialogOpen] = useState(false)
    const [reviewNotes, setReviewNotes] = useState('')
    const [isProcessing, setIsProcessing] = useState(false)
    const [filter, setFilter] = useState<'ALL' | 'IN_REVIEW' | 'DRAFT'>('IN_REVIEW')

    // ✅ FIX: moved above useEffect
    const fetchCourses = useCallback(async () => {
        setIsLoading(true)
        try {
            const res = await api.get('/admin/courses/pending', {
                params: { status: filter }
            })
            setCourses(res.data.courses || [])
        } catch (error) {
            console.error('Failed to fetch pending courses:', error)

            // Mock data fallback
            setCourses([
                {
                    id: '1',
                    title: 'Advanced React Patterns',
                    description: 'Learn advanced React patterns including compound components...',
                    category: 'Development',
                    courseType: 'RECORDED',
                    difficulty: 'ADVANCED',
                    publishStatus: 'IN_REVIEW',
                    submittedForReviewAt: new Date().toISOString(),
                    instructorId: 'inst1',
                    price: 2999,
                    _count: { modules: 8, enrollments: 0 }
                },
                {
                    id: '2',
                    title: 'Live Python Bootcamp',
                    description: 'Comprehensive Python course with live sessions...',
                    category: 'Development',
                    courseType: 'LIVE',
                    difficulty: 'BEGINNER',
                    publishStatus: 'IN_REVIEW',
                    submittedForReviewAt: new Date().toISOString(),
                    instructorId: 'inst2',
                    price: 4999,
                    _count: { modules: 12, enrollments: 0 }
                }
            ])
        } finally {
            setIsLoading(false)
        }
    }, [filter])

    useEffect(() => {
        fetchCourses()
    }, [fetchCourses])

    const handleApprove = async (course: PendingCourse) => {
        setIsProcessing(true)
        try {
            await api.patch(`/admin/courses/${course.id}/approve`, { notes: reviewNotes })
            setCourses(courses.filter(c => c.id !== course.id))
            setIsDialogOpen(false)
            setSelectedCourse(null)
            setReviewNotes('')
        } catch (error) {
            console.error('Failed to approve course:', error)
            alert('Failed to approve course')
        } finally {
            setIsProcessing(false)
        }
    }

    const handleReject = async (course: PendingCourse) => {
        if (!reviewNotes.trim()) {
            alert('Please provide rejection notes')
            return
        }
        setIsProcessing(true)
        try {
            await api.patch(`/admin/courses/${course.id}/reject`, { notes: reviewNotes })
            setCourses(courses.filter(c => c.id !== course.id))
            setIsDialogOpen(false)
            setSelectedCourse(null)
            setReviewNotes('')
        } catch (error) {
            console.error('Failed to reject course:', error)
            alert('Failed to reject course')
        } finally {
            setIsProcessing(false)
        }
    }

    const handleArchive = async (courseId: string) => {
        if (!confirm('Are you sure you want to archive this course?')) return
        try {
            await api.patch(`/admin/courses/${courseId}/archive`)
            fetchCourses()
        } catch (error) {
            console.error('Failed to archive course:', error)
        }
    }

    const getCourseTypeIcon = (type: string) => {
        switch (type) {
            case 'LIVE': return <Users className="h-4 w-4 text-green-600" />
            case 'HYBRID': return <Video className="h-4 w-4 text-orange-600" />
            default: return <BookOpen className="h-4 w-4 text-blue-600" />
        }
    }

    const getStatusBadge = (status: string) => {
        switch (status) {
            case 'IN_REVIEW':
                return <Badge variant="outline">In Review</Badge>
            case 'PUBLISHED':
                return <Badge variant="outline">Published</Badge>
            case 'ARCHIVED':
                return <Badge variant="outline">Archived</Badge>
            default:
                return <Badge>Draft</Badge>
        }
    }

    return (
        <div className="space-y-6">
            <h1 className="text-3xl font-bold">Course Review</h1>

            <Card>
                <CardContent className="pt-6">
                    {isLoading ? (
                        <Loader2 className="animate-spin" />
                    ) : (
                        courses.map(course => (
                            <div key={course.id}>{course.title}</div>
                        ))
                    )}
                </CardContent>
            </Card>
        </div>
    )
}

'use client'

import React, { useState, useEffect } from 'react'
import { Button } from '@/components/ui/button'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { Separator } from '@/components/ui/separator'
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from '@/components/ui/dialog'
import { Textarea } from '@/components/ui/textarea'
import { useToast } from '@/components/ui/use-toast'
import api from '@/lib/api'
import { Mail, Phone, Building2, Calendar, CheckCircle, XCircle, Clock, Loader2 } from 'lucide-react'

interface EmployerRequest {
  id: string
  name: string
  designation: string
  email: string
  phone?: string
  status: 'PENDING' | 'APPROVED' | 'REJECTED'
  adminNotes?: string
  rejectionReason?: string
  createdAt: string
  updatedAt: string
}

export default function EmployerRequestsPage() {
  const { toast } = useToast()
  const [requests, setRequests] = useState<EmployerRequest[]>([])
  const [isLoading, setIsLoading] = useState(true)
  const [filterStatus, setFilterStatus] = useState<'ALL' | 'PENDING' | 'APPROVED' | 'REJECTED'>('PENDING')
  const [actionLoading, setActionLoading] = useState<string | null>(null)
  const [_selectedRequest, setSelectedRequest] = useState<EmployerRequest | null>(null)
  const [rejectionReason, setRejectionReason] = useState('')
  const [adminNotes, setAdminNotes] = useState('')

  useEffect(() => {
    fetchRequests()
  }, [filterStatus])

  const fetchRequests = async () => {
    setIsLoading(true)
    try {
      const params = filterStatus === 'ALL' ? {} : { status: filterStatus }
      const response = await api.get('/employer-requests', { params })
      setRequests(response.data.data || [])
    } catch (error) {
      console.error('Failed to fetch employer requests:', error)
      toast({
        title: 'Error',
        description: 'Failed to fetch employer requests',
        variant: 'destructive',
      })
    } finally {
      setIsLoading(false)
    }
  }

  const handleApprove = async (request: EmployerRequest) => {
    setActionLoading(request.id)
    try {
      const _response = await api.put(`/employer-requests/${request.id}/approve`, {
        adminNotes: adminNotes || null,
      })

      toast({
        title: 'Success',
        description: 'Employer request approved successfully',
      })

      // Refresh the list
      await fetchRequests()
      setAdminNotes('')
    } catch (error: any) {
      console.error('Failed to approve request:', error)
      toast({
        title: 'Error',
        description: error.response?.data?.message || 'Failed to approve request',
        variant: 'destructive',
      })
    } finally {
      setActionLoading(null)
    }
  }

  const handleReject = async (request: EmployerRequest) => {
    if (!rejectionReason.trim()) {
      toast({
        title: 'Error',
        description: 'Rejection reason is required',
        variant: 'destructive',
      })
      return
    }

    setActionLoading(request.id)
    try {
      const _response = await api.put(`/employer-requests/${request.id}/reject`, {
        rejectionReason: rejectionReason.trim(),
      })

      toast({
        title: 'Success',
        description: 'Employer request rejected',
      })

      // Refresh the list
      await fetchRequests()
      setRejectionReason('')
      setSelectedRequest(null)
    } catch (error: any) {
      console.error('Failed to reject request:', error)
      toast({
        title: 'Error',
        description: error.response?.data?.message || 'Failed to reject request',
        variant: 'destructive',
      })
    } finally {
      setActionLoading(null)
    }
  }

  const getStatusBadge = (status: string) => {
    switch (status) {
      case 'PENDING':
        return <Badge variant="outline" className="bg-yellow-50 text-yellow-700 border-yellow-300"><Clock className="h-3 w-3 mr-1" /> Pending</Badge>
      case 'APPROVED':
        return <Badge variant="outline" className="bg-green-50 text-green-700 border-green-300"><CheckCircle className="h-3 w-3 mr-1" /> Approved</Badge>
      case 'REJECTED':
        return <Badge variant="outline" className="bg-red-50 text-red-700 border-red-300"><XCircle className="h-3 w-3 mr-1" /> Rejected</Badge>
      default:
        return null
    }
  }

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
    })
  }

  const filteredRequests = requests.filter(req =>
    filterStatus === 'ALL' || req.status === filterStatus
  )

  return (
    <div className="space-y-6 p-6 max-w-7xl mx-auto">
      {/* Header */}
      <div>
        <h1 className="text-3xl font-bold">Employer Requests</h1>
        <p className="text-muted-foreground mt-2">
          Manage and approve employer requests to post jobs on TechWell
        </p>
      </div>

      {/* Filter Tabs */}
      <div className="flex gap-4 border-b">
        {(['PENDING', 'APPROVED', 'REJECTED', 'ALL'] as const).map(status => (
          <Button
            key={status}
            variant={filterStatus === status ? 'default' : 'ghost'}
            onClick={() => setFilterStatus(status)}
            className="text-base"
          >
            {status === 'ALL' ? 'All' : status.charAt(0) + status.slice(1).toLowerCase()}
            <span className="ml-2 text-sm opacity-70">
              {status === 'ALL'
                ? requests.length
                : requests.filter(r => r.status === status).length}
            </span>
          </Button>
        ))}
      </div>

      {/* Requests List */}
      {isLoading ? (
        <div className="flex items-center justify-center py-12">
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
      ) : filteredRequests.length === 0 ? (
        <Card>
          <CardContent className="text-center py-12">
            <Building2 className="h-12 w-12 text-muted-foreground mx-auto mb-4 opacity-40" />
            <h3 className="text-lg font-semibold mb-2">No employer requests</h3>
            <p className="text-muted-foreground">
              {filterStatus === 'PENDING'
                ? 'No pending employer requests at this time'
                : `No ${filterStatus.toLowerCase()} employer requests`}
            </p>
          </CardContent>
        </Card>
      ) : (
        <div className="grid gap-4">
          {filteredRequests.map(request => (
            <Card key={request.id} className="hover:shadow-md transition-shadow">
              <CardContent className="p-6">
                <div className="flex items-start justify-between mb-4">
                  <div className="flex-1">
                    <div className="flex items-center gap-3 mb-2">
                      <h3 className="text-lg font-bold">{request.name}</h3>
                      {getStatusBadge(request.status)}
                    </div>
                    <p className="text-sm text-muted-foreground">{request.designation}</p>
                  </div>
                  <div className="text-right text-xs text-muted-foreground">
                    <div className="flex items-center gap-1 mb-1">
                      <Calendar className="h-3 w-3" />
                      {formatDate(request.createdAt)}
                    </div>
                  </div>
                </div>

                <Separator className="my-4" />

                {/* Contact Information */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
                  <div className="flex items-center gap-3">
                    <Mail className="h-4 w-4 text-muted-foreground" />
                    <div>
                      <p className="text-xs text-muted-foreground">Email</p>
                      <p className="font-medium break-all">{request.email}</p>
                    </div>
                  </div>
                  {request.phone && (
                    <div className="flex items-center gap-3">
                      <Phone className="h-4 w-4 text-muted-foreground" />
                      <div>
                        <p className="text-xs text-muted-foreground">Phone</p>
                        <p className="font-medium">{request.phone}</p>
                      </div>
                    </div>
                  )}
                </div>

                {/* Admin Notes (if approved) */}
                {request.status === 'APPROVED' && request.adminNotes && (
                  <div className="bg-blue-50 dark:bg-blue-950/20 border border-blue-200 dark:border-blue-900 rounded p-3 mb-4">
                    <p className="text-xs font-semibold text-blue-900 dark:text-blue-200 mb-1">Admin Notes</p>
                    <p className="text-sm text-blue-800 dark:text-blue-300">{request.adminNotes}</p>
                  </div>
                )}

                {/* Rejection Reason (if rejected) */}
                {request.status === 'REJECTED' && request.rejectionReason && (
                  <div className="bg-red-50 dark:bg-red-950/20 border border-red-200 dark:border-red-900 rounded p-3 mb-4">
                    <p className="text-xs font-semibold text-red-900 dark:text-red-200 mb-1">Rejection Reason</p>
                    <p className="text-sm text-red-800 dark:text-red-300">{request.rejectionReason}</p>
                  </div>
                )}

                {/* Action Buttons */}
                {request.status === 'PENDING' && (
                  <div className="flex gap-3 mt-4">
                    {/* Approve Dialog */}
                    <Dialog>
                      <DialogTrigger asChild>
                        <Button
                          variant="default"
                          size="sm"
                          className="gap-2"
                        >
                          <CheckCircle className="h-4 w-4" />
                          Approve
                        </Button>
                      </DialogTrigger>
                      <DialogContent>
                        <DialogHeader>
                          <DialogTitle>Approve Employer Request</DialogTitle>
                          <DialogDescription>
                            Approve the request from {request.name} to enable job posting
                          </DialogDescription>
                        </DialogHeader>
                        <div className="space-y-4">
                          <div>
                            <p className="text-sm font-medium mb-2">Admin Notes (Optional)</p>
                            <Textarea
                              placeholder="Add any notes for your records..."
                              value={adminNotes}
                              onChange={(e) => setAdminNotes(e.target.value)}
                              className="min-h-24"
                            />
                          </div>
                          <div className="flex justify-end gap-3">
                            <Button variant="outline" onClick={() => {
                              setAdminNotes('')
                            }}>
                              Cancel
                            </Button>
                            <Button
                              onClick={() => handleApprove(request)}
                              disabled={actionLoading === request.id}
                            >
                              {actionLoading === request.id ? 'Approving...' : 'Approve Request'}
                            </Button>
                          </div>
                        </div>
                      </DialogContent>
                    </Dialog>

                    {/* Reject Dialog */}
                    <Dialog>
                      <DialogTrigger asChild>
                        <Button
                          variant="destructive"
                          size="sm"
                          className="gap-2"
                        >
                          <XCircle className="h-4 w-4" />
                          Reject
                        </Button>
                      </DialogTrigger>
                      <DialogContent>
                        <DialogHeader>
                          <DialogTitle>Reject Employer Request</DialogTitle>
                          <DialogDescription>
                            Provide a reason for rejecting {request.name}'s request
                          </DialogDescription>
                        </DialogHeader>
                        <div className="space-y-4">
                          <div>
                            <p className="text-sm font-medium mb-2">Rejection Reason *</p>
                            <Textarea
                              placeholder="Please explain why this request is being rejected..."
                              value={rejectionReason}
                              onChange={(e) => setRejectionReason(e.target.value)}
                              className="min-h-24"
                            />
                          </div>
                          <div className="flex justify-end gap-3">
                            <Button variant="outline" onClick={() => {
                              setRejectionReason('')
                            }}>
                              Cancel
                            </Button>
                            <Button
                              variant="destructive"
                              onClick={() => handleReject(request)}
                              disabled={actionLoading === request.id || !rejectionReason.trim()}
                            >
                              {actionLoading === request.id ? 'Rejecting...' : 'Confirm Rejection'}
                            </Button>
                          </div>
                        </div>
                      </DialogContent>
                    </Dialog>
                  </div>
                )}
              </CardContent>
            </Card>
          ))}
        </div>
      )}
    </div>
  )
}

"use client"

import * as React from "react"
import { useState, useEffect } from "react"
import api from "@/lib/api"
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import { Loader2, Check, X, Building2 } from "lucide-react"
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar"

interface EmployerRequest {
    id: string
    companyName: string
    status: string
    createdAt: string
    user: {
        name: string
        email: string
        phone: string
    }
}

export default function AdminEmployersPage() {
    const [requests, setRequests] = useState<EmployerRequest[]>([])
    const [isLoading, setIsLoading] = useState(true)

    useEffect(() => {
        fetchRequests()
    }, [])

    const fetchRequests = async () => {
        try {
            const res = await api.get('/employers/pending')
            setRequests(res.data)
        } catch {
            // Error handling
        } finally {
            setIsLoading(false)
        }
    }

    const handleStatusUpdate = async (id: string, status: 'APPROVED' | 'REJECTED') => {
        try {
            await api.put(`/employers/${id}/status`, { status })
            setRequests(prev => prev.filter(r => r.id !== id))
            alert(`Employer ${status.toLowerCase()} successfully`)
        } catch {
            alert('Failed to update status')
        }
    }

    if (isLoading) return <div className="flex justify-center p-8"><Loader2 className="animate-spin" /></div>

    return (
        <div className="space-y-6">
            <div>
                <h1 className="text-3xl font-bold tracking-tight">Employer Requests</h1>
                <p className="text-muted-foreground">Approve or reject company registration requests.</p>
            </div>

            {requests.length === 0 ? (
                <Card className="p-8 text-center text-muted-foreground">
                    <Building2 className="mx-auto h-12 w-12 mb-4 opacity-50" />
                    <p>No pending employer requests.</p>
                </Card>
            ) : (
                <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
                    {requests.map((req) => (
                        <Card key={req.id}>
                            <CardHeader className="pb-3">
                                <div className="flex justify-between items-start">
                                    <Avatar className="h-10 w-10 border">
                                        <AvatarFallback><Building2 className="h-5 w-5" /></AvatarFallback>
                                    </Avatar>
                                    <Badge variant="outline">{req.status}</Badge>
                                </div>
                                <CardTitle className="mt-4">{req.companyName}</CardTitle>
                                <CardDescription>Registered {new Date(req.createdAt).toLocaleDateString()}</CardDescription>
                            </CardHeader>
                            <CardContent className="space-y-4">
                                <div className="text-sm space-y-1">
                                    <p><span className="font-medium">User:</span> {req.user.name}</p>
                                    <p><span className="font-medium">Email:</span> {req.user.email}</p>
                                    <p><span className="font-medium">Phone:</span> {req.user.phone || 'N/A'}</p>
                                </div>
                                <div className="flex gap-2 pt-2">
                                    <Button
                                        className="w-full bg-green-600 hover:bg-green-700"
                                        size="sm"
                                        onClick={() => handleStatusUpdate(req.id, 'APPROVED')}
                                    >
                                        <Check className="mr-2 h-4 w-4" /> Approve
                                    </Button>
                                    <Button
                                        className="w-full"
                                        variant="destructive"
                                        size="sm"
                                        onClick={() => handleStatusUpdate(req.id, 'REJECTED')}
                                    >
                                        <X className="mr-2 h-4 w-4" /> Reject
                                    </Button>
                                </div>
                            </CardContent>
                        </Card>
                    ))}
                </div>
            )}
        </div>
    )
}

"use client"

import { useAuth } from "@/lib/auth-context"
import { useRouter } from "next/navigation"
import { useEffect, useState } from "react"
import { Loader2 } from "lucide-react"
import { AdminSidebar } from "@/components/admin/AdminSidebar"

export default function AdminLayout({
    children,
}: {
    children: React.ReactNode
}) {
    const { user, isAuthenticated, isLoading } = useAuth()
    const router = useRouter()
    const [mounted, setMounted] = useState(false)

    useEffect(() => {
        setMounted(true)
    }, [])

    useEffect(() => {
        if (!isLoading && mounted) {
            if (!isAuthenticated || !['SUPER_ADMIN', 'ADMIN', 'INSTITUTE_ADMIN', 'STAFF'].includes(user?.role || '')) {
                router.push('/dashboard')
            }
        }
    }, [isLoading, isAuthenticated, user, router, mounted])

    if (isLoading || !mounted) {
        return (
            <div className="h-screen flex items-center justify-center">
                <Loader2 className="h-8 w-8 animate-spin text-primary" />
            </div>
        )
    }

    if (!isAuthenticated || !['SUPER_ADMIN', 'ADMIN', 'INSTITUTE_ADMIN', 'STAFF'].includes(user?.role || '')) {
        return null
    }

    return (
        <div className="flex min-h-screen no-scrollbar">

            {/* Sidebar */}
            <AdminSidebar />

            {/* Main Content */}
            <div className="flex-1 md:ml-64 p-8 bg-muted/10">
                {children}
            </div>

        </div>
    )
}

"use client"

import * as React from 'react'
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Badge } from '@/components/ui/badge'
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs'
import {
    Facebook,
    Globe,
    Phone,
    Check,
    AlertCircle,
    Copy,
    Share2,
    Settings
} from 'lucide-react'
import api from '@/lib/api'

interface Integration {
    id: string
    platform: string
    name: string
    isActive: boolean
    lastSyncAt: string | null
}

export default function LeadIntegrationsPage() {
    const [integrations, setIntegrations] = React.useState<Integration[]>([])
    const [_isLoading, setIsLoading] = React.useState(true)
    const [showConfig, setShowConfig] = React.useState<string | null>(null) // 'META', 'GOOGLE', 'JUSTDIAL'

    // Config Form State
    const [configData, setConfigData] = React.useState({
        platform: '',
        accessToken: '',
        pageId: '',
        accountId: '',
        webhookSecret: '',
        name: ''
    })

    React.useEffect(() => {
        fetchIntegrations()
    }, [])

    const fetchIntegrations = async () => {
        try {
            const res = await api.get('/leads/integrations')
            setIntegrations(res.data)
        } catch {
            // Error handling
        } finally {
            setIsLoading(false)
        }
    }

    const handleSaveConfig = async () => {
        try {
            await api.post('/leads/integrations', configData)
            fetchIntegrations()
            setShowConfig(null)
            setConfigData({ platform: '', accessToken: '', pageId: '', accountId: '', webhookSecret: '', name: '' })
        } catch {
            alert('Failed to connect integration')
        }
    }

    const getWebhookUrl = (platform: string) => {
        if (typeof window === 'undefined') return ''
        // Assuming backend is on same domain/port proxy or configured URL
        // Using window.location.origin as placeholder, normally this is API_URL
        return `https://your-backend-api.com/api/leads/webhook/${platform.toLowerCase()}`
    }

    return (
        <div className="space-y-6">
            <div>
                <h1 className="text-3xl font-bold flex items-center gap-2">
                    <Share2 className="h-8 w-8 text-primary" />
                    Lead Integrations
                </h1>
                <p className="text-muted-foreground">Connect your marketing channels to auto-import leads.</p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">

                {/* Meta Integration */}
                <Card className="border-blue-200 bg-blue-50/20">
                    <CardHeader>
                        <CardTitle className="flex justify-between">
                            <span className="flex items-center gap-2"><Facebook className="h-5 w-5 text-blue-600" /> Meta (Facebook/Insta)</span>
                            {integrations.find(i => i.platform === 'META') ? (
                                <Badge className="bg-green-500">Connected</Badge>
                            ) : (
                                <Badge variant="outline">Disconnected</Badge>
                            )}
                        </CardTitle>
                        <CardDescription>Import leads from Facebook & Instagram Instant Forms.</CardDescription>
                    </CardHeader>
                    <CardContent>
                        {integrations.find(i => i.platform === 'META') ? (
                            <div className="space-y-4">
                                <div className="p-3 bg-muted rounded-md text-sm">
                                    <p className="font-semibold text-xs uppercase text-muted-foreground mb-1">Webhook URL</p>
                                    <code className="text-xs break-all">{getWebhookUrl('META')}</code>
                                </div>
                                <div className="p-3 bg-muted rounded-md text-sm">
                                    <p className="font-semibold text-xs uppercase text-muted-foreground mb-1">Verify Token</p>
                                    <code className="text-xs select-all">techwell_meta_secret</code>
                                </div>
                                <Button variant="outline" className="w-full">Reconfigure</Button>
                            </div>
                        ) : (
                            <Button className="w-full" onClick={() => {
                                setConfigData({ ...configData, platform: 'META', name: 'Facebook Ads' })
                                setShowConfig('META')
                            }}>Connect Facebook</Button>
                        )}
                    </CardContent>
                </Card>

                {/* JustDial Integration */}
                <Card className="border-orange-200 bg-orange-50/20">
                    <CardHeader>
                        <CardTitle className="flex justify-between">
                            <span className="flex items-center gap-2"><Phone className="h-5 w-5 text-orange-600" /> Just Dial</span>
                            {integrations.find(i => i.platform === 'JUSTDIAL') ? (
                                <Badge className="bg-green-500">Connected</Badge>
                            ) : (
                                <Badge variant="outline">Disconnected</Badge>
                            )}
                        </CardTitle>
                        <CardDescription>Receive lead data via JustDial API/Webhook.</CardDescription>
                    </CardHeader>
                    <CardContent>
                        <div className="space-y-4">
                            <div className="p-3 bg-muted rounded-md text-sm">
                                <p className="font-semibold text-xs uppercase text-muted-foreground mb-1">Target URL for JustDial</p>
                                <code className="text-xs break-all">{getWebhookUrl('generic')}</code>
                            </div>
                            {integrations.find(i => i.platform === 'JUSTDIAL') ? (
                                <Button variant="outline" className="w-full" disabled>Connected</Button>
                            ) : (
                                <Button className="w-full" onClick={() => {
                                    setConfigData({ ...configData, platform: 'JUSTDIAL', name: 'JustDial Leads' })
                                    handleSaveConfig() // Just basic activation
                                }}>Activate Listener</Button>
                            )}
                        </div>
                    </CardContent>
                </Card>

                {/* Google My Business */}
                <Card className="border-red-200 bg-red-50/20">
                    <CardHeader>
                        <CardTitle className="flex justify-between">
                            <span className="flex items-center gap-2"><Globe className="h-5 w-5 text-red-600" /> Google Business</span>
                            <Badge variant="secondary">Coming Soon</Badge>
                        </CardTitle>
                        <CardDescription>Sync messages and quote requests from GMB.</CardDescription>
                    </CardHeader>
                    <CardContent>
                        <Button variant="outline" className="w-full" disabled>Connect Google</Button>
                    </CardContent>
                </Card>

            </div>

            {/* Config Dialog (Overlay) */}
            {showConfig === 'META' && (
                <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
                    <Card className="max-w-md w-full">
                        <CardHeader>
                            <CardTitle>Configure Meta Integration</CardTitle>
                            <CardDescription>Enter your Facebook App Token</CardDescription>
                        </CardHeader>
                        <CardContent className="space-y-4">
                            <div className="space-y-2">
                                <Label>Page Access Token</Label>
                                <Input
                                    type="password"
                                    value={configData.accessToken}
                                    onChange={e => setConfigData({ ...configData, accessToken: e.target.value })}
                                />
                                <p className="text-xs text-muted-foreground">Used to fetch lead details from Graph API.</p>
                            </div>
                            <div className="space-y-2">
                                <Label>Page ID (Optional)</Label>
                                <Input
                                    value={configData.pageId}
                                    onChange={e => setConfigData({ ...configData, pageId: e.target.value })}
                                />
                            </div>
                            <div className="flex justify-end gap-2">
                                <Button variant="ghost" onClick={() => setShowConfig(null)}>Cancel</Button>
                                <Button onClick={handleSaveConfig}>Save & Connect</Button>
                            </div>
                        </CardContent>
                    </Card>
                </div>
            )}
        </div>
    )
}

"use client";

import { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Label } from '@/components/ui/label';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Plus, BookOpen, FolderTree, FileText, Upload, Trash2, Edit, Save, X } from 'lucide-react';

import api from '@/lib/api';
import { useToast } from '@/components/ui/use-toast';

interface Category {
    id: string;
    name: string;
    description?: string;
    domains?: Domain[];
}

interface Domain {
    id: string;
    name: string;
    description?: string;
    categoryId: string;
    category?: Category;
    _count?: { resources: number };
}

interface Resource {
    id: string;
    title: string;
    description?: string;
    type: 'PDF' | 'QA';
    domainId: string;
    domain?: Domain;
    views: number;
    downloads: number;
    url?: string;
    content?: Record<string, unknown>;
    isPaid?: boolean;
}

interface QAItem {
    q: string;
    a: string;
}

interface ResourceFormState {
    title: string;
    description: string;
    domainId: string;
    file: File | null;
    qaContent: QAItem[];
    syncToAI: boolean;
    isPaid: boolean;
    publishedAt: string;
}

const initialResourceForm: ResourceFormState = {
    title: '',
    description: '',
    domainId: '',
    file: null,
    qaContent: [{ q: '', a: '' }],
    syncToAI: false,
    isPaid: false,
    publishedAt: ''
};

export default function LibraryManagementPage() {
    const [categories, setCategories] = useState<Category[]>([]);
    const [domains, setDomains] = useState<Domain[]>([]);
    const [resources, setResources] = useState<Resource[]>([]);
    const [loading, setLoading] = useState(true);

    // Form states
    const [showCategoryForm, setShowCategoryForm] = useState(false);
    const [showDomainForm, setShowDomainForm] = useState(false);
    const [showResourceForm, setShowResourceForm] = useState(false);
    const [resourceType, setResourceType] = useState('PDF');

    const [categoryForm, setCategoryForm] = useState({ name: '', description: '', icon: '' });
    const [domainForm, setDomainForm] = useState({ name: '', description: '', categoryId: '' });
    const [resourceForm, setResourceForm] = useState<ResourceFormState>({ ...initialResourceForm });

    const { toast } = useToast();

    useEffect(() => {
        fetchData();
    }, []);

    const fetchData = async () => {
        try {
            const [cats, doms, res] = await Promise.all([
                api.get('/library/categories').then(r => r.data),
                api.get('/library/domains').then(r => r.data),
                api.get('/library/resources').then(r => r.data)
            ]);
            setCategories(cats);
            setDomains(doms);
            setResources(res);
        } catch (error) {
            console.error('Error fetching data:', error);
            toast({
                title: "Error",
                description: "Failed to fetch library data",
                variant: "destructive"
            });
        } finally {
            setLoading(false);
        }
    };

    const handleCreateCategory = async () => {
        if (!categoryForm.name) return;
        try {
            await api.post('/library/categories', categoryForm);
            setCategoryForm({ name: '', description: '', icon: '' });
            setShowCategoryForm(false);
            fetchData();
            toast({
                title: "Success",
                description: "Category created successfully",
            });
        } catch (error) {
            console.error('Error creating category:', error);
            toast({
                title: "Error",
                description: "Failed to create category",
                variant: "destructive"
            });
        }
    };

    const handleCreateDomain = async () => {
        if (!domainForm.name || !domainForm.categoryId) return;
        try {
            await api.post('/library/domains', domainForm);
            setDomainForm({ name: '', description: '', categoryId: '' });
            setShowDomainForm(false);
            fetchData();
            toast({
                title: "Success",
                description: "Domain created successfully",
            });
        } catch (error) {
            console.error('Error creating domain:', error);
            toast({
                title: "Error",
                description: "Failed to create domain",
                variant: "destructive"
            });
        }
    };

    const handleCreateResource = async () => {
        try {
            // Validation
            if (!resourceForm.title) {
                toast({ title: "Validation Error", description: "Please enter a title", variant: "destructive" });
                return;
            }
            if (!resourceForm.domainId) {
                toast({ title: "Validation Error", description: "Please select a category/domain", variant: "destructive" });
                return;
            }

            if (resourceType === 'PDF') {
                if (!resourceForm.file) {
                    toast({ title: "Validation Error", description: "Please select a PDF file", variant: "destructive" });
                    return;
                }
                const formData = new FormData();
                formData.append('file', resourceForm.file);
                formData.append('title', resourceForm.title);
                formData.append('description', resourceForm.description);
                formData.append('domainId', resourceForm.domainId);
                formData.append('createdBy', 'admin'); 
                formData.append('isPaid', String(resourceForm.isPaid));
                if (resourceForm.publishedAt) {
                    formData.append('publishedAt', resourceForm.publishedAt);
                }

                await api.post('/library/resources/pdf', formData, {
                    headers: { 'Content-Type': 'multipart/form-data' }
                });
            } else {
                // Q&A type
                const validQuestions = resourceForm.qaContent.filter(qa => qa.q && qa.a);
                if (validQuestions.length === 0) {
                    toast({ title: "Validation Error", description: "Please add at least one valid Q&A pair", variant: "destructive" });
                    return;
                }

                const content = {
                    questions: validQuestions
                };

                await api.post('/library/resources/qa', {
                    title: resourceForm.title,
                    description: resourceForm.description,
                    domainId: resourceForm.domainId,
                    createdBy: 'admin',
                    content,
                    syncToAI: resourceForm.syncToAI,
                    isPaid: resourceForm.isPaid,
                    publishedAt: resourceForm.publishedAt || null
                });
            }

            toast({
                title: "Success",
                description: `Library ${resourceType === 'PDF' ? 'PDF' : 'Q&A'} resource created successfully`,
            });

            setResourceForm({ ...initialResourceForm });
            setShowResourceForm(false);
            fetchData();
        } catch (error: any) {
            console.error('Error creating resource:', error);
            toast({
                title: "Error",
                description: error.response?.data?.error || "Failed to create resource",
                variant: "destructive"
            });
        }
    };

    const addQAPair = () => {
        setResourceForm({
            ...resourceForm,
            qaContent: [...resourceForm.qaContent, { q: '', a: '' }]
        });
    };

    const updateQAPair = (index: number, field: keyof QAItem, value: string) => {
        const updated = [...resourceForm.qaContent];
        updated[index][field] = value;
        setResourceForm({ ...resourceForm, qaContent: updated });
    };

    const removeQAPair = (index: number) => {
        const updated = resourceForm.qaContent.filter((_, i) => i !== index);
        setResourceForm({ ...resourceForm, qaContent: updated });
    };

    if (loading) {
        return <div className="p-6">Loading...</div>;
    }

    return (
  <div className="p-6 space-y-6">

    {/* 🔥 TOP CARDS */}
    <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
      
      <Card>
        <CardContent className="p-4">
          <p className="text-sm text-muted-foreground">All Library</p>
          <h2 className="text-2xl font-bold">{resources.length}</h2>
        </CardContent>
      </Card>

      <Card>
        <CardContent className="p-4">
          <p className="text-sm text-muted-foreground">Paid</p>
          <h2 className="text-2xl font-bold">
            {resources.filter(r => r.isPaid).length}
          </h2>
        </CardContent>
      </Card>

      <Card>
        <CardContent className="p-4">
          <p className="text-sm text-muted-foreground">Free</p>
          <h2 className="text-2xl font-bold">
            {resources.filter(r => !r.isPaid).length}
          </h2>
        </CardContent>
      </Card>

    </div>

    {/* 🔥 QUICK ACTIONS */}
    <div className="flex flex-wrap gap-4 justify-between items-center bg-muted/20 p-4 rounded-lg border border-dashed">
      <div className="flex flex-wrap gap-2">
        <Button variant="outline" size="sm" onClick={() => setShowCategoryForm(!showCategoryForm)}>
          <BookOpen className="h-4 w-4 mr-2" />
          {showCategoryForm ? "Cancel Category" : "New Category"}
        </Button>
        <Button variant="outline" size="sm" onClick={() => setShowDomainForm(!showDomainForm)}>
          <FolderTree className="h-4 w-4 mr-2" />
          {showDomainForm ? "Cancel Domain" : "New Domain"}
        </Button>
      </div>
      
      <Button onClick={() => setShowResourceForm(!showResourceForm)} className="shadow-lg">
        <Plus className="h-4 w-4 mr-2" />
        {showResourceForm ? "Close Form" : "Add Library Post"}
      </Button>
    </div>

    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        
        {/* 🔥 CATEGORY FORM */}
        {showCategoryForm && (
            <Card className="border-primary/30">
                <CardHeader>
                    <CardTitle className="text-lg">Create New Category</CardTitle>
                </CardHeader>
                <CardContent className="space-y-4">
                    <div className="space-y-2">
                        <Label>Category Name</Label>
                        <Input 
                            value={categoryForm.name}
                            onChange={(e) => setCategoryForm({...categoryForm, name: e.target.value})}
                            placeholder="e.g. Artificial Intelligence"
                        />
                    </div>
                    <div className="space-y-2">
                        <Label>Description</Label>
                        <Textarea 
                            value={categoryForm.description}
                            onChange={(e) => setCategoryForm({...categoryForm, description: e.target.value})}
                            placeholder="Brief overview..."
                        />
                    </div>
                    <Button onClick={handleCreateCategory} className="w-full">Save Category</Button>
                </CardContent>
            </Card>
        )}

        {/* 🔥 DOMAIN FORM */}
        {showDomainForm && (
            <Card className="border-primary/30">
                <CardHeader>
                    <CardTitle className="text-lg">Create New Domain</CardTitle>
                </CardHeader>
                <CardContent className="space-y-4">
                    <div className="space-y-2">
                        <Label>Parent Category</Label>
                        <select
                            className="w-full p-2 border rounded bg-background"
                            value={domainForm.categoryId}
                            onChange={(e) => setDomainForm({...domainForm, categoryId: e.target.value})}
                        >
                            <option value="">Select Category</option>
                            {categories.map(cat => (
                                <option key={cat.id} value={cat.id}>{cat.name}</option>
                            ))}
                        </select>
                    </div>
                    <div className="space-y-2">
                        <Label>Domain Name</Label>
                        <Input 
                            value={domainForm.name}
                            onChange={(e) => setDomainForm({...domainForm, name: e.target.value})}
                            placeholder="e.g. Prompt Engineering"
                        />
                    </div>
                    <Button onClick={handleCreateDomain} className="w-full">Save Domain</Button>
                </CardContent>
            </Card>
        )}
    </div>

    {/* 🔥 FORM */}
    {showResourceForm && (
      <Card>
        <CardHeader>
          <CardTitle>Add Library</CardTitle>
        </CardHeader>

        <CardContent className="space-y-4">
          {/* Resource Type Tabs */}
          <Tabs defaultValue="PDF" onValueChange={(v) => setResourceType(v)}>
            <TabsList className="grid w-full grid-cols-2">
              <TabsTrigger value="PDF">PDF Document</TabsTrigger>
              <TabsTrigger value="QA">Q&A / Interview</TabsTrigger>
            </TabsList>
          </Tabs>

          {/* Name */}
          <div className="pt-4">
            <Label>Resource Title</Label>
            <Input
              placeholder="e.g. Frontend Interview Preparation Guide"
              value={resourceForm.title}
              onChange={(e) =>
                setResourceForm({ ...resourceForm, title: e.target.value })
              }
            />
          </div>

          {/* Category */}
          <div>
            <Label>Domain / Category</Label>
            <select
              className="w-full p-2 border rounded bg-background"
              value={resourceForm.domainId}
              onChange={(e) =>
                setResourceForm({ ...resourceForm, domainId: e.target.value })
              }
            >
              <option value="">Select Domain</option>
              {domains.map((domain) => (
                <option key={domain.id} value={domain.id}>
                  {domain.category ? `${domain.category.name} - ${domain.name}` : domain.name}
                </option>
              ))}
            </select>
          </div>

          {/* PDF Specific Fields */}
          {resourceType === 'PDF' && (
            <div className="space-y-4 border p-4 rounded-lg bg-muted/30">
              <div>
                <Label>PDF File</Label>
                <Input
                  type="file"
                  accept=".pdf"
                  className="bg-background"
                  onChange={(e) => {
                    if (e.target.files?.[0]) {
                      setResourceForm({
                        ...resourceForm,
                        file: e.target.files[0],
                      });
                    }
                  }}
                />
              </div>
            </div>
          )}

          {/* QA Specific Fields */}
          {resourceType === 'QA' && (
            <div className="space-y-4 border p-4 rounded-lg bg-muted/30">
              <div className="flex items-center justify-between">
                <Label>Questions & Answers</Label>
                <Button variant="outline" size="sm" onClick={addQAPair}>
                  <Plus className="h-4 w-4 mr-1" /> Add QA
                </Button>
              </div>
              
              <div className="space-y-4">
                {resourceForm.qaContent.map((qa, index) => (
                  <div key={index} className="space-y-2 p-3 border rounded bg-background relative">
                    <Button 
                      variant="ghost" 
                      size="icon" 
                      className="absolute top-1 right-1 h-6 w-6 text-red-500"
                      onClick={() => removeQAPair(index)}
                    >
                      <X className="h-4 w-4" />
                    </Button>
                    <Input 
                      placeholder="Question" 
                      value={qa.q} 
                      onChange={(e) => updateQAPair(index, 'q', e.target.value)}
                    />
                    <Textarea 
                      placeholder="Answer" 
                      value={qa.a} 
                      onChange={(e) => updateQAPair(index, 'a', e.target.value)}
                    />
                  </div>
                ))}
              </div>

              <div className="flex items-center gap-2 pt-2">
                <input 
                  type="checkbox" 
                  id="syncToAI" 
                  checked={resourceForm.syncToAI}
                  onChange={(e) => setResourceForm({...resourceForm, syncToAI: e.target.checked})}
                />
                <Label htmlFor="syncToAI" className="cursor-pointer">Sync to AI Interview Database</Label>
              </div>
            </div>
          )}

          <div className="grid grid-cols-2 gap-4">
            {/* Access */}
            <div>
              <Label>Access Type</Label>
              <div className="flex gap-4 mt-2">
                <label className="flex items-center gap-2 cursor-pointer">
                  <input
                    type="radio"
                    name="isPaid"
                    checked={!resourceForm.isPaid}
                    onChange={() => setResourceForm({ ...resourceForm, isPaid: false })}
                  />
                  <span className="text-sm">Free</span>
                </label>
                <label className="flex items-center gap-2 cursor-pointer">
                  <input
                    type="radio"
                    name="isPaid"
                    checked={resourceForm.isPaid}
                    onChange={() => setResourceForm({ ...resourceForm, isPaid: true })}
                  />
                  <span className="text-sm">Paid</span>
                </label>
              </div>
            </div>

            {/* Published Date */}
            <div>
              <Label>Published Date</Label>
              <Input
                type="date"
                value={resourceForm.publishedAt}
                onChange={(e) => setResourceForm({ ...resourceForm, publishedAt: e.target.value })}
              />
            </div>
          </div>

          <div>
            <Label>Description (Optional)</Label>
            <Textarea
              placeholder="Provide a brief overview of this resource..."
              value={resourceForm.description}
              onChange={(e) =>
                setResourceForm({ ...resourceForm, description: e.target.value })
              }
            />
          </div>

          <Button className="w-full" onClick={handleCreateResource}>
            Add {resourceType === 'PDF' ? 'Document' : 'Interview Q&A'}
          </Button>

        </CardContent>
      </Card>
    )}

    {/* 🔥 LIST */}
    <div className="space-y-4">
      {resources.map((r) => (
        <Card key={r.id}>
          <CardContent className="p-4 flex justify-between items-center">
            <div>
              <h3 className="font-semibold">{r.title}</h3>
              <p className="text-sm text-muted-foreground">{r.description}</p>
            </div>

            <div className="flex gap-2">
              <span className={`text-xs px-2 py-1 rounded ${r.isPaid ? "bg-red-100 text-red-600" : "bg-green-100 text-green-600"}`}>
                {r.isPaid ? "Paid" : "Free"}
              </span>
            </div>
          </CardContent>
        </Card>
      ))}
    </div>

  </div>
)
}

"use client"

import React, { useState, useEffect } from 'react'
import axios from 'axios'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Textarea } from '@/components/ui/textarea'
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from '@/components/ui/select'
import {
    Tabs,
    TabsContent,
    TabsList,
    TabsTrigger,
} from '@/components/ui/tabs'
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from '@/components/ui/table'
import { Badge } from '@/components/ui/badge'
import {
    Send,
    Loader2,
    CheckCircle,
    AlertCircle,
    MessageSquare,
    Users,
    BookOpen,
    Trash2,
    Eye,
} from 'lucide-react'
import api from '@/lib/api'

interface Message {
    id: string
    title: string
    content: string
    priority: string
    sender: {
        id: string
        name: string
        email: string
        avatar?: string
    }
    recipients: Array<{
        userId: string
        isRead: boolean
        readAt?: string
    }>
    createdAt: string
    updatedAt: string
}

interface Batch {
    id: string
    name: string
    courseId: string
    course: {
        title: string
    }
}

interface Student {
    id: string
    name: string
    email: string
    avatar?: string
}

export default function AdminMessagesPage() {
    const [activeTab, setActiveTab] = useState('send-all')
    const [messages, setMessages] = useState<Message[]>([])
    const [batches, setBatches] = useState<Batch[]>([])
    const [students, setStudents] = useState<Student[]>([])
    const [loading, setLoading] = useState(false)
    const [messageLoading, setMessageLoading] = useState(false)
    const [successMessage, setSuccessMessage] = useState('')
    const [errorMessage, setErrorMessage] = useState('')

    // Form states
    const [title, setTitle] = useState('')
    const [content, setContent] = useState('')
    const [priority, setPriority] = useState('NORMAL')
    const [selectedBatch, setSelectedBatch] = useState('')
    const [selectedStudent, setSelectedStudent] = useState('')

    // Fetch sent messages
    useEffect(() => {
        fetchMessages()
        fetchBatches()
        fetchStudents()
    }, [])

    const fetchMessages = async () => {
        try {
            setLoading(true)
            const response = await api.get('/messages')
            setMessages(response.data.data || [])
        } catch (error) {
            console.error('Error fetching messages:', error)
            setErrorMessage('Failed to fetch messages')
        } finally {
            setLoading(false)
        }
    }

    const fetchBatches = async () => {
        try {
            // Try to fetch batches from courses API
            const response = await api.get('/courses?skip=0&take=100')
            const coursesList = response.data.courses || []
            // If we have course data, you could derive batches from it
            setBatches(coursesList.map((course: any) => ({
                id: course.id,
                name: course.title,
                courseId: course.id,
                course: { title: course.title }
            })) || [])
        } catch (error) {
            console.error('Error fetching batches/courses:', error)
            setBatches([])
        }
    }

    const fetchStudents = async () => {
        try {
            // Try to fetch students from users API
            const response = await api.get('/users?role=STUDENT&skip=0&take=100')
            setStudents(response.data.users || response.data.data || [])
        } catch (error) {
            console.error('Error fetching students:', error)
            setStudents([])
        }
    }

    const resetForm = () => {
        setTitle('')
        setContent('')
        setPriority('NORMAL')
        setSelectedBatch('')
        setSelectedStudent('')
    }

    const handleSendToAll = async (e: React.FormEvent) => {
        e.preventDefault()
        if (!title.trim() || !content.trim()) {
            setErrorMessage('Title and content are required')
            return
        }

        try {
            setMessageLoading(true)
            const response = await api.post('/messages/send-to-all', {
                title,
                content,
                priority
            })
            setSuccessMessage(`Message sent successfully to ${response.data.recipientsCount || 0} students`)
            resetForm()
            fetchMessages()
            setTimeout(() => setSuccessMessage(''), 3000)
        } catch (error) {
            setErrorMessage('Failed to send message')
            console.error(error)
        } finally {
            setMessageLoading(false)
        }
    }

    const handleSendToBatch = async (e: React.FormEvent) => {
        e.preventDefault()
        if (!title.trim() || !content.trim() || !selectedBatch) {
            setErrorMessage('Title, content, and batch are required')
            return
        }

        try {
            setMessageLoading(true)
            const response = await api.post('/messages/send-to-batch', {
                title,
                content,
                batchId: selectedBatch,
                priority
            })
            setSuccessMessage(`Message sent successfully to ${response.data.recipientsCount || 0} students in batch`)
            resetForm()
            fetchMessages()
            setTimeout(() => setSuccessMessage(''), 3000)
        } catch (error) {
            setErrorMessage('Failed to send message')
            console.error(error)
        } finally {
            setMessageLoading(false)
        }
    }

    const handleSendToStudent = async (e: React.FormEvent) => {
        e.preventDefault()
        if (!title.trim() || !content.trim() || !selectedStudent) {
            setErrorMessage('Title, content, and student are required')
            return
        }

        try {
            setMessageLoading(true)
            await api.post('/messages/send-to-student', {
                title,
                content,
                studentId: selectedStudent,
                priority
            })
            setSuccessMessage('Message sent successfully to student')
            resetForm()
            fetchMessages()
            setTimeout(() => setSuccessMessage(''), 3000)
        } catch (error) {
            setErrorMessage('Failed to send message')
            console.error(error)
        } finally {
            setMessageLoading(false)
        }
    }

    const handleDeleteMessage = async (messageId: string) => {
        if (confirm('Are you sure you want to delete this message?')) {
            try {
                await api.delete(`/messages/${messageId}`)
                setSuccessMessage('Message deleted successfully')
                fetchMessages()
                setTimeout(() => setSuccessMessage(''), 3000)
            } catch (error) {
                setErrorMessage('Failed to delete message')
                console.error(error)
            }
        }
    }

    return (
        <div className="min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 p-6">
            <div className="max-w-7xl mx-auto space-y-6">
                {/* Header */}
                <div className="flex items-center gap-3">
                    <MessageSquare className="w-8 h-8 text-blue-600" />
                    <div>
                        <h1 className="text-3xl font-bold text-slate-900">Student Messages</h1>
                        <p className="text-sl text-slate-600">Send instructions and announcements to students</p>
                    </div>
                </div>

                {/* Alerts */}
                {successMessage && (
                    <Card className="border-green-200 bg-green-50">
                        <CardContent className="pt-6 flex items-center gap-3 text-green-700">
                            <CheckCircle className="w-5 h-5" />
                            <span>{successMessage}</span>
                        </CardContent>
                    </Card>
                )}

                {errorMessage && (
                    <Card className="border-red-200 bg-red-50">
                        <CardContent className="pt-6 flex items-center gap-3 text-red-700">
                            <AlertCircle className="w-5 h-5" />
                            <span>{errorMessage}</span>
                        </CardContent>
                    </Card>
                )}

                {/* Tabs */}
                <Tabs value={activeTab} onValueChange={setActiveTab} className="w-full">
                    <TabsList className="grid w-full grid-cols-4">
                        <TabsTrigger value="send-all" className="flex items-center gap-2">
                            <Users className="w-4 h-4" />
                            <span className="hidden sm:inline">Send to All</span>
                        </TabsTrigger>
                        <TabsTrigger value="send-batch" className="flex items-center gap-2">
                            <BookOpen className="w-4 h-4" />
                            <span className="hidden sm:inline">Send to Batch</span>
                        </TabsTrigger>
                        <TabsTrigger value="send-student" className="flex items-center gap-2">
                            <MessageSquare className="w-4 h-4" />
                            <span className="hidden sm:inline">Send to Student</span>
                        </TabsTrigger>
                        <TabsTrigger value="history" className="flex items-center gap-2">
                            <Eye className="w-4 h-4" />
                            <span className="hidden sm:inline">History</span>
                        </TabsTrigger>
                    </TabsList>

                    {/* Send to All Tab */}
                    <TabsContent value="send-all" className="space-y-4">
                        <Card>
                            <CardHeader>
                                <CardTitle>Send Message to All Students</CardTitle>
                                <CardDescription>This message will be sent to all active students</CardDescription>
                            </CardHeader>
                            <CardContent>
                                <form onSubmit={handleSendToAll} className="space-y-4">
                                    <div>
                                        <label className="block text-sm font-medium text-slate-700 mb-2">
                                            Title
                                        </label>
                                        <Input
                                            placeholder="Message title"
                                            value={title}
                                            onChange={(e) => setTitle(e.target.value)}
                                            required
                                        />
                                    </div>

                                    <div>
                                        <label className="block text-sm font-medium text-slate-700 mb-2">
                                            Message Content
                                        </label>
                                        <Textarea
                                            placeholder="Enter your message..."
                                            value={content}
                                            onChange={(e) => setContent(e.target.value)}
                                            rows={6}
                                            required
                                        />
                                    </div>

                                    <div>
                                        <label className="block text-sm font-medium text-slate-700 mb-2">
                                            Priority
                                        </label>
                                        <Select value={priority} onValueChange={setPriority}>
                                            <SelectTrigger>
                                                <SelectValue />
                                            </SelectTrigger>
                                            <SelectContent>
                                                <SelectItem value="LOW">Low</SelectItem>
                                                <SelectItem value="NORMAL">Normal</SelectItem>
                                                <SelectItem value="HIGH">High</SelectItem>
                                                <SelectItem value="URGENT">Urgent</SelectItem>
                                            </SelectContent>
                                        </Select>
                                    </div>

                                    <Button
                                        type="submit"
                                        disabled={messageLoading}
                                        className="w-full"
                                    >
                                        {messageLoading ? (
                                            <>
                                                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                                                Sending...
                                            </>
                                        ) : (
                                            <>
                                                <Send className="mr-2 h-4 w-4" />
                                                Send to All Students
                                            </>
                                        )}
                                    </Button>
                                </form>
                            </CardContent>
                        </Card>
                    </TabsContent>

                    {/* Send to Batch Tab */}
                    <TabsContent value="send-batch" className="space-y-4">
                        <Card>
                            <CardHeader>
                                <CardTitle>Send Message to Batch</CardTitle>
                                <CardDescription>Send a message to all students in a specific batch</CardDescription>
                            </CardHeader>
                            <CardContent>
                                <form onSubmit={handleSendToBatch} className="space-y-4">
                                    <div>
                                        <label className="block text-sm font-medium text-slate-700 mb-2">
                                            Select Batch
                                        </label>
                                        <Select value={selectedBatch} onValueChange={setSelectedBatch}>
                                            <SelectTrigger>
                                                <SelectValue placeholder="Choose a batch" />
                                            </SelectTrigger>
                                            <SelectContent>
                                                {batches.map((batch) => (
                                                    <SelectItem key={batch.id} value={batch.id}>
                                                        {batch.name} - {batch.course?.title}
                                                    </SelectItem>
                                                ))}
                                            </SelectContent>
                                        </Select>
                                    </div>

                                    <div>
                                        <label className="block text-sm font-medium text-slate-700 mb-2">
                                            Title
                                        </label>
                                        <Input
                                            placeholder="Message title"
                                            value={title}
                                            onChange={(e) => setTitle(e.target.value)}
                                            required
                                        />
                                    </div>

                                    <div>
                                        <label className="block text-sm font-medium text-slate-700 mb-2">
                                            Message Content
                                        </label>
                                        <Textarea
                                            placeholder="Enter your message..."
                                            value={content}
                                            onChange={(e) => setContent(e.target.value)}
                                            rows={6}
                                            required
                                        />
                                    </div>

                                    <div>
                                        <label className="block text-sm font-medium text-slate-700 mb-2">
                                            Priority
                                        </label>
                                        <Select value={priority} onValueChange={setPriority}>
                                            <SelectTrigger>
                                                <SelectValue />
                                            </SelectTrigger>
                                            <SelectContent>
                                                <SelectItem value="LOW">Low</SelectItem>
                                                <SelectItem value="NORMAL">Normal</SelectItem>
                                                <SelectItem value="HIGH">High</SelectItem>
                                                <SelectItem value="URGENT">Urgent</SelectItem>
                                            </SelectContent>
                                        </Select>
                                    </div>

                                    <Button
                                        type="submit"
                                        disabled={messageLoading || !selectedBatch}
                                        className="w-full"
                                    >
                                        {messageLoading ? (
                                            <>
                                                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                                                Sending...
                                            </>
                                        ) : (
                                            <>
                                                <Send className="mr-2 h-4 w-4" />
                                                Send to Batch
                                            </>
                                        )}
                                    </Button>
                                </form>
                            </CardContent>
                        </Card>
                    </TabsContent>

                    {/* Send to Individual Student Tab */}
                    <TabsContent value="send-student" className="space-y-4">
                        <Card>
                            <CardHeader>
                                <CardTitle>Send Message to Individual Student</CardTitle>
                                <CardDescription>Send a personal message to a specific student</CardDescription>
                            </CardHeader>
                            <CardContent>
                                <form onSubmit={handleSendToStudent} className="space-y-4">
                                    <div>
                                        <label className="block text-sm font-medium text-slate-700 mb-2">
                                            Select Student
                                        </label>
                                        <Select value={selectedStudent} onValueChange={setSelectedStudent}>
                                            <SelectTrigger>
                                                <SelectValue placeholder="Choose a student" />
                                            </SelectTrigger>
                                            <SelectContent>
                                                {students.map((student) => (
                                                    <SelectItem key={student.id} value={student.id}>
                                                        {student.name} - {student.email}
                                                    </SelectItem>
                                                ))}
                                            </SelectContent>
                                        </Select>
                                    </div>

                                    <div>
                                        <label className="block text-sm font-medium text-slate-700 mb-2">
                                            Title
                                        </label>
                                        <Input
                                            placeholder="Message title"
                                            value={title}
                                            onChange={(e) => setTitle(e.target.value)}
                                            required
                                        />
                                    </div>

                                    <div>
                                        <label className="block text-sm font-medium text-slate-700 mb-2">
                                            Message Content
                                        </label>
                                        <Textarea
                                            placeholder="Enter your message..."
                                            value={content}
                                            onChange={(e) => setContent(e.target.value)}
                                            rows={6}
                                            required
                                        />
                                    </div>

                                    <div>
                                        <label className="block text-sm font-medium text-slate-700 mb-2">
                                            Priority
                                        </label>
                                        <Select value={priority} onValueChange={setPriority}>
                                            <SelectTrigger>
                                                <SelectValue />
                                            </SelectTrigger>
                                            <SelectContent>
                                                <SelectItem value="LOW">Low</SelectItem>
                                                <SelectItem value="NORMAL">Normal</SelectItem>
                                                <SelectItem value="HIGH">High</SelectItem>
                                                <SelectItem value="URGENT">Urgent</SelectItem>
                                            </SelectContent>
                                        </Select>
                                    </div>

                                    <Button
                                        type="submit"
                                        disabled={messageLoading || !selectedStudent}
                                        className="w-full"
                                    >
                                        {messageLoading ? (
                                            <>
                                                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                                                Sending...
                                            </>
                                        ) : (
                                            <>
                                                <Send className="mr-2 h-4 w-4" />
                                                Send to Student
                                            </>
                                        )}
                                    </Button>
                                </form>
                            </CardContent>
                        </Card>
                    </TabsContent>

                    {/* Message History Tab */}
                    <TabsContent value="history" className="space-y-4">
                        <Card>
                            <CardHeader>
                                <CardTitle>Message History</CardTitle>
                                <CardDescription>View and manage sent messages</CardDescription>
                            </CardHeader>
                            <CardContent>
                                {loading ? (
                                    <div className="flex items-center justify-center py-8">
                                        <Loader2 className="h-6 w-6 animate-spin text-blue-600" />
                                    </div>
                                ) : messages.length === 0 ? (
                                    <p className="text-center text-slate-500 py-8">No messages sent yet</p>
                                ) : (
                                    <div className="overflow-x-auto">
                                        <Table>
                                            <TableHead>
                                                <TableRow>
                                                    <TableCell>Title</TableCell>
                                                    <TableCell>Sent By</TableCell>
                                                    <TableCell>Recipients</TableCell>
                                                    <TableCell>Read</TableCell>
                                                    <TableCell>Priority</TableCell>
                                                    <TableCell>Date</TableCell>
                                                    <TableCell>Action</TableCell>
                                                </TableRow>
                                            </TableHead>
                                            <TableBody>
                                                {messages.map((message) => {
                                                    const totalRecipients = message.recipients.length
                                                    const readCount = message.recipients.filter(r => r.isRead).length
                                                    return (
                                                        <TableRow key={message.id}>
                                                            <TableCell className="font-medium">{message.title}</TableCell>
                                                            <TableCell>{message.sender.name}</TableCell>
                                                            <TableCell>{totalRecipients}</TableCell>
                                                            <TableCell>
                                                                <Badge variant="outline">
                                                                    {readCount}/{totalRecipients}
                                                                </Badge>
                                                            </TableCell>
                                                            <TableCell>
                                                                <Badge
                                                                    variant={
                                                                        message.priority === 'URGENT'
                                                                            ? 'destructive'
                                                                            : message.priority === 'HIGH'
                                                                            ? 'secondary'
                                                                            : 'outline'
                                                                    }
                                                                >
                                                                    {message.priority}
                                                                </Badge>
                                                            </TableCell>
                                                            <TableCell>
                                                                {new Date(message.createdAt).toLocaleDateString()}
                                                            </TableCell>
                                                            <TableCell>
                                                                <Button
                                                                    variant="ghost"
                                                                    size="sm"
                                                                    onClick={() => handleDeleteMessage(message.id)}
                                                                    className="text-red-600 hover:text-red-700"
                                                                >
                                                                    <Trash2 className="w-4 h-4" />
                                                                </Button>
                                                            </TableCell>
                                                        </TableRow>
                                                    )
                                                })}
                                            </TableBody>
                                        </Table>
                                    </div>
                                )}
                            </CardContent>
                        </Card>
                    </TabsContent>
                </Tabs>
            </div>
        </div>
    )
}

"use client";

import { useEffect, useState } from "react";
import { Plus, Edit, Trash2, Search, Filter } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
} from "@/components/ui/dialog";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";

import api from "@/lib/api";

interface Project {
    id: string;
    title: string;
    description: string;
    price: string;
    originalPrice?: string;
    image: string;
    category: string;
    techStack: string | string[];
}

export default function AdminProjects() {
    const [projects, setProjects] = useState<Project[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState("");
    const [isDialogOpen, setIsDialogOpen] = useState(false);
    const [editingProject, setEditingProject] = useState<Project | null>(null);

    // Form State
    const [formData, setFormData] = useState({
        title: "",
        description: "",
        price: "",
        originalPrice: "",
        image: "",
        category: "AI & ML",
        techStack: "", // Comma separated string for input
    });

    useEffect(() => {
        fetchProjects();
    }, []);

    const fetchProjects = async () => {
        try {
            const res = await api.get("/projects");
            const data = res.data;
            setProjects(Array.isArray(data) ? data : []);
        } catch (error) {
            console.error("Failed to fetch projects", error);
        } finally {
            setLoading(false);
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        const payload = {
            ...formData,
            techStack: formData.techStack.split(",").map((s) => s.trim()),
        };

        try {
            const res = editingProject
                ? await api.put(`/projects/${editingProject.id}`, payload)
                : await api.post("/projects", payload);

            if (res.status === 200 || res.status === 201) {
                setIsDialogOpen(false);
                fetchProjects();
                resetForm();
            }
        } catch (error) {
            console.error("Error saving project", error);
        }
    };

    const handleDelete = async (id: string) => {
        if (!confirm("Are you sure you want to delete this project?")) return;
        try {
            await api.delete(`/projects/${id}`);
            fetchProjects();
        } catch (error) {
            console.error("Error deleting project", error);
        }
    };

    const handleEdit = (project: Project) => {
        setEditingProject(project);
        setFormData({
            title: project.title,
            description: project.description,
            price: project.price,
            originalPrice: project.originalPrice || "",
            image: project.image,
            category: project.category,
            techStack: Array.isArray(project.techStack) ? project.techStack.join(", ") : project.techStack,
        });
        setIsDialogOpen(true);
    };

    const resetForm = () => {
        setEditingProject(null);
        setFormData({
            title: "",
            description: "",
            price: "",
            originalPrice: "",
            image: "",
            category: "AI & ML",
            techStack: "",
        });
    };

    const filteredProjects = projects.filter((p) =>
        p.title.toLowerCase().includes(searchTerm.toLowerCase())
    );

    return (
        <div className="p-8 space-y-8">
            <div className="flex items-center justify-between">
                <div>
                    <h1 className="text-3xl font-bold tracking-tight">Projects Marketplace</h1>
                    <p className="text-muted-foreground">Manage final year projects listings.</p>
                </div>
                <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
                    <DialogTrigger asChild>
                        <Button onClick={resetForm} className="gap-2">
                            <Plus className="w-4 h-4" /> Add Project
                        </Button>
                    </DialogTrigger>
                    <DialogContent className="sm:max-w-[600px]">
                        <DialogHeader>
                            <DialogTitle>{editingProject ? "Edit Project" : "Add New Project"}</DialogTitle>
                        </DialogHeader>
                        <form onSubmit={handleSubmit} className="space-y-4">
                            <div className="grid grid-cols-2 gap-4">
                                <div className="space-y-2">
                                    <Label>Title</Label>
                                    <Input
                                        required
                                        value={formData.title}
                                        onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                                    />
                                </div>
                                <div className="space-y-2">
                                    <Label>Category</Label>
                                    <Input
                                        required
                                        value={formData.category}
                                        onChange={(e) => setFormData({ ...formData, category: e.target.value })}
                                        placeholder="AI & ML, Web, IoT..."
                                    />
                                </div>
                            </div>

                            <div className="space-y-2">
                                <Label>Description</Label>
                                <Textarea
                                    required
                                    value={formData.description}
                                    onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                                />
                            </div>

                            <div className="grid grid-cols-2 gap-4">
                                <div className="space-y-2">
                                    <Label>Price</Label>
                                    <Input
                                        required
                                        value={formData.price}
                                        onChange={(e) => setFormData({ ...formData, price: e.target.value })}
                                        placeholder="$199 or ₹5000"
                                    />
                                </div>
                                <div className="space-y-2">
                                    <Label>Original Price</Label>
                                    <Input
                                        value={formData.originalPrice}
                                        onChange={(e) => setFormData({ ...formData, originalPrice: e.target.value })}
                                    />
                                </div>
                            </div>

                            <div className="space-y-2">
                                <Label>Tech Stack (Comma separated)</Label>
                                <Input
                                    required
                                    value={formData.techStack}
                                    onChange={(e) => setFormData({ ...formData, techStack: e.target.value })}
                                    placeholder="React, Node.js, Python..."
                                />
                            </div>

                            <div className="space-y-2">
                                <Label>Image URL</Label>
                                <Input
                                    value={formData.image}
                                    onChange={(e) => setFormData({ ...formData, image: e.target.value })}
                                    placeholder="/images/projects/..."
                                />
                            </div>

                            <div className="flex justify-end gap-2 pt-4">
                                <Button type="button" variant="outline" onClick={() => setIsDialogOpen(false)}>Cancel</Button>
                                <Button type="submit">Save Project</Button>
                            </div>
                        </form>
                    </DialogContent>
                </Dialog>
            </div>

            <div className="flex items-center gap-4">
                <div className="relative flex-1 max-w-sm">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                    <Input
                        placeholder="Search projects..."
                        className="pl-9"
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                    />
                </div>
            </div>

            <div className="border rounded-lg">
                <Table>
                    <TableHeader>
                        <TableRow>
                            <TableHead>Title</TableHead>
                            <TableHead>Category</TableHead>
                            <TableHead>Price</TableHead>
                            <TableHead>Tech Stack</TableHead>
                            <TableHead className="text-right">Actions</TableHead>
                        </TableRow>
                    </TableHeader>
                    <TableBody>
                        {filteredProjects.map((project) => (
                            <TableRow key={project.id}>
                                <TableCell className="font-medium">{project.title}</TableCell>
                                <TableCell>
                                    <Badge variant="secondary">{project.category}</Badge>
                                </TableCell>
                                <TableCell>{project.price}</TableCell>
                                <TableCell className="max-w-[200px] truncate">
                                    {Array.isArray(project.techStack) ? project.techStack.join(", ") : project.techStack}
                                </TableCell>
                                <TableCell className="text-right space-x-2">
                                    <Button variant="ghost" size="icon" onClick={() => handleEdit(project)}>
                                        <Edit className="w-4 h-4" />
                                    </Button>
                                    <Button variant="ghost" size="icon" className="text-destructive" onClick={() => handleDelete(project.id)}>
                                        <Trash2 className="w-4 h-4" />
                                    </Button>
                                </TableCell>
                            </TableRow>
                        ))}
                        {filteredProjects.length === 0 && !loading && (
                            <TableRow>
                                <TableCell colSpan={5} className="text-center h-24 text-muted-foreground">
                                    No projects found. Add one to get started.
                                </TableCell>
                            </TableRow>
                        )}
                    </TableBody>
                </Table>
            </div>
        </div>
    );
}

"use client"

import { useState, useEffect } from 'react'
import api from '@/lib/api'
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs'
import { Badge } from '@/components/ui/badge'
import { CheckCircle, XCircle, ExternalLink, Loader2, FileText, BookOpen } from 'lucide-react'
import { toast } from 'sonner'
import { format } from 'date-fns'

export default function ReviewsPage() {
    interface ReviewCourse {
        id: string
        title: string
        instructor?: { name: string }
        price: number
        category: string
        submittedForReviewAt?: string
        publishStatus: string
        status: string
    }
    interface ReviewBlog {
        id: string
        title: string
        author?: { name: string }
        summary?: string
        content: string
        createdAt: string
    }
    const [courses, setCourses] = useState<ReviewCourse[]>([])
    const [blogs, setBlogs] = useState<ReviewBlog[]>([])
    const [isLoading, setIsLoading] = useState(true)

    useEffect(() => {
        fetchData()
    }, [])

    const fetchData = async () => {
        setIsLoading(true)
        try {
            // We need to fetch ALL mostly, or specific endpoints for pending
            // For now, fetch generic and filter client side or use dedicated params if implemented
            const [coursesRes, blogsRes] = await Promise.all([
                api.get('/courses'), // Needs to return all for admin
                api.get('/blogs?status=IN_REVIEW') // Blog API supports status filter
            ])

            // Filter courses client side if API returns all
            const pendingCourses = (coursesRes.data.courses || coursesRes.data).filter((c: { publishStatus: string, status: string }) =>
                c.publishStatus === 'IN_REVIEW' || c.status === 'IN_REVIEW' // handle both legacy/new
            )

            setCourses(pendingCourses)
            setBlogs(blogsRes.data.blogs || blogsRes.data)
        } catch {
            // Error handling
        } finally {
            setIsLoading(false)
        }
    }

    const handleApproveCourse = async (id: string) => {
        try {
            await api.patch(`/courses/${id}/status`, { status: 'PUBLISHED' })
            toast.success('Course approved & published')
            setCourses(prev => prev.filter(c => c.id !== id))
        } catch (_error) {
            toast.error('Failed to approve course')
        }
    }

    const handleRejectCourse = async (id: string) => {
        if (!confirm('Reject this course and return to draft?')) return
        try {
            await api.patch(`/courses/${id}/status`, { status: 'DRAFT' })
            toast.success('Course rejected')
            setCourses(prev => prev.filter(c => c.id !== id))
        } catch (_error) {
            toast.error('Failed to reject course')
        }
    }

    const handleApproveBlog = async (id: string) => {
        try {
            await api.put(`/blogs/${id}`, { status: 'PUBLISHED' })
            toast.success('Blog post published')
            setBlogs(prev => prev.filter(b => b.id !== id))
        } catch (_error) {
            toast.error('Failed to publish blog')
        }
    }

    const handleRejectBlog = async (id: string) => {
        if (!confirm('Return this post to draft?')) return
        try {
            await api.put(`/blogs/${id}`, { status: 'DRAFT' })
            toast.success('Blog returned to draft')
            setBlogs(prev => prev.filter(b => b.id !== id))
        } catch (_error) {
            toast.error('Failed to reject blog')
        }
    }

    if (isLoading) return <div className="p-8"><Loader2 className="animate-spin h-8 w-8 mx-auto" /></div>

    return (
        <div className="container py-8 space-y-8">
            <div>
                <h1 className="text-3xl font-bold tracking-tight">Review Queue</h1>
                <p className="text-muted-foreground">Approve or reject content submitted for publication.</p>
            </div>

            <Tabs defaultValue="courses">
                <TabsList>
                    <TabsTrigger value="courses">Courses ({courses.length})</TabsTrigger>
                    <TabsTrigger value="blogs">Blog Posts ({blogs.length})</TabsTrigger>
                </TabsList>

                <TabsContent value="courses" className="space-y-4 mt-6">
                    {courses.length === 0 ? (
                        <div className="text-center py-12 text-muted-foreground border rounded-lg bg-muted/10">
                            <BookOpen className="h-12 w-12 mx-auto mb-4 opacity-50" />
                            <p>No courses pending review.</p>
                        </div>
                    ) : (
                        courses.map(course => (
                            <Card key={course.id}>
                                <CardHeader>
                                    <div className="flex justify-between items-start">
                                        <div>
                                            <CardTitle>{course.title}</CardTitle>
                                            <CardDescription>Submitted by {course.instructor?.name || 'Instructor'}</CardDescription>
                                        </div>
                                        <Badge variant="outline" className="bg-yellow-50 text-yellow-700 border-yellow-200">Pending Review</Badge>
                                    </div>
                                </CardHeader>
                                <CardContent>
                                    <div className="flex justify-between items-end">
                                        <div className="text-sm text-muted-foreground space-y-1">
                                            <p>Price: ₹{course.price}</p>
                                            <p>Category: {course.category}</p>
                                            <p>Submitted: {course.submittedForReviewAt ? format(new Date(course.submittedForReviewAt), 'MMM d, yyyy') : 'Recently'}</p>
                                        </div>
                                        <div className="flex gap-2">
                                            {/* Preview Link would go here */}
                                            <Button variant="outline" size="sm" onClick={() => handleRejectCourse(course.id)}>
                                                <XCircle className="mr-2 h-4 w-4" /> Reject
                                            </Button>
                                            <Button size="sm" onClick={() => handleApproveCourse(course.id)}>
                                                <CheckCircle className="mr-2 h-4 w-4" /> Approve
                                            </Button>
                                        </div>
                                    </div>
                                </CardContent>
                            </Card>
                        ))
                    )}
                </TabsContent>

                <TabsContent value="blogs" className="space-y-4 mt-6">
                    {blogs.length === 0 ? (
                        <div className="text-center py-12 text-muted-foreground border rounded-lg bg-muted/10">
                            <FileText className="h-12 w-12 mx-auto mb-4 opacity-50" />
                            <p>No blog posts pending review.</p>
                        </div>
                    ) : (
                        blogs.map(blog => (
                            <Card key={blog.id}>
                                <CardHeader>
                                    <div className="flex justify-between items-start">
                                        <div>
                                            <CardTitle>{blog.title}</CardTitle>
                                            <CardDescription>Authored by {blog.author?.name || 'User'}</CardDescription>
                                        </div>
                                        <Badge variant="outline" className="bg-yellow-50 text-yellow-700 border-yellow-200">Pending Review</Badge>
                                    </div>
                                </CardHeader>
                                <CardContent>
                                    <div className="space-y-4">
                                        <p className="text-sm text-muted-foreground line-clamp-2">{blog.summary || blog.content}</p>
                                        <div className="flex justify-between items-end">
                                            <div className="text-sm text-muted-foreground">
                                                Created: {format(new Date(blog.createdAt), 'MMM d, yyyy')}
                                            </div>
                                            <div className="flex gap-2">
                                                {/* Preview Link */}
                                                <Button variant="outline" size="sm" onClick={() => handleRejectBlog(blog.id)}>
                                                    <XCircle className="mr-2 h-4 w-4" /> Return to Draft
                                                </Button>
                                                <Button size="sm" onClick={() => handleApproveBlog(blog.id)}>
                                                    <CheckCircle className="mr-2 h-4 w-4" /> Publish
                                                </Button>
                                            </div>
                                        </div>
                                    </div>
                                </CardContent>
                            </Card>
                        ))
                    )}
                </TabsContent>
            </Tabs>
        </div>
    )
}

"use client"

import * as React from 'react'
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar'
import { Loader2, Camera, Upload, User } from 'lucide-react'
import api from '@/lib/api'

export default function SettingsPage() {
    interface UserProfile {
        name: string
        email: string
        phone?: string
        avatar?: string
        role: string
    }
    const [user, setUser] = React.useState<UserProfile | null>(null)
    const [isLoading, setIsLoading] = React.useState(true)
    const [isSaving, setIsSaving] = React.useState(false)

    // Profile Form
    const [formData, setFormData] = React.useState({
        name: '',
        phone: '',
    })
    const [avatarFile, setAvatarFile] = React.useState<File | null>(null)
    const [avatarPreview, setAvatarPreview] = React.useState<string | null>(null)

    // System Settings State
    const [systemSettings, setSystemSettings] = React.useState({
        platformName: '',
        supportEmail: '',
        primaryColor: '#2563eb'
    })

    React.useEffect(() => {
        fetchProfile()
    }, [])

    const fetchProfile = async () => {
        try {
            const [userRes, settingsRes] = await Promise.all([
                api.get('/users/me'),
                api.get('/settings') // Requires permissions, handles 403 gracefully if not admin
            ])

            setUser(userRes.data)
            setFormData({
                name: userRes.data.name || '',
                phone: userRes.data.phone || ''
            })
            setAvatarPreview(userRes.data.avatar ? `${process.env.NEXT_PUBLIC_API_URL?.replace('/api', '') || 'http://localhost:5001'}${userRes.data.avatar}` : null)

            if (settingsRes.data) {
                setSystemSettings(settingsRes.data)
            }
        } catch (error) {
            console.error(error)
        } finally {
            setIsLoading(false)
        }
    }

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0]
        if (file) {
            setAvatarFile(file)
            const reader = new FileReader()
            reader.onloadend = () => {
                setAvatarPreview(reader.result as string)
            }
            reader.readAsDataURL(file)
        }
    }

    const handleSaveProfile = async () => {
        setIsSaving(true)
        try {
            // 1. Update Details
            await api.put('/users/profile', formData)

            // 2. Upload Avatar if changed
            if (avatarFile) {
                const uploadData = new FormData()
                uploadData.append('avatar', avatarFile)
                await api.post('/users/profile-image', uploadData, {
                    headers: { 'Content-Type': 'multipart/form-data' }
                })
            }

            alert('Profile updated successfully!')
            fetchProfile() // Refresh
        } catch (error) {
            console.error(error)
            alert('Failed to update profile.')
        } finally {
            setIsSaving(false)
        }
    }

    if (isLoading) {
        return (
            <div className="flex h-[50vh] items-center justify-center">
                <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
            </div>
        )
    }

    return (
        <div className="space-y-6">
            <div>
                <h1 className="text-3xl font-bold tracking-tight">Account Settings</h1>
                <p className="text-muted-foreground">Manage your profile and preferences.</p>
            </div>

            <div className="grid gap-6 md:grid-cols-2">
                {/* Profile Card */}
                <Card className="md:col-span-2">
                    <CardHeader>
                        <CardTitle>Personal Profile</CardTitle>
                        <CardDescription>Update your photo and personal details.</CardDescription>
                    </CardHeader>
                    <CardContent className="space-y-6">
                        <div className="flex flex-col md:flex-row gap-8 items-start">
                            {/* Avatar Section */}
                            <div className="flex flex-col items-center gap-4">
                                <Avatar className="h-32 w-32 border-2 border-muted">
                                    <AvatarImage src={avatarPreview || ''} className="object-cover" />
                                    <AvatarFallback className="text-4xl bg-muted">
                                        {user?.name?.charAt(0) || 'U'}
                                    </AvatarFallback>
                                </Avatar>
                                <div className="relative">
                                    <input
                                        type="file"
                                        id="avatar-upload"
                                        className="hidden"
                                        accept="image/jpeg,image/png,image/jpg"
                                        onChange={handleFileChange}
                                    />
                                    <Button variant="outline" size="sm" className="cursor-pointer" asChild>
                                        <label htmlFor="avatar-upload">
                                            <Camera className="mr-2 h-4 w-4" />
                                            Change Photo
                                        </label>
                                    </Button>
                                </div>
                                <p className="text-xs text-muted-foreground">
                                    JPG, JPEG or PNG. Max 5MB.
                                </p>
                            </div>

                            {/* Details Section */}
                            <div className="flex-1 space-y-4 w-full max-w-lg">
                                <div className="grid gap-2">
                                    <Label>Full Name</Label>
                                    <Input
                                        value={formData.name}
                                        onChange={e => setFormData({ ...formData, name: e.target.value })}
                                    />
                                </div>
                                <div className="grid gap-2">
                                    <Label>Email Address</Label>
                                    <Input value={user?.email} disabled className="bg-muted/50" />
                                    <p className="text-[0.8rem] text-muted-foreground">Email cannot be changed.</p>
                                </div>
                                <div className="grid gap-2">
                                    <Label>Phone Number</Label>
                                    <Input
                                        value={formData.phone}
                                        onChange={e => setFormData({ ...formData, phone: e.target.value })}
                                        placeholder="+91..."
                                    />
                                </div>

                                <div className="pt-4">
                                    <Button onClick={handleSaveProfile} disabled={isSaving}>
                                        {isSaving && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                                        Save Changes
                                    </Button>
                                </div>
                            </div>
                        </div>
                    </CardContent>
                </Card>

                {/* Platform Settings */}
                {user?.role === 'SUPER_ADMIN' || user?.role === 'ADMIN' ? (
                    <Card>
                        <CardHeader>
                            <CardTitle>Platform Configuration</CardTitle>
                            <CardDescription>System-wide branding and settings.</CardDescription>
                        </CardHeader>
                        <CardContent className="space-y-4">
                            <div className="grid gap-2">
                                <Label>Platform Name</Label>
                                <Input
                                    value={systemSettings.platformName}
                                    onChange={e => setSystemSettings({ ...systemSettings, platformName: e.target.value })}
                                />
                            </div>
                            <div className="grid gap-2">
                                <Label>Support Email</Label>
                                <Input
                                    value={systemSettings.supportEmail}
                                    onChange={e => setSystemSettings({ ...systemSettings, supportEmail: e.target.value })}
                                />
                            </div>
                            <Button variant="outline" onClick={async () => {
                                try {
                                    await api.put('/settings', systemSettings)
                                    alert('Settings updated!')
                                } catch (e) { console.error(e); alert('Update failed') }
                            }}>Update Config</Button>
                        </CardContent>
                    </Card>
                ) : null}

                <Card>
                    <CardHeader>
                        <CardTitle>Integrations</CardTitle>
                        <CardDescription>Third-party service connections.</CardDescription>
                    </CardHeader>
                    <CardContent className="space-y-4">
                        <div className="flex items-center justify-between p-3 border rounded-md">
                            <div className="flex items-center gap-3">
                                <div className="bg-blue-100 p-2 rounded">
                                    <Video className="h-5 w-5 text-blue-600" />
                                </div>
                                <div>
                                    <p className="font-medium text-sm">Video Conferencing</p>
                                    <p className="text-xs text-muted-foreground">Zoom / Meet / Teams</p>
                                </div>
                            </div>
                            <Button variant="ghost" size="sm">Manage</Button>
                        </div>
                        <div className="flex items-center justify-between p-3 border rounded-md">
                            <div className="flex items-center gap-3">
                                <div className="bg-green-100 p-2 rounded">
                                    <DollarSign className="h-5 w-5 text-green-600" />
                                </div>
                                <div>
                                    <p className="font-medium text-sm">Payment Gateway</p>
                                    <p className="text-xs text-muted-foreground">Razorpay Connected</p>
                                </div>
                            </div>
                            <Button variant="ghost" size="sm">Configure</Button>
                        </div>
                    </CardContent>
                </Card>
            </div>
        </div>
    )
}

function Video({ className }: { className?: string }) {
    return (
        <svg
            className={className}
            xmlns="http://www.w3.org/2000/svg"
            viewBox="0 0 24 24"
            fill="none"
            stroke="currentColor"
            strokeWidth="2"
            strokeLinecap="round"
            strokeLinejoin="round"
        >
            <path d="M15 10l5-5v14l-5-5" />
            <path d="M4 6h16a2 2 0 0 1 2 2v8a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2z" />
        </svg>
    )
}

function DollarSign({ className }: { className?: string }) {
    return (
        <svg
            className={className}
            xmlns="http://www.w3.org/2000/svg"
            viewBox="0 0 24 24"
            fill="none"
            stroke="currentColor"
            strokeWidth="2"
            strokeLinecap="round"
            strokeLinejoin="round"
        >
            <line x1="12" y1="1" x2="12" y2="23" />
            <path d="M17 5H9.5a3.5 3.5 0 0 0 0 7h5a3.5 3.5 0 0 1 0 7H6" />
        </svg>
    )
}

"use client"

import { useState, useEffect } from "react"
import Image from "next/image"
import { motion } from "framer-motion"
import { Plus, Search, Edit, Trash2, Video, User, Briefcase, Linkedin } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
} from "@/components/ui/dialog"
import { Label } from "@/components/ui/label"
import { Textarea } from "@/components/ui/textarea"
import { toast } from "sonner"
import { Badge } from "@/components/ui/badge"

interface Skillcast {
    id: string
    title: string
    description: string
    videoUrl: string
    expertName: string
    designation: string
    company: string
    linkedinUrl: string
    experience: string
    thumbnail?: string
}

export default function AdminSkillcastPage() {
    const [skillcasts, setSkillcasts] = useState<Skillcast[]>([])
    const [loading, setLoading] = useState(true)
    const [searchQuery, setSearchQuery] = useState("")
    const [isDialogOpen, setIsDialogOpen] = useState(false)
    const [editingItem, setEditingItem] = useState<Skillcast | null>(null)

    // Form Stats
    const [formData, setFormData] = useState({
        title: "",
        description: "",
        videoUrl: "",
        expertName: "",
        designation: "",
        company: "",
        linkedinUrl: "",
        experience: "",
        thumbnail: ""
    })

    useEffect(() => {
        fetchSkillcasts()
    }, [])

    const fetchSkillcasts = async () => {
        try {
            const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/skillcasts`)
            if (res.ok) {
                const data = await res.json()
                setSkillcasts(Array.isArray(data) ? data : [])
            }
        } catch (error) {
            console.error(error)
            toast.error("Failed to fetch skillcasts")
        } finally {
            setLoading(false)
        }
    }

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault()
        try {
            const url = editingItem
                ? `${process.env.NEXT_PUBLIC_API_URL}/skillcasts/${editingItem.id}`
                : `${process.env.NEXT_PUBLIC_API_URL}/skillcasts`

            const method = editingItem ? "PUT" : "POST"

            const token = localStorage.getItem("token") // Assuming auth token is stored here

            const res = await fetch(url, {
                method,
                headers: {
                    "Content-Type": "application/json",
                    "Authorization": `Bearer ${token}`
                },
                body: JSON.stringify(formData)
            })

            if (res.ok) {
                toast.success(editingItem ? "Skillcast updated" : "Skillcast created")
                fetchSkillcasts()
                setIsDialogOpen(false)
                resetForm()
            } else {
                toast.error("Failed to save skillcast")
            }
        } catch (error) {
            console.error(error)
            toast.error("An error occurred")
        }
    }

    const handleDelete = async (id: string) => {
        if (!confirm("Are you sure you want to delete this skillcast?")) return

        try {
            const token = localStorage.getItem("token")
            const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/skillcasts/${id}`, {
                method: "DELETE",
                headers: {
                    "Authorization": `Bearer ${token}`
                }
            })

            if (res.ok) {
                toast.success("Skillcast deleted")
                fetchSkillcasts()
            } else {
                toast.error("Failed to delete")
            }
        } catch (error) {
            console.error(error)
            toast.error("Error deleting skillcast")
        }
    }

    const handleEdit = (item: any) => {
        setEditingItem(item)
        setFormData({
            title: item.title,
            description: item.description,
            videoUrl: item.videoUrl,
            expertName: item.expertName,
            designation: item.designation,
            company: item.company,
            linkedinUrl: item.linkedinUrl || "",
            experience: item.experience || "",
            thumbnail: item.thumbnail || ""
        })
        setIsDialogOpen(true)
    }

    const resetForm = () => {
        setEditingItem(null)
        setFormData({
            title: "",
            description: "",
            videoUrl: "",
            expertName: "",
            designation: "",
            company: "",
            linkedinUrl: "",
            experience: "",
            thumbnail: ""
        })
    }

    const filteredSkillcasts = skillcasts.filter(item =>
        item.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
        item.expertName.toLowerCase().includes(searchQuery.toLowerCase())
    )

    return (
        <div className="p-6 space-y-6">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                    <h1 className="text-3xl font-bold tracking-tight">Skillcast Management</h1>
                    <p className="text-muted-foreground">Manage expert interviews and video content.</p>
                </div>
                <Dialog open={isDialogOpen} onOpenChange={(open) => {
                    setIsDialogOpen(open)
                    if (!open) resetForm()
                }}>
                    <DialogTrigger asChild>
                        <Button className="gap-2">
                            <Plus className="w-4 h-4" /> Add Skillcast
                        </Button>
                    </DialogTrigger>
                    <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
                        <DialogHeader>
                            <DialogTitle>{editingItem ? "Edit Skillcast" : "Add New Skillcast"}</DialogTitle>
                        </DialogHeader>
                        <form onSubmit={handleSubmit} className="space-y-4 pt-4">
                            <div className="grid grid-cols-2 gap-4">
                                <div className="space-y-2 col-span-2">
                                    <Label>Title</Label>
                                    <Input
                                        value={formData.title}
                                        onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                                        required
                                        placeholder="e.g., The Future of AI in Tech"
                                    />
                                </div>
                                <div className="space-y-2 col-span-2">
                                    <Label>Description</Label>
                                    <Textarea
                                        value={formData.description}
                                        onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                                        required
                                        placeholder="Brief summary of the interview..."
                                    />
                                </div>
                                <div className="space-y-2">
                                    <Label>Video URL</Label>
                                    <Input
                                        value={formData.videoUrl}
                                        onChange={(e) => setFormData({ ...formData, videoUrl: e.target.value })}
                                        required
                                        placeholder="YouTube or MP4 URL"
                                    />
                                </div>
                                <div className="space-y-2">
                                    <Label>Thumbnail URL (Optional)</Label>
                                    <Input
                                        value={formData.thumbnail}
                                        onChange={(e) => setFormData({ ...formData, thumbnail: e.target.value })}
                                        placeholder="https://..."
                                    />
                                </div>

                                <div className="col-span-2 border-t pt-4 mt-2">
                                    <h4 className="font-medium mb-4 flex items-center gap-2">
                                        <User className="w-4 h-4" /> Expert Details
                                    </h4>
                                </div>

                                <div className="space-y-2">
                                    <Label>Expert Name</Label>
                                    <Input
                                        value={formData.expertName}
                                        onChange={(e) => setFormData({ ...formData, expertName: e.target.value })}
                                        required
                                        placeholder="e.g., John Doe"
                                    />
                                </div>
                                <div className="space-y-2">
                                    <Label>Designation</Label>
                                    <Input
                                        value={formData.designation}
                                        onChange={(e) => setFormData({ ...formData, designation: e.target.value })}
                                        required
                                        placeholder="e.g., CTO"
                                    />
                                </div>
                                <div className="space-y-2">
                                    <Label>Company</Label>
                                    <Input
                                        value={formData.company}
                                        onChange={(e) => setFormData({ ...formData, company: e.target.value })}
                                        required
                                        placeholder="e.g., TechCorp"
                                    />
                                </div>
                                <div className="space-y-2">
                                    <Label>Experience</Label>
                                    <Input
                                        value={formData.experience}
                                        onChange={(e) => setFormData({ ...formData, experience: e.target.value })}
                                        placeholder="e.g., 10+ Years"
                                    />
                                </div>
                                <div className="space-y-2 col-span-2">
                                    <Label>LinkedIn URL (Optional)</Label>
                                    <div className="flex items-center gap-2">
                                        <Linkedin className="w-4 h-4 text-muted-foreground" />
                                        <Input
                                            value={formData.linkedinUrl}
                                            onChange={(e) => setFormData({ ...formData, linkedinUrl: e.target.value })}
                                            placeholder="https://linkedin.com/in/..."
                                        />
                                    </div>
                                </div>
                            </div>
                            <div className="flex justify-end gap-2 pt-4">
                                <Button type="button" variant="outline" onClick={() => setIsDialogOpen(false)}>
                                    Cancel
                                </Button>
                                <Button type="submit">
                                    {editingItem ? "Update Skillcast" : "Create Skillcast"}
                                </Button>
                            </div>
                        </form>
                    </DialogContent>
                </Dialog>
            </div>

            {/* Search Filter */}
            <div className="relative max-w-md">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                <Input
                    placeholder="Search by title or expert..."
                    className="pl-10"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                />
            </div>

            {/* List */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {loading ? (
                    <p>Loading...</p>
                ) : filteredSkillcasts.length === 0 ? (
                    <div className="col-span-full text-center py-10 text-muted-foreground">
                        No skillcasts found. Add your first one!
                    </div>
                ) : (
                    filteredSkillcasts.map((item) => (
                        <Card key={item.id} className="overflow-hidden group">
                            <CardHeader className="p-0">
                                <div className="aspect-video relative bg-muted">
                                    {item.thumbnail ? (
                                        <Image src={item.thumbnail} alt={item.title} width={400} height={225} className="w-full h-full object-cover" />
                                    ) : (
                                        <div className="w-full h-full flex items-center justify-center text-muted-foreground">
                                            <Video className="w-10 h-10 opacity-20" />
                                        </div>
                                    )}
                                    <div className="absolute top-2 right-2 flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                        <Button size="icon" variant="secondary" className="h-8 w-8" onClick={() => handleEdit(item)}>
                                            <Edit className="w-4 h-4" />
                                        </Button>
                                        <Button size="icon" variant="destructive" className="h-8 w-8" onClick={() => handleDelete(item.id)}>
                                            <Trash2 className="w-4 h-4" />
                                        </Button>
                                    </div>
                                </div>
                            </CardHeader>
                            <CardContent className="p-4 space-y-3">
                                <div>
                                    <h3 className="font-semibold line-clamp-1">{item.title}</h3>
                                    <p className="text-xs text-muted-foreground line-clamp-2">{item.description}</p>
                                </div>
                                <div className="flex items-center gap-3 pt-2 border-t text-sm">
                                    <div className="h-8 w-8 rounded-full bg-primary/10 flex items-center justify-center shrink-0">
                                        <User className="w-4 h-4 text-primary" />
                                    </div>
                                    <div className="min-w-0">
                                        <div className="font-medium truncate">{item.expertName}</div>
                                        <div className="text-xs text-muted-foreground truncate">{item.designation}, {item.company}</div>
                                    </div>
                                </div>
                                <div className="flex flex-wrap gap-2">
                                    {item.experience && <Badge variant="secondary" className="text-[10px]">{item.experience} Exp</Badge>}
                                    {item.linkedinUrl && <Badge variant="outline" className="text-[10px] gap-1"><Linkedin className="w-3 h-3" /> Linked</Badge>}
                                </div>
                            </CardContent>
                        </Card>
                    ))
                )}
            </div>
        </div>
    )
}

"use client"

import * as React from 'react'
import { Card, CardContent } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Input } from '@/components/ui/input'
import { Textarea } from '@/components/ui/textarea'
import { ScrollArea } from '@/components/ui/scroll-area'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Loader2, MessageSquare, Paperclip, Send, Lock } from 'lucide-react'
import { format } from 'date-fns'
import api, { ticketApi } from '@/lib/api'
import { useAuth } from '@/lib/auth-context'

// Types
interface Ticket {
    id: string
    subject: string
    description: string
    status: 'OPEN' | 'IN_PROGRESS' | 'WAITING_FOR_USER' | 'RESOLVED' | 'CLOSED'
    priority: 'LOW' | 'MEDIUM' | 'HIGH' | 'URGENT'
    category: string
    createdAt: string
    user: {
        name: string
        email: string
        role: string
    }
    _count: {
        messages: number
    }
}

interface Message {
    id: string
    message: string
    attachmentUrl?: string
    isStaffReply: boolean
    createdAt: string
}

export default function AdminSupportPage() {
    interface StaffUser {
        id: string
        name: string
        role: string
    }
    const [staffList, setStaffList] = React.useState<StaffUser[]>([])
    const [internalNotes, setInternalNotes] = React.useState('')
    const [activeTab, setActiveTab] = React.useState('conversation')

    const { user: _user } = useAuth()
    const [file, setFile] = React.useState<File | null>(null)

    const [tickets, setTickets] = React.useState<Ticket[]>([])
    const [selectedTicket, setSelectedTicket] = React.useState<Ticket | null>(null)
    const [messages, setMessages] = React.useState<Message[]>([])
    const [isLoading, setIsLoading] = React.useState(true)
    const [isLoadingMessages, setIsLoadingMessages] = React.useState(false)
    const [filterStatus, setFilterStatus] = React.useState('ALL')
    const [filterPriority, setFilterPriority] = React.useState('ALL')
    const [replyText, setReplyText] = React.useState('')
    const [isSending, setIsSending] = React.useState(false)

    // Fetch Tickets & Staff
    React.useEffect(() => {
        fetchTickets()
        fetchStaff()
    }, [filterStatus, filterPriority])

    // Fetch Messages when ticket selected
    React.useEffect(() => {
        if (selectedTicket) {
            fetchMessages(selectedTicket.id)
        }
    }, [selectedTicket])

    const fetchTickets = async () => {
        setIsLoading(true)
        try {
            const params: Record<string, string> = {}
            if (filterStatus !== 'ALL') params.status = filterStatus
            if (filterPriority !== 'ALL') params.priority = filterPriority

            const res = await ticketApi.getAll(params)
            setTickets(res.data)
        } catch (error) {
            console.error(error)
        } finally {
            setIsLoading(false)
        }
    }

    const fetchMessages = async (ticketId: string) => {
        setIsLoadingMessages(true)
        try {
            const res = await api.get(`/tickets/${ticketId}`)
            setMessages(res.data.messages)
        } catch (error) {
            console.error(error)
        } finally {
            setIsLoadingMessages(false)
        }
    }

    const fetchStaff = async () => {
        try {
            const res = await api.get('/users?role=STAFF,ADMIN,INSTRUCTOR')
            if (res.data.users) {
                setStaffList(res.data.users.filter((u: { role: string }) => ['ADMIN', 'SUPER_ADMIN', 'STAFF', 'INSTRUCTOR'].includes(u.role)))
            }
        } catch (error) {
            console.error("Failed to fetch staff", error)
        }
    }

    const handleAssign = async (staffId: string) => {
        if (!selectedTicket) return
        try {
            await api.patch(`/tickets/${selectedTicket.id}/assign`, { assignedTo: staffId })
            setSelectedTicket({ ...selectedTicket, assignedTo: staffId } as Ticket & { assignedTo: string })
            fetchTickets()
        } catch (error) {
            console.error(error)
        }
    }

    const handleSaveNotes = async () => {
        if (!selectedTicket) return
        try {
            await api.patch(`/tickets/${selectedTicket.id}/assign`, { internalNotes })
            alert("Notes saved")
        } catch (error) {
            console.error(error)
        }
    }

    const handleSendReply = async () => {
        if (!selectedTicket || !replyText.trim()) return

        setIsSending(true)
        try {
            const formData = new FormData()
            formData.append('message', replyText)
            if (file) {
                formData.append('attachment', file)
            }

            await ticketApi.reply(selectedTicket.id, formData)

            // Refresh messages and ticket list
            await fetchMessages(selectedTicket.id)
            setReplyText('')
            setFile(null)
            fetchTickets()
        } catch (error) {
            console.error(error)
            alert('Failed to send reply')
        } finally {
            setIsSending(false)
        }
    }

    const handleStatusUpdate = async (newStatus: string) => {
        if (!selectedTicket) return
        try {
            await ticketApi.updateStatus(selectedTicket.id, { status: newStatus })
            setSelectedTicket({ ...selectedTicket, status: newStatus as Ticket['status'] })
            fetchTickets()
        } catch (error) {
            console.error(error)
            alert('Failed to update status')
        }
    }

    const getStatusColor = (status: string) => {
        switch (status) {
            case 'OPEN': return 'bg-yellow-100 text-yellow-800'
            case 'IN_PROGRESS': return 'bg-blue-100 text-blue-800'
            case 'WAITING_FOR_USER': return 'bg-purple-100 text-purple-800'
            case 'RESOLVED': return 'bg-green-100 text-green-800'
            case 'CLOSED': return 'bg-gray-100 text-gray-800'
            default: return 'bg-gray-100'
        }
    }

    const getPriorityColor = (priority: string) => {
        switch (priority) {
            case 'URGENT': return 'text-red-600 font-bold'
            case 'HIGH': return 'text-orange-500 font-semibold'
            default: return 'text-muted-foreground'
        }
    }

    return (
        <div className="flex h-[calc(100vh-6rem)] gap-6">
            {/* Ticket List (Left Panel) */}
            <div className="w-1/3 flex flex-col gap-4 border-r pr-6">
                <div>
                    <h2 className="text-2xl font-bold tracking-tight mb-2">Support Tickets</h2>
                    <div className="flex gap-2 flex-col lg:flex-row">
                        <Select value={filterStatus} onValueChange={setFilterStatus}>
                            <SelectTrigger>
                                <SelectValue placeholder="Status" />
                            </SelectTrigger>
                            <SelectContent>
                                <SelectItem value="ALL">All Status</SelectItem>
                                <SelectItem value="OPEN">Open</SelectItem>
                                <SelectItem value="IN_PROGRESS">In Progress</SelectItem>
                                <SelectItem value="WAITING_FOR_USER">Waiting for User</SelectItem>
                                <SelectItem value="RESOLVED">Resolved</SelectItem>
                                <SelectItem value="CLOSED">Closed</SelectItem>
                            </SelectContent>
                        </Select>
                        <Select value={filterPriority} onValueChange={setFilterPriority}>
                            <SelectTrigger>
                                <SelectValue placeholder="Priority" />
                            </SelectTrigger>
                            <SelectContent>
                                <SelectItem value="ALL">All Priority</SelectItem>
                                <SelectItem value="URGENT">Urgent</SelectItem>
                                <SelectItem value="HIGH">High</SelectItem>
                                <SelectItem value="MEDIUM">Medium</SelectItem>
                                <SelectItem value="LOW">Low</SelectItem>
                            </SelectContent>
                        </Select>
                    </div>
                </div>

                <ScrollArea className="flex-1">
                    <div className="space-y-3">
                        {isLoading ? (
                            <div className="flex justify-center p-4"><Loader2 className="animate-spin text-muted-foreground" /></div>
                        ) : tickets.length === 0 ? (
                            <div className="text-center text-muted-foreground p-8">No tickets found.</div>
                        ) : (
                            tickets.map(ticket => (
                                <Card
                                    key={ticket.id}
                                    className={`cursor-pointer transition-colors hover:bg-muted/50 ${selectedTicket?.id === ticket.id ? 'border-primary bg-primary/5' : ''}`}
                                    onClick={() => setSelectedTicket(ticket)}
                                >
                                    <CardContent className="p-4 space-y-2">
                                        <div className="flex justify-between items-start">
                                            <Badge variant="outline" className={getStatusColor(ticket.status)}>
                                                {ticket.status.replace('_', ' ')}
                                            </Badge>
                                            <span className="text-xs text-muted-foreground">
                                                {format(new Date(ticket.createdAt), 'MMM d, h:mm a')}
                                            </span>
                                        </div>
                                        <h4 className="font-semibold line-clamp-1">{ticket.subject}</h4>
                                        <div className="flex justify-between items-center text-sm text-muted-foreground">
                                            <span className="flex items-center gap-1">
                                                <MessageSquare className="h-3 w-3" />
                                                {ticket._count.messages}
                                            </span>
                                            <span className={getPriorityColor(ticket.priority)}>
                                                {ticket.priority}
                                            </span>
                                        </div>
                                        <div className="text-xs pt-1 border-t mt-2">
                                            {ticket.user.name} ({ticket.user.role})
                                        </div>
                                    </CardContent>
                                </Card>
                            ))
                        )}
                    </div>
                </ScrollArea>
            </div>

            {/* Right Panel */}
            <div className="flex-1 flex flex-col bg-muted/20 rounded-lg border overflow-hidden">
                {selectedTicket ? (
                    <>
                        {/* Header */}
                        <div className="p-4 border-b bg-background flex justify-between items-center">
                            <div>
                                <h3 className="font-bold text-lg">{selectedTicket.subject}</h3>
                                <p className="text-sm text-muted-foreground">
                                    Ticket #{selectedTicket.id.slice(-6)} • {selectedTicket.category}
                                </p>
                            </div>
                            <div className="flex gap-2">
                                <Select onValueChange={handleAssign} value={(selectedTicket as Ticket & { assignedTo?: string }).assignedTo || ''}>
                                    <SelectTrigger className="w-[180px]">
                                        <SelectValue placeholder="Assign to..." />
                                    </SelectTrigger>
                                    <SelectContent>
                                        <SelectItem value="unassigned">Unassigned</SelectItem>
                                        {staffList.map(staff => (
                                            <SelectItem key={staff.id} value={staff.id}>{staff.name}</SelectItem>
                                        ))}
                                    </SelectContent>
                                </Select>

                                <Select
                                    value={selectedTicket.status}
                                    onValueChange={handleStatusUpdate}
                                >
                                    <SelectTrigger className="w-[160px]">
                                        <SelectValue />
                                    </SelectTrigger>
                                    <SelectContent>
                                        <SelectItem value="OPEN">Open</SelectItem>
                                        <SelectItem value="IN_PROGRESS">In Progress</SelectItem>
                                        <SelectItem value="WAITING_FOR_USER">Waiting for User</SelectItem>
                                        <SelectItem value="RESOLVED">Resolved</SelectItem>
                                        <SelectItem value="CLOSED">Closed</SelectItem>
                                    </SelectContent>
                                </Select>
                            </div>
                        </div>

                        {/* Tabs for Conversation vs Notes */}
                        <div className="flex border-b bg-background px-4 gap-4">
                            <button
                                className={`py-2 text-sm font-medium border-b-2 ${activeTab === 'conversation' ? 'border-primary text-primary' : 'border-transparent text-muted-foreground'}`}
                                onClick={() => setActiveTab('conversation')}
                            >
                                Conversation
                            </button>
                            <button
                                className={`py-2 text-sm font-medium border-b-2 ${activeTab === 'notes' ? 'border-primary text-primary' : 'border-transparent text-muted-foreground'}`}
                                onClick={() => {
                                    setActiveTab('notes')
                                    setInternalNotes((selectedTicket as Ticket & { internalNotes?: string }).internalNotes || '')
                                }}
                            >
                                Internal Notes
                            </button>
                        </div>

                        {/* Content Area */}
                        {activeTab === 'conversation' ? (
                            <>
                                <ScrollArea className="flex-1 p-4">
                                    <div className="space-y-4">
                                        {isLoadingMessages ? (
                                            <div className="flex justify-center p-8"><Loader2 className="animate-spin" /></div>
                                        ) : (
                                            messages.map((msg) => (
                                                <div
                                                    key={msg.id}
                                                    className={`flex ${msg.isStaffReply ? 'justify-end' : 'justify-start'}`}
                                                >
                                                    <div
                                                        className={`max-w-[80%] rounded-lg p-3 ${msg.isStaffReply
                                                            ? 'bg-primary text-primary-foreground'
                                                            : 'bg-muted border'
                                                            }`}
                                                    >
                                                        <p className="text-sm whitespace-pre-wrap">{msg.message}</p>
                                                        {msg.attachmentUrl && (
                                                            <div className="mt-2">
                                                                <a
                                                                    href={`${process.env.NEXT_PUBLIC_API_URL}${msg.attachmentUrl}`}
                                                                    target="_blank"
                                                                    rel="noreferrer"
                                                                    className="text-xs underline flex items-center gap-1"
                                                                >
                                                                    <Paperclip className="h-3 w-3" />
                                                                    View Attachment
                                                                </a>
                                                            </div>
                                                        )}
                                                        <p className={`text-[10px] mt-1 text-right ${msg.isStaffReply ? 'text-primary-foreground/70' : 'text-muted-foreground'}`}>
                                                            {format(new Date(msg.createdAt), 'h:mm a')}
                                                        </p>
                                                    </div>
                                                </div>
                                            ))
                                        )}
                                    </div>
                                </ScrollArea>
                                <div className="p-4 border-t bg-background">
                                    <div className="flex gap-2 items-end">
                                        <div className="flex-1 space-y-2">
                                            <Textarea
                                                placeholder="Type your reply..."
                                                className="min-h-[60px]"
                                                value={replyText}
                                                onChange={(e) => setReplyText(e.target.value)}
                                            />
                                            <div className="flex items-center gap-2">
                                                <Input
                                                    type="file"
                                                    className="w-full text-xs"
                                                    onChange={(e) => setFile(e.target.files?.[0] || null)}
                                                />
                                            </div>
                                        </div>
                                        <Button
                                            className="h-[60px] px-4"
                                            onClick={handleSendReply}
                                            disabled={isSending || !replyText.trim()}
                                        >
                                            {isSending ? <Loader2 className="animate-spin" /> : <Send className="h-4 w-4" />}
                                        </Button>
                                    </div>
                                </div>
                            </>
                        ) : (
                            <div className="flex-1 p-4 flex flex-col gap-4">
                                <div className="bg-yellow-50 border border-yellow-200 p-4 rounded-md text-sm text-yellow-800">
                                    <h4 className="font-semibold flex items-center gap-2"><Lock className="h-4 w-4" /> Confidential</h4>
                                    <p>These notes are only visible to staff members.</p>
                                </div>
                                <Textarea
                                    className="flex-1 resize-none"
                                    placeholder="Add internal notes about this ticket..."
                                    value={internalNotes}
                                    onChange={(e) => setInternalNotes(e.target.value)}
                                />
                                <div className="flex justify-end">
                                    <Button onClick={handleSaveNotes}>Save Notes</Button>
                                </div>
                            </div>
                        )}
                    </>
                ) : (
                    <div className="flex-1 flex items-center justify-center text-muted-foreground flex-col gap-2">
                        <MessageSquare className="h-12 w-12 opacity-20" />
                        <p>Select a ticket to view conversation</p>
                    </div>
                )}
            </div>
        </div>
    )
}

"use client"

import * as React from 'react'
import { Card, CardContent } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { ScrollArea } from '@/components/ui/scroll-area'
import {
    Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger, DialogFooter
} from "@/components/ui/dialog"
import { Input } from '@/components/ui/input'
import { Textarea } from '@/components/ui/textarea'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar'
import {
    CheckSquare, Plus, Calendar, Clock, AlertCircle, CheckCircle2, User, Trash2, MessageSquare, Send
} from 'lucide-react'
import api from '@/lib/api'
import { format } from 'date-fns'
import { toast } from 'sonner'

interface Comment {
    id: string
    content: string
    createdAt: string
    user?: {
        name: string
        avatar?: string
    }
}

interface Task {
    id: string
    title: string
    description?: string
    status: 'PENDING' | 'IN_PROGRESS' | 'COMPLETED' | 'OVERDUE'
    priority: 'LOW' | 'MEDIUM' | 'HIGH' | 'URGENT'
    dueDate?: string
    assignedTo?: string
    assignee?: { id: string, name: string, avatar?: string }
    comments?: Comment[]
    _count?: { comments: number }
}

export default function TaskManagerPage() {
    const [tasks, setTasks] = React.useState<Task[]>([])
    interface TaskUser {
        id: string
        name: string
    }
    const [users, setUsers] = React.useState<TaskUser[]>([])
    const [_isLoading, setIsLoading] = React.useState(true)
    const [isAddOpen, setIsAddOpen] = React.useState(false)
    const [selectedTask, setSelectedTask] = React.useState<Task | null>(null)
    const [detailOpen, setDetailOpen] = React.useState(false)
    const [commentText, setCommentText] = React.useState('')

    // New Task Form
    const [newTask, setNewTask] = React.useState({
        title: '',
        description: '',
        priority: 'MEDIUM',
        dueDate: '',
        status: 'PENDING',
        assignedTo: ''
    })

    React.useEffect(() => {
        fetchData()
    }, [])

    const fetchData = async () => {
        setIsLoading(true)
        try {
            const [tasksRes, usersRes] = await Promise.all([
                api.get('/tasks'),
                api.get('/users?role=ADMIN,INSTRUCTOR,STAFF') // Assuming filter exists or returns all
            ])
            setTasks(tasksRes.data || [])
            setUsers(usersRes.data.users || usersRes.data || [])
        } catch {
            // Error handling
        } finally {
            setIsLoading(false)
        }
    }

    const handleAddTask = async () => {
        try {
            await api.post('/tasks', newTask)
            setIsAddOpen(false)
            fetchData()
            setNewTask({ title: '', description: '', priority: 'MEDIUM', dueDate: '', status: 'PENDING', assignedTo: '' })
            toast.success('Task created')
        } catch (_error) {
            toast.error('Failed to add task')
        }
    }

    const handleUpdateStatus = async (id: string, currentStatus: string, e?: React.MouseEvent) => {
        if (e) e.stopPropagation()
        const nextStatus =
            currentStatus === 'PENDING' ? 'IN_PROGRESS' :
                currentStatus === 'IN_PROGRESS' ? 'COMPLETED' : 'PENDING'

        try {
            setTasks(prev => prev.map(t => t.id === id ? { ...t, status: nextStatus as Task['status'] } : t))
            await api.put(`/tasks/${id}`, { status: nextStatus })
        } catch (_error) {
            fetchData()
        }
    }

    const handleDeleteTask = async (id: string, e?: React.MouseEvent) => {
        if (e) e.stopPropagation()
        if (!confirm('Delete this task?')) return
        try {
            await api.delete(`/tasks/${id}`)
            setTasks(prev => prev.filter(t => t.id !== id))
            if (selectedTask?.id === id) setDetailOpen(false)
            toast.success('Task deleted')
        } catch (_error) {
            toast.error('Failed to delete task')
        }
    }

    const handleAddComment = async () => {
        if (!selectedTask || !commentText.trim()) return
        try {
            const res = await api.post(`/tasks/${selectedTask.id}/comments`, { text: commentText })
            const newComment = res.data

            // Update local state
            const updatedTask = {
                ...selectedTask,
                comments: [newComment, ...(selectedTask.comments || [])]
            }
            setSelectedTask(updatedTask)
            setTasks(prev => prev.map(t => t.id === selectedTask.id ? updatedTask : t))
            setCommentText('')
        } catch {
            toast.error('Failed to post comment')
        }
    }

    const getPriorityColor = (priority: string) => {
        switch (priority) {
            case 'URGENT': return 'bg-red-100 text-red-700 border-red-200'
            case 'HIGH': return 'bg-orange-100 text-orange-700 border-orange-200'
            case 'MEDIUM': return 'bg-blue-100 text-blue-700 border-blue-200'
            default: return 'bg-gray-100 text-gray-700 border-gray-200'
        }
    }

    const openDetail = (task: Task) => {
        setSelectedTask(task)
        setDetailOpen(true)
    }

    const KanbanColumn = ({ status, title, icon: Icon }: { status: string, title: string, icon: React.ElementType }) => {
        const columnTasks = tasks.filter(t => t.status === status)

        return (
            <div className="flex flex-col h-full bg-muted/30 rounded-lg border p-4">
                <div className="flex items-center justify-between mb-4">
                    <h3 className="font-semibold flex items-center gap-2">
                        <Icon className="h-4 w-4" />
                        {title}
                    </h3>
                    <Badge variant="secondary">{columnTasks.length}</Badge>
                </div>

                <ScrollArea className="flex-1">
                    <div className="space-y-3 pr-4">
                        {columnTasks.map(task => (
                            <Card key={task.id} className="cursor-pointer hover:shadow-md transition-shadow" onClick={() => openDetail(task)}>
                                <CardContent className="p-4 space-y-3">
                                    <div className="flex justify-between items-start">
                                        <Badge variant="outline" className={getPriorityColor(task.priority)}>
                                            {task.priority}
                                        </Badge>
                                        <div className="flex gap-1">
                                            {task.assignee && (
                                                <Avatar className="h-6 w-6">
                                                    <AvatarImage src={task.assignee.avatar} />
                                                    <AvatarFallback>{task.assignee.name[0]}</AvatarFallback>
                                                </Avatar>
                                            )}
                                        </div>
                                    </div>

                                    <div>
                                        <h4 className="font-medium text-sm leading-none mb-1">{task.title}</h4>
                                        {task.description && <p className="text-xs text-muted-foreground line-clamp-2">{task.description}</p>}
                                    </div>

                                    <div className="flex items-center justify-between pt-2">
                                        <div className="flex items-center gap-3">
                                            {task.dueDate && (
                                                <div className="flex items-center text-xs text-muted-foreground">
                                                    <Calendar className="h-3 w-3 mr-1" />
                                                    {format(new Date(task.dueDate), 'MMM d')}
                                                </div>
                                            )}
                                            {(task.comments?.length || 0) > 0 && (
                                                <div className="flex items-center text-xs text-muted-foreground">
                                                    <MessageSquare className="h-3 w-3 mr-1" />
                                                    {task.comments?.length}
                                                </div>
                                            )}
                                        </div>
                                        <Button
                                            size="sm"
                                            variant={status === 'COMPLETED' ? 'outline' : 'default'}
                                            className="h-6 text-xs"
                                            onClick={(e) => handleUpdateStatus(task.id, status, e)}
                                        >
                                            {status === 'PENDING' ? 'Start' : status === 'IN_PROGRESS' ? 'Complete' : 'Reopen'}
                                        </Button>
                                    </div>
                                </CardContent>
                            </Card>
                        ))}
                    </div>
                </ScrollArea>
            </div>
        )
    }

    return (
        <div className="space-y-6 h-[calc(100vh-100px)] flex flex-col">
            <div className="flex items-center justify-between shrink-0">
                <div>
                    <h1 className="text-3xl font-bold tracking-tight">Task Manager</h1>
                    <p className="text-muted-foreground">Organize your team&apos;s workflow and priorities.</p>
                </div>
                <Dialog open={isAddOpen} onOpenChange={setIsAddOpen}>
                    <DialogTrigger asChild>
                        <Button>
                            <Plus className="mr-2 h-4 w-4" />
                            New Task
                        </Button>
                    </DialogTrigger>
                    <DialogContent>
                        <DialogHeader>
                            <DialogTitle>Create New Task</DialogTitle>
                        </DialogHeader>
                        <div className="space-y-4 py-4">
                            <div className="space-y-2">
                                <label className="text-sm font-medium">Task Title</label>
                                <Input value={newTask.title} onChange={e => setNewTask({ ...newTask, title: e.target.value })} placeholder="e.g. Follow up with leads" />
                            </div>
                            <div className="space-y-2">
                                <label className="text-sm font-medium">Description</label>
                                <Textarea value={newTask.description} onChange={e => setNewTask({ ...newTask, description: e.target.value })} />
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div className="space-y-2">
                                    <label className="text-sm font-medium">Priority</label>
                                    <Select value={newTask.priority} onValueChange={v => setNewTask({ ...newTask, priority: v })}>
                                        <SelectTrigger><SelectValue /></SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="LOW">Low</SelectItem>
                                            <SelectItem value="MEDIUM">Medium</SelectItem>
                                            <SelectItem value="HIGH">High</SelectItem>
                                            <SelectItem value="URGENT">Urgent</SelectItem>
                                        </SelectContent>
                                    </Select>
                                </div>
                                <div className="space-y-2">
                                    <label className="text-sm font-medium">Assign To</label>
                                    <Select value={newTask.assignedTo} onValueChange={v => setNewTask({ ...newTask, assignedTo: v })}>
                                        <SelectTrigger><SelectValue placeholder="Select User" /></SelectTrigger>
                                        <SelectContent>
                                            {users.map(u => (
                                                <SelectItem key={u.id} value={u.id}>{u.name}</SelectItem>
                                            ))}
                                        </SelectContent>
                                    </Select>
                                </div>
                                <div className="space-y-2">
                                    <label className="text-sm font-medium">Due Date</label>
                                    <Input type="date" value={newTask.dueDate} onChange={e => setNewTask({ ...newTask, dueDate: e.target.value })} />
                                </div>
                            </div>
                        </div>
                        <DialogFooter>
                            <Button onClick={handleAddTask}>Create Task</Button>
                        </DialogFooter>
                    </DialogContent>
                </Dialog>
            </div>

            <div className="flex-1 grid grid-cols-1 md:grid-cols-3 gap-6 min-h-0">
                <KanbanColumn status="PENDING" title="To Do" icon={AlertCircle} />
                <KanbanColumn status="IN_PROGRESS" title="In Progress" icon={Clock} />
                <KanbanColumn status="COMPLETED" title="Completed" icon={CheckCircle2} />
            </div>

            {/* Task Detail Modal */}
            <Dialog open={detailOpen} onOpenChange={setDetailOpen}>
                <DialogContent className="max-w-2xl max-h-[90vh] flex flex-col">
                    <DialogHeader>
                        <div className="flex justify-between items-start pr-8">
                            <DialogTitle className="text-xl">{selectedTask?.title}</DialogTitle>
                            <Button variant="ghost" size="icon" className="text-destructive" onClick={() => selectedTask && handleDeleteTask(selectedTask.id)}>
                                <Trash2 className="h-4 w-4" />
                            </Button>
                        </div>
                    </DialogHeader>

                    <div className="flex-1 overflow-y-auto pr-2 space-y-6">
                        <div className="flex gap-4 text-sm text-muted-foreground">
                            <Badge variant="outline">{selectedTask?.priority}</Badge>
                            <span className="flex items-center gap-1">
                                <User className="h-3 w-3" />
                                Assigned to: {selectedTask?.assignee?.name || 'Unassigned'}
                            </span>
                            {selectedTask?.dueDate && (
                                <span className="flex items-center gap-1">
                                    <Calendar className="h-3 w-3" />
                                    Due: {format(new Date(selectedTask.dueDate), 'MMM d, yyyy')}
                                </span>
                            )}
                        </div>

                        <div className="text-sm bg-muted/30 p-4 rounded-lg">
                            {selectedTask?.description || 'No description provided.'}
                        </div>

                        {/* Comments Section */}
                        <div className="space-y-4">
                            <h3 className="font-semibold flex items-center gap-2">
                                <MessageSquare className="h-4 w-4" />
                                Comments
                            </h3>

                            <div className="space-y-4 mb-4">
                                {selectedTask?.comments && selectedTask.comments.length > 0 ? (
                                    selectedTask.comments.map(comment => (
                                        <div key={comment.id} className="flex gap-3 text-sm">
                                            <Avatar className="h-8 w-8">
                                                <AvatarImage src={comment.user?.avatar} />
                                                <AvatarFallback>{comment.user?.name?.[0]}</AvatarFallback>
                                            </Avatar>
                                            <div className="flex-1 space-y-1">
                                                <div className="flex items-center gap-2">
                                                    <span className="font-medium">{comment.user?.name}</span>
                                                    <span className="text-xs text-muted-foreground">
                                                        {format(new Date(comment.createdAt), 'MMM d, h:mm a')}
                                                    </span>
                                                </div>
                                                <p className="text-muted-foreground">{comment.content}</p>
                                            </div>
                                        </div>
                                    ))
                                ) : (
                                    <p className="text-sm text-muted-foreground italic">No comments yet.</p>
                                )}
                            </div>
                        </div>
                    </div>

                    <div className="pt-4 border-t flex gap-2">
                        <Input
                            placeholder="Write a comment..."
                            value={commentText}
                            onChange={(e) => setCommentText(e.target.value)}
                            onKeyDown={(e) => e.key === 'Enter' && handleAddComment()}
                        />
                        <Button size="icon" onClick={handleAddComment} disabled={!commentText.trim()}>
                            <Send className="h-4 w-4" />
                        </Button>
                    </div>
                </DialogContent>
            </Dialog>
        </div>
    )
}

"use client"

import { useState, useEffect } from "react"
import { useParams, useRouter } from "next/navigation"
import api from "@/lib/api"
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card"
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs"
import { ScrollArea } from "@/components/ui/scroll-area"
import { Loader2, ArrowLeft, Mail, Phone, Calendar, Shield, Activity, FileText } from "lucide-react"

export default function User360Page() {
    const { id } = useParams()
    const router = useRouter()


    interface UserProfile {
        id: string
        name: string
        email: string
        role: string
        avatar?: string
        createdAt: string
        isActive: boolean
    }
    interface AuditLog {
        id: string
        action: string
        entityType: string
        timestamp: string
        method: string
        path: string
        ipAddress?: string
        userAgent?: string
        details?: unknown
    }

    const [user, setUser] = useState<UserProfile | null>(null)
    const [auditLogs, setAuditLogs] = useState<AuditLog[]>([])
    const [isLoading, setIsLoading] = useState(true)

    useEffect(() => {
        fetchData()
    }, [id])

    const fetchData = async () => {
        try {
            // Fetch basic user data (mocking endpoint logic as /users/id might not exist, using activity mostly)
            // But we do need user details. We can reuse /users/me logic if we had /users/:id
            // For now, let's assume we can fetch via the list or dedicated endpoint.
            // Since we implemented GET /users/:id/activity, let's assume we can get basic info there or fetch list and find.
            // Let's rely on activity primarily as that's the new feature.

            // Actually, best to verify if there is a generic admin get user. 
            // Existing `user.routes.js` doesn't have GET /:id except 'me'. 
            // I will use activity to show "Working" and mock user details from it if possible, OR
            // I should have added GET /api/users/:id. 
            // Optimization: I'll fetch /api/users (list) and find (inefficient but safe for now) OR just display activity.

            const [activityRes, usersRes] = await Promise.all([
                api.get(`/users/${id}/activity`),
                api.get('/users')
            ])

            setAuditLogs(activityRes.data)

            const foundUser = usersRes.data.users.find((u: UserProfile) => u.id === id)
            setUser(foundUser)

        } catch (error) {
            console.error("Failed to fetch user data", error)
        } finally {
            setIsLoading(false)
        }
    }

    if (isLoading) return <div className="flex justify-center p-20"><Loader2 className="animate-spin h-8 w-8" /></div>
    if (!user) return <div className="p-8">User not found</div>

    return (
        <div className="space-y-6">
            <Button variant="ghost" onClick={() => router.back()} className="mb-4">
                <ArrowLeft className="mr-2 h-4 w-4" /> Back to Users
            </Button>

            {/* Profile Header */}
            <div className="grid gap-6 md:grid-cols-3">
                <Card className="md:col-span-1">
                    <CardContent className="pt-6 flex flex-col items-center text-center">
                        <Avatar className="h-24 w-24 mb-4">
                            <AvatarImage src={user.avatar} />
                            <AvatarFallback className="text-2xl">{user.name?.[0]}</AvatarFallback>
                        </Avatar>
                        <h2 className="text-2xl font-bold">{user.name}</h2>
                        <Badge variant="outline" className="mt-2 mb-4">{user.role}</Badge>

                        <div className="w-full space-y-3 text-left">
                            <div className="flex items-center gap-2 text-sm text-muted-foreground">
                                <Mail className="h-4 w-4" /> {user.email}
                            </div>
                            <div className="flex items-center gap-2 text-sm text-muted-foreground">
                                <Calendar className="h-4 w-4" /> Joined {new Date(user.createdAt).toLocaleDateString()}
                            </div>
                            <div className="flex items-center gap-2 text-sm text-muted-foreground">
                                <Shield className="h-4 w-4" /> {user.isActive ? 'Active Account' : 'Deactivated'}
                            </div>
                        </div>
                    </CardContent>
                </Card>

                {/* Activity & Stats */}
                <div className="md:col-span-2 space-y-6">
                    <Card>
                        <CardHeader>
                            <CardTitle className="flex items-center gap-2">
                                <Activity className="h-5 w-5 text-blue-600" />
                                Audit Trail & Activity
                            </CardTitle>
                            <CardDescription>
                                Monitor accountability: Track every action performed by this user.
                            </CardDescription>
                        </CardHeader>
                        <CardContent>
                            <ScrollArea className="h-[400px] pr-4">
                                <div className="space-y-6 relative border-l ml-2 pl-6">
                                    {auditLogs.length === 0 && (
                                        <p className="text-muted-foreground text-sm">No activity recorded for this user yet.</p>
                                    )}
                                    {auditLogs.map((log) => (
                                        <div key={log.id} className="relative">
                                            <div className={`absolute -left-[31px] top-1 h-3 w-3 rounded-full border-2 border-white ${log.action === 'LOGIN' ? 'bg-green-500' :
                                                log.action === 'DELETE' ? 'bg-red-500' :
                                                    'bg-blue-500'
                                                }`} />
                                            <div className="flex flex-col gap-1">
                                                <div className="flex items-center gap-2">
                                                    <span className="font-semibold text-sm">{log.action}</span>
                                                    <Badge variant="secondary" className="text-[10px]">{log.entityType}</Badge>
                                                    <span className="text-xs text-muted-foreground ml-auto">
                                                        {new Date(log.timestamp).toLocaleString()}
                                                    </span>
                                                </div>
                                                <p className="text-xs text-muted-foreground bg-muted/50 p-2 rounded font-mono">
                                                    {log.method} {log.path}
                                                </p>
                                                {log.ipAddress && (
                                                    <div className="text-[10px] text-muted-foreground mt-1">
                                                        IP: {log.ipAddress} | UA: {log.userAgent?.substring(0, 50)}...
                                                    </div>
                                                )}
                                                {Boolean(log.details) && (
                                                    <pre className="text-[10px] bg-slate-900 text-slate-50 p-2 rounded mt-2 overflow-x-auto">
                                                        {JSON.stringify(log.details as Record<string, unknown>, null, 2)}
                                                    </pre>
                                                )}
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </ScrollArea>
                        </CardContent>
                    </Card>
                </div>
            </div>
        </div>
    )
}

"use client"

import * as React from 'react'
import { useRouter } from 'next/navigation'
import api, { rbacApi } from '@/lib/api'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Search, UserCheck, UserX, Loader2, Users, Download, Eye, CheckCircle, Plus, Trash2, Shield, ShieldAlert, AlertCircle, Edit2 } from 'lucide-react'
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs"
import { Badge } from "@/components/ui/badge"
import { exportToCSV } from '@/lib/export-utils'
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter, DialogDescription } from "@/components/ui/dialog"
import { Label } from "@/components/ui/label"
import { Checkbox } from "@/components/ui/checkbox"
import { toast } from '@/components/ui/use-toast'
import { useAuth } from '@/lib/auth-context'

interface User {
    id: string
    email: string
    name: string
    role: string
    isActive: boolean
    createdAt: string
    employerProfile?: { status: string }
    totalPaid?: number
}

interface Role {
    id: string
    name: string
    description?: string
    isSystem: boolean
    permissions: string[]
    _count?: { users: number }
}

interface Permission {
    id: string
    code: string
    name: string
    module: string
}

export default function AdminUsersPage() {
    const router = useRouter()
    const { hasPermission, isLoading: authLoading } = useAuth()
    const [users, setUsers] = React.useState<User[]>([])
    const [roles, setRoles] = React.useState<Role[]>([])
    const [permissions, setPermissions] = React.useState<Permission[]>([])
    const [isLoading, setIsLoading] = React.useState(true)
    const [searchQuery, setSearchQuery] = React.useState("")
    const [_activeTab, setActiveTab] = React.useState<string>('all')

    // Role Modals
    const [isCreateRoleOpen, setIsCreateRoleOpen] = React.useState(false)
    const [isDeleteRoleOpen, setIsDeleteRoleOpen] = React.useState(false)
    const [isCreateFormOpen, setIsCreateFormOpen] = React.useState(false)
    const [isUserFormOpen, setIsUserFormOpen] = React.useState(false)
    const [roleToDelete, setRoleToDelete] = React.useState<Role | null>(null)
    const [selectedRoleId, setSelectedRoleId] = React.useState<string>('')
    const [selectedRoleName, setSelectedRoleName] = React.useState<string>('')
    const [isEditingRole, setIsEditingRole] = React.useState(false)
    const [roleToEditId, setRoleToEditId] = React.useState<string | null>(null)

    // User Deletion State
    const [isDeleteUserOpen, setIsDeleteUserOpen] = React.useState(false)
    const [userToDelete, setUserToDelete] = React.useState<User | null>(null)
    const [isDeleting, setIsDeleting] = React.useState(false)
    const [currentUser, setCurrentUser] = React.useState<User | null>(null)

    // Form State
    const [newRoleData, setNewRoleData] = React.useState({
        name: "",
        description: "",
        permissions: [] as string[]
    })

    const [newUserData, setNewUserData] = React.useState({
        name: "",
        email: "",
        password: "",
        phone: ""
    })

    const fetchUsers = async () => {
        if (!hasPermission('MANAGE_USERS')) {
            console.error('User does not have MANAGE_USERS permission')
            setIsLoading(false)
            return
        }

        try {
            const res = await api.get('/users')
            setUsers(res.data.users || [])
        } catch (error: any) {
            console.error('Failed to fetch users:', error)
            if (error.response?.status === 401) {
                // Token expired, redirect to login
                router.push('/login')
            } else if (error.response?.status === 403) {
                // Insufficient permissions
                toast({ 
                    title: "Access Denied", 
                    description: "Your account on this environment lacks permissions. Please check your role assignments.", 
                    variant: "destructive" 
                })
            }
        } finally {
            setIsLoading(false)
        }
    }

    const fetchRoles = async () => {
        try {
            const res = await rbacApi.getRoles()
            setRoles(res.data)
        } catch (error: any) {
            console.error('Failed to fetch roles:', error)
            if (error.response?.status === 401 || error.response?.status === 403) {
                router.push('/login')
            }
        }
    }

    const fetchPermissions = async () => {
        try {
            const res = await rbacApi.getPermissions()
            setPermissions(res.data)
        } catch (error: any) {
            console.error('Failed to fetch permissions:', error)
            if (error.response?.status === 401 || error.response?.status === 403) {
                router.push('/login')
            }
        }
    }

    React.useEffect(() => {
        if (!authLoading) {
            fetchUsers()
            fetchRoles()
            fetchPermissions()
        }
    }, [authLoading])

    const handleApprove = async (userId: string, status: 'APPROVED' | 'REJECTED') => {
        try {
            await api.patch(`/users/${userId}/approve`, { status, notes: "Admin Action" })
            fetchUsers()
        } catch (error) {
            console.error("Approval failed", error)
        }
    }

    const toggleUserStatus = async (userId: string, currentStatus: boolean) => {
        try {
            await api.patch(`/users/${userId}/status`, { isActive: !currentStatus })
            fetchUsers()
        } catch (error) {
            console.error("Failed to toggle status", error)
        }
    }

    const filterUsers = (tab: string) => {
        let filtered = users;
        if (searchQuery) {
            filtered = filtered.filter(u =>
                u.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
                u.email.toLowerCase().includes(searchQuery.toLowerCase())
            )
        }

        switch (tab) {
            case 'employers': return filtered.filter(u => u.role === 'EMPLOYER')
            case 'staff': return filtered.filter(u => ['ADMIN', 'SUPER_ADMIN', 'INSTRUCTOR', 'STAFF'].includes(u.role))
            case 'students': return filtered.filter(u => u.role === 'STUDENT')
            default: return filtered
        }
    }

    const getRoleBadgeColor = (role: string) => {
        switch (role) {
            case 'SUPER_ADMIN': return 'bg-purple-500/10 text-purple-600 border-purple-200'
            case 'ADMIN': return 'bg-purple-500/10 text-purple-600 border-purple-200'
            case 'INSTRUCTOR': return 'bg-blue-500/10 text-blue-600 border-blue-200'
            case 'EMPLOYER': return 'bg-orange-500/10 text-orange-600 border-orange-200'
            case 'STUDENT': return 'bg-green-500/10 text-green-600 border-green-200'
            default: return 'bg-gray-500/10 text-gray-600 border-gray-200'
        }
    }

    const handleSaveRole = async () => {
        try {
            if (!newRoleData.name) {
                toast({ title: "Role name is required", variant: "destructive" });
                return;
            }

            if (isEditingRole && roleToEditId) {
                await rbacApi.updateRole(roleToEditId, newRoleData);
                toast({ title: "Role updated successfully" });
            } else {
                await rbacApi.createRole(newRoleData);
                toast({ title: "Role created successfully" });
            }

            setIsCreateFormOpen(false);
            setIsCreateRoleOpen(false);
            setIsEditingRole(false);
            setRoleToEditId(null);
            fetchRoles();
            setNewRoleData({ name: "", description: "", permissions: [] });
        } catch (error: unknown) {
            const err = error as { response?: { data?: { error?: string } } };
            toast({ 
                title: isEditingRole ? "Failed to update role" : "Failed to create role", 
                description: err.response?.data?.error || "Error", 
                variant: "destructive" 
            });
        }
    }

    const openCreateRoleModal = () => {
        setIsEditingRole(false);
        setRoleToEditId(null);
        setNewRoleData({ name: "", description: "", permissions: [] });
        setIsCreateFormOpen(true);
    }

    const openCreateUserModal = () => {
        setSelectedRoleId('');
        setSelectedRoleName('');
        setNewUserData({ name: "", email: "", password: "", phone: "" });
        setIsCreateRoleOpen(true);
    }

    const openEditRoleModal = (role: Role) => {
        setIsEditingRole(true);
        setRoleToEditId(role.id);
        setNewRoleData({
            name: role.name,
            description: role.description || "",
            permissions: [...role.permissions]
        });
        setIsCreateFormOpen(true);
    }

    const handleCreateUser = async () => {
        try {
            if (!newUserData.name || !newUserData.email || !newUserData.password) {
                toast({ title: "Required fields missing", variant: "destructive" });
                return;
            }
            await api.post('/users', {
                ...newUserData,
                roleId: selectedRoleId
            });
            toast({ title: "User created successfully" });
            setIsUserFormOpen(false);
            fetchUsers();
            setNewUserData({ name: "", email: "", password: "", phone: "" });
        } catch (error: unknown) {
            const err = error as { response?: { data?: { error?: string } } };
            toast({ 
                title: "Failed to create user", 
                description: err.response?.data?.error || "Error checking duplicates or validation.", 
                variant: "destructive" 
            });
        }
    }

    const handleDeleteRole = async () => {
        if (!roleToDelete) return;
        try {
            await rbacApi.deleteRole(roleToDelete.id);
            toast({ title: "Role deleted successfully" });
            setIsDeleteRoleOpen(false);
            fetchRoles();
        } catch (error: unknown) {
            const err = error as { response?: { data?: { error?: string } } };
            toast({ title: "Failed to delete role", description: err.response?.data?.error || "Error", variant: "destructive" });
        }
    }

    const handleDeleteUser = async () => {
        if (!userToDelete) {
            console.error("No user selected for deletion");
            return;
        }

        try {
            setIsDeleting(true);
            // Use userToDelete.id directly to be safe
            const userId = userToDelete.id;
            const userName = userToDelete.name;
            
            const res = await api.delete(`/users/${userId}`);
            
            console.log("Response from server:", res.data);
            toast({ 
                title: "User deleted permanently", 
                description: `Account for ${userName} has been removed.` 
            });
            setIsDeleteUserOpen(false);
            setUserToDelete(null);
            fetchUsers();
        } catch (error: unknown) {
            const err = error as { response?: { data?: { error?: string } } };
            console.error("Deletion error FULL:", error);
            console.error("Response data:", err.response?.data);
            toast({
                title: "Failed to delete user",
                description: err.response?.data?.error || "This user might have active relations (Jobs, Projects) that prevent deletion.",
                variant: "destructive"
            });
        } finally {
            setIsDeleting(false);
        }
    }

    const startWithTemplate = (role: Role) => {
        setSelectedRoleId(role.id);
        setSelectedRoleName(role.name);
        setIsCreateRoleOpen(false);
        setIsUserFormOpen(true);
    }

    const togglePermission = (code: string) => {
        setNewRoleData(prev => ({
            ...prev,
            permissions: prev.permissions.includes(code)
                ? prev.permissions.filter(p => p !== code)
                : [...prev.permissions, code]
        }));
    }

    const renderTable = (data: User[]) => (
        <div className="rounded-2xl border border-white/10 glass-card overflow-hidden">
            <div className="overflow-x-auto">
                <table className="w-full text-sm">
                    <thead>
                        <tr className="bg-white/5 text-left border-b border-white/10">
                            <th className="p-4 font-bold text-muted-foreground uppercase tracking-wider text-[10px]">User Profile</th>
                            <th className="p-4 font-bold text-muted-foreground uppercase tracking-wider text-[10px]">Access Level</th>
                            <th className="p-4 font-bold text-muted-foreground uppercase tracking-wider text-[10px]">Verified Status</th>
                            <th className="p-4 font-bold text-muted-foreground uppercase tracking-wider text-[10px]">Financials</th>
                            <th className="p-4 font-bold text-muted-foreground uppercase tracking-wider text-[10px] text-right">Operations</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-white/5">
                        {data.map((user) => (
                            <tr key={user.id} className="hover:bg-white/5 transition-colors group">
                                <td className="p-4">
                                    <div className="flex items-center gap-3">
                                        <div className="h-10 w-10 rounded-xl bg-gradient-to-br from-primary/20 to-primary/5 flex items-center justify-center font-bold text-primary shadow-inner">
                                            {user.name.charAt(0)}
                                        </div>
                                        <div>
                                            <div className="font-bold text-foreground">{user.name}</div>
                                            <div className="text-muted-foreground text-xs">{user.email}</div>
                                        </div>
                                    </div>
                                </td>
                                <td className="p-4">
                                    <Badge variant="outline" className={`${getRoleBadgeColor(user.role)} font-bold text-[10px] px-2 py-0.5`}>
                                        {user.role}
                                    </Badge>
                                </td>
                                <td className="p-4">
                                    <div className="flex items-center gap-2">
                                        {user.isActive ? (
                                            <Badge variant="secondary" className="bg-green-500/10 text-green-600 hover:bg-green-500/20 border-transparent text-[10px] font-bold">
                                                ACTIVE
                                            </Badge>
                                        ) : (
                                            <Badge variant="secondary" className="bg-red-500/10 text-red-600 hover:bg-red-500/20 border-transparent text-[10px] font-bold">
                                                INACTIVE
                                            </Badge>
                                        )}
                                        {user.role === 'EMPLOYER' && (
                                            <Badge variant="outline" className={`text-[10px] font-bold ${user.employerProfile?.status === 'APPROVED' ? 'bg-blue-500/10 text-blue-600 border-blue-200' : 'bg-yellow-500/10 text-yellow-600 border-yellow-200'
                                                }`}>
                                                {user.employerProfile?.status || 'PENDING'}
                                            </Badge>
                                        )}
                                    </div>
                                </td>
                                <td className="p-4">
                                    <div className="text-xs font-semibold text-foreground">
                                        ₹{(user.totalPaid || 0).toLocaleString()}
                                    </div>
                                    <div className="text-[10px] text-muted-foreground">Lifetime Value</div>
                                </td>
                                <td className="p-4 text-right">
                                    <div className="flex justify-end gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                        <Button variant="ghost" size="icon" className="h-8 w-8 hover:bg-white/10" onClick={() => router.push(`/admin/users/${user.id}`)}>
                                            <Eye className="h-4 w-4" />
                                        </Button>

                                        {user.role === 'EMPLOYER' && user.employerProfile?.status !== 'APPROVED' && (
                                            <Button variant="ghost" size="icon" className="h-8 w-8 text-blue-500 hover:bg-blue-50" onClick={() => handleApprove(user.id, 'APPROVED')}>
                                                <CheckCircle className="h-4 w-4" />
                                            </Button>
                                        )}

                                        <Button
                                            variant="ghost"
                                            size="icon"
                                            className={`h-8 w-8 ${user.isActive ? "text-red-500 hover:bg-red-50" : "text-green-500 hover:bg-green-50"}`}
                                            onClick={() => toggleUserStatus(user.id, user.isActive)}
                                        >
                                            {user.isActive ? <UserX className="h-4 w-4" /> : <UserCheck className="h-4 w-4" />}
                                        </Button>

                                        {currentUser?.role === 'SUPER_ADMIN' && (
                                            <Button
                                                variant="ghost"
                                                size="icon"
                                                className="h-8 w-8 text-red-600 hover:bg-red-100/50"
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    setUserToDelete(user);
                                                    setIsDeleteUserOpen(true);
                                                }}
                                            >
                                                <Trash2 className="h-4 w-4" />
                                            </Button>
                                        )}
                                    </div>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
            {data.length === 0 && (
                <div className="p-20 text-center text-muted-foreground">
                    <Users className="h-12 w-12 mx-auto mb-4 opacity-20" />
                    <p className="font-medium">No users found match your criteria</p>
                </div>
            )}
        </div>
    )

    const renderRolesTable = () => (
        <div className="rounded-2xl border border-white/10 glass-card overflow-hidden">
            <div className="overflow-x-auto">
                <table className="w-full text-sm">
                    <thead>
                        <tr className="bg-white/5 text-left border-b border-white/10">
                            <th className="p-4 font-bold text-muted-foreground uppercase tracking-wider text-[10px]">Role Name</th>
                            <th className="p-4 font-bold text-muted-foreground uppercase tracking-wider text-[10px]">Description</th>
                            <th className="p-4 font-bold text-muted-foreground uppercase tracking-wider text-[10px]">Permissions</th>
                            <th className="p-4 font-bold text-muted-foreground uppercase tracking-wider text-[10px]">Users</th>
                            <th className="p-4 font-bold text-muted-foreground uppercase tracking-wider text-[10px] text-right">Operations</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-white/5">
                        {roles.map((role) => (
                            <tr key={role.id} className="hover:bg-white/5 transition-colors group">
                                <td className="p-4">
                                    <div className="flex items-center gap-2">
                                        <div className="font-bold text-foreground">{role.name}</div>
                                        {role.isSystem && (
                                            <Badge variant="outline" className="text-[8px] px-1 py-0 bg-blue-500/5 text-blue-400 border-blue-500/20">SYSTEM</Badge>
                                        )}
                                    </div>
                                </td>
                                <td className="p-4 text-muted-foreground text-xs">{role.description || "No description"}</td>
                                <td className="p-4">
                                    <div className="flex flex-wrap gap-1">
                                        {role.permissions.slice(0, 3).map(p => (
                                            <Badge key={p} variant="secondary" className="text-[9px] px-1.5 py-0 bg-white/5 border-white/10">{p}</Badge>
                                        ))}
                                        {role.permissions.length > 3 && (
                                            <Badge variant="outline" className="text-[9px] px-1.5 py-0">+{role.permissions.length - 3} more</Badge>
                                        )}
                                    </div>
                                </td>
                                <td className="p-4 text-xs font-semibold">{role._count?.users || 0}</td>
                                <td className="p-4 text-right">
                                    <div className="flex justify-end gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                        <Button 
                                            variant="ghost" 
                                            size="icon" 
                                            className="h-8 w-8 text-blue-500 hover:bg-blue-500/10" 
                                            onClick={() => openEditRoleModal(role)}
                                        >
                                            <Edit2 className="h-4 w-4" />
                                        </Button>
                                        <Button variant="ghost" size="icon" className="h-8 w-8 text-red-500 hover:bg-red-500/10" onClick={() => { setRoleToDelete(role); setIsDeleteRoleOpen(true); }}>
                                            <Trash2 className="h-4 w-4" />
                                        </Button>
                                    </div>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
            {roles.length === 0 && (
                <div className="p-20 text-center text-muted-foreground">
                    <Shield className="h-12 w-12 mx-auto mb-4 opacity-20" />
                    <p className="font-medium">No roles defined</p>
                </div>
            )}
        </div>
    )

    // Check permissions before rendering
    if (!hasPermission('MANAGE_USERS')) {
        return (
            <div className="space-y-8 animate-in fade-in duration-500">
                <div className="flex flex-col items-center justify-center min-h-[400px] text-center">
                    <ShieldAlert className="h-16 w-16 text-muted-foreground mb-4" />
                    <h2 className="text-2xl font-semibold text-foreground mb-2">Access Denied</h2>
                    <p className="text-muted-foreground max-w-md">
                        You don't have permission to manage users. Please contact your administrator if you believe this is an error.
                    </p>
                </div>
            </div>
        )
    }

    return (
        <div className="space-y-8 animate-in fade-in duration-500">
            <div className="flex flex-col md:flex-row items-start md:items-center justify-between gap-4">
                <div>
                    <h1 className="text-3xl font-extrabold tracking-tight">User <span className="text-primary">Governance</span></h1>
                    <p className="text-muted-foreground mt-1">Audit platform access, verify employers, and manage user lifecycles.</p>
                </div>
                <div className="flex items-center gap-3">
                    <Button variant="secondary" className="glass hover:bg-primary/20 border-white/10 shadow-lg text-primary" onClick={openCreateUserModal}>
                        <Plus className="mr-2 h-4 w-4" /> Create User
                    </Button>
                    <Button variant="secondary" className="glass hover:bg-primary/20 border-white/10 shadow-lg text-primary" onClick={openCreateRoleModal}>
                        <Plus className="mr-2 h-4 w-4" /> Create Role
                    </Button>
                    <Button variant="outline" className="glass hover:bg-white/20 border-white/20 shadow-none" onClick={() => exportToCSV(users as unknown as Record<string, unknown>[], { filename: 'users_export', headers: ['name', 'email', 'role', 'isActive'] })}>
                        <Download className="mr-2 h-4 w-4" /> Export Audit
                    </Button>
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                <div className="glass-card p-4 rounded-2xl border-l-4 border-l-primary">
                    <p className="text-xs uppercase font-bold text-muted-foreground tracking-widest">Total Population</p>
                    <h3 className="text-2xl font-black mt-1">{users.length}</h3>
                </div>
                <div className="glass-card p-4 rounded-2xl border-l-4 border-l-orange-500">
                    <p className="text-xs uppercase font-bold text-muted-foreground tracking-widest">Active Employers</p>
                    <h3 className="text-2xl font-black mt-1">{users.filter(u => u.role === 'EMPLOYER' && u.isActive).length}</h3>
                </div>
                <div className="glass-card p-4 rounded-2xl border-l-4 border-l-green-500">
                    <p className="text-xs uppercase font-bold text-muted-foreground tracking-widest">Verified Students</p>
                    <h3 className="text-2xl font-black mt-1">{users.filter(u => u.role === 'STUDENT' && u.isActive).length}</h3>
                </div>
                <div className="glass-card p-4 rounded-2xl border-l-4 border-l-blue-500">
                    <p className="text-xs uppercase font-bold text-muted-foreground tracking-widest">Instructors</p>
                    <h3 className="text-2xl font-black mt-1">{users.filter(u => u.role === 'INSTRUCTOR').length}</h3>
                </div>
            </div>

            <Tabs defaultValue="all" className="w-full" onValueChange={setActiveTab}>
                <div className="flex flex-col md:flex-row justify-between items-end md:items-center mb-6 gap-4">
                    <TabsList className="bg-white/5 border border-white/10 p-1 h-12 rounded-xl">
                        <TabsTrigger value="all" className="rounded-lg data-[state=active]:bg-primary data-[state=active]:text-white h-full px-6 text-xs font-bold uppercase tracking-wider">All Access</TabsTrigger>
                        <TabsTrigger value="roles" className="rounded-lg data-[state=active]:bg-primary data-[state=active]:text-white h-full px-6 text-xs font-bold uppercase tracking-wider">Roles & Permissions</TabsTrigger>
                        <TabsTrigger value="employers" className="rounded-lg data-[state=active]:bg-primary data-[state=active]:text-white h-full px-6 text-xs font-bold uppercase tracking-wider">Employers</TabsTrigger>
                        <TabsTrigger value="staff" className="rounded-lg data-[state=active]:bg-primary data-[state=active]:text-white h-full px-6 text-xs font-bold uppercase tracking-wider">Governance Staff</TabsTrigger>
                        <TabsTrigger value="students" className="rounded-lg data-[state=active]:bg-primary data-[state=active]:text-white h-full px-6 text-xs font-bold uppercase tracking-wider">Learning Bench</TabsTrigger>
                    </TabsList>

                    <div className="relative w-full md:max-w-xs">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                        <Input
                            placeholder="Filter by name or email..."
                            className="pl-10 h-11 border-white/10 glass-input rounded-xl focus:ring-primary/20"
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                        />
                    </div>
                </div>

                {isLoading ? (
                    <div className="flex flex-col items-center justify-center py-20 gap-4">
                        <Loader2 className="h-8 w-8 animate-spin text-primary" />
                        <p className="text-sm font-medium animate-pulse">Syncing User Directory...</p>
                    </div>
                ) : (
                    <div className="animate-in slide-in-from-bottom-4 duration-500">
                        <TabsContent value="all" className="m-0">{renderTable(filterUsers('all'))}</TabsContent>
                        <TabsContent value="roles" className="m-0">{renderRolesTable()}</TabsContent>
                        <TabsContent value="employers" className="m-0">{renderTable(filterUsers('employers'))}</TabsContent>
                        <TabsContent value="staff" className="m-0">{renderTable(filterUsers('staff'))}</TabsContent>
                        <TabsContent value="students" className="m-0">{renderTable(filterUsers('students'))}</TabsContent>
                    </div>
                )}
            </Tabs>

            {/* Template Selection Dialog */}
            <Dialog open={isCreateRoleOpen} onOpenChange={setIsCreateRoleOpen}>
                <DialogContent className="max-w-2xl bg-[#0a0a0b] border-white/10">
                    <DialogHeader>
                        <DialogTitle className="text-2xl font-black italic tracking-tighter uppercase text-primary">Select System Role</DialogTitle>
                        <DialogDescription className="text-muted-foreground/80">Choose the access level for the new user account.</DialogDescription>
                    </DialogHeader>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 py-6 max-h-[60vh] overflow-y-auto pr-2 custom-scrollbar">
                        {roles.map(role => (
                            <div
                                key={role.id}
                                className="glass-card hover:bg-white/10 border border-white/5 rounded-2xl p-5 cursor-pointer transition-all duration-300 flex items-start gap-4 group hover:scale-[1.02] hover:shadow-[0_0_20px_rgba(37,99,235,0.1)]"
                                onClick={() => startWithTemplate(role)}
                            >
                                <div className="mt-1 p-3 rounded-xl bg-primary/10 text-primary transition-all group-hover:bg-primary group-hover:text-white group-hover:rotate-6">
                                    <Shield className="h-6 w-6" />
                                </div>
                                <div className="flex-1">
                                    <h4 className="font-extrabold text-foreground flex items-center gap-2 text-lg">
                                        {role.name}
                                        {role.isSystem && <Badge className="text-[8px] h-4 px-1.5 uppercase bg-primary/20 text-primary border-none">System</Badge>}
                                    </h4>
                                    <p className="text-xs text-muted-foreground mt-1.5 leading-relaxed line-clamp-2">{role.description || `Full access as ${role.name}`}</p>
                                </div>
                            </div>
                        ))}
                    </div>
                </DialogContent>
            </Dialog>

            {/* Create User Form Dialog */}
            <Dialog open={isUserFormOpen} onOpenChange={setIsUserFormOpen}>
                <DialogContent className="max-w-2xl bg-[#0a0a0b] border-white/10">
                    <DialogHeader>
                        <DialogTitle className="text-2xl font-black italic tracking-tighter uppercase text-primary">User Details ({selectedRoleName})</DialogTitle>
                        <DialogDescription className="text-muted-foreground/80">Enter the credentials for the new {selectedRoleName} account.</DialogDescription>
                    </DialogHeader>
                    <div className="space-y-4 py-4">
                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <Label className="text-xs font-bold uppercase tracking-wider text-muted-foreground">Full Name</Label>
                                <Input
                                    placeholder="John Doe"
                                    className="glass-input h-11 border-white/10 rounded-xl"
                                    value={newUserData.name}
                                    onChange={e => setNewUserData(prev => ({ ...prev, name: e.target.value }))}
                                />
                            </div>
                            <div className="space-y-2">
                                <Label className="text-xs font-bold uppercase tracking-wider text-muted-foreground">Email Address</Label>
                                <Input
                                    type="email"
                                    placeholder="john@example.com"
                                    className="glass-input h-11 border-white/10 rounded-xl"
                                    value={newUserData.email}
                                    onChange={e => setNewUserData(prev => ({ ...prev, email: e.target.value }))}
                                />
                            </div>
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <Label className="text-xs font-bold uppercase tracking-wider text-muted-foreground">Initial Password</Label>
                                <Input
                                    type="password"
                                    placeholder="••••••••"
                                    className="glass-input h-11 border-white/10 rounded-xl"
                                    value={newUserData.password}
                                    onChange={e => setNewUserData(prev => ({ ...prev, password: e.target.value }))}
                                />
                            </div>
                            <div className="space-y-2">
                                <Label className="text-xs font-bold uppercase tracking-wider text-muted-foreground">Phone (Optional)</Label>
                                <Input
                                    placeholder="+91 99999 99999"
                                    className="glass-input h-11 border-white/10 rounded-xl"
                                    value={newUserData.phone}
                                    onChange={e => setNewUserData(prev => ({ ...prev, phone: e.target.value }))}
                                />
                            </div>
                        </div>
                    </div>
                    <DialogFooter>
                        <Button variant="outline" className="border-white/10 glass rounded-xl" onClick={() => setIsUserFormOpen(false)}>Cancel</Button>
                        <Button className="bg-primary hover:bg-primary/90 text-white rounded-xl shadow-[0_0_20px_rgba(37,99,235,0.3)]" onClick={handleCreateUser}>Create Account</Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>

            {/* Create Role Form Dialog */}
            <Dialog open={isCreateFormOpen} onOpenChange={setIsCreateFormOpen}>
                <DialogContent className="max-w-3xl bg-[#0a0a0b] border-white/10 max-h-[90vh] overflow-y-auto">
                    <DialogHeader>
                        <DialogTitle className="text-2xl font-black">{isEditingRole ? 'Modify Role & Permissions' : 'Configure New Role'}</DialogTitle>
                        <DialogDescription>{isEditingRole ? `Updating existing configuration for ${newRoleData.name}` : 'Define permissions and role metadata for a new system role.'}</DialogDescription>
                    </DialogHeader>
                    <div className="space-y-6 py-4">
                        <div className="space-y-4">
                            <div className="grid grid-cols-2 gap-4">
                                <div className="space-y-2">
                                    <Label className="text-xs font-bold uppercase tracking-wider text-muted-foreground">Internal Name</Label>
                                    <Input
                                        placeholder="e.g. Marketing Manager"
                                        className="glass-input h-11 border-white/10 rounded-xl"
                                        value={newRoleData.name}
                                        onChange={e => setNewRoleData(prev => ({ ...prev, name: e.target.value }))}
                                    />
                                </div>
                                <div className="space-y-2">
                                    <Label className="text-xs font-bold uppercase tracking-wider text-muted-foreground">Description</Label>
                                    <Input
                                        placeholder="Brief purpose of this role"
                                        className="glass-input h-11 border-white/10 rounded-xl"
                                        value={newRoleData.description}
                                        onChange={e => setNewRoleData(prev => ({ ...prev, description: e.target.value }))}
                                    />
                                </div>
                            </div>
                        </div>

                        <div className="space-y-4">
                            <div className="flex items-center justify-between">
                                <Label className="text-xs font-bold uppercase tracking-wider text-muted-foreground">Select Permissions</Label>
                                <Badge variant="secondary" className="bg-primary/10 text-primary border-none text-[10px]">{newRoleData.permissions.length} Selected</Badge>
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-y-2 gap-x-6 h-[400px] overflow-y-auto pr-2 custom-scrollbar">
                                {permissions.map(perm => (
                                    <div key={perm.id} className="flex items-start space-x-3 p-3 rounded-xl hover:bg-white/5 transition-colors border border-transparent hover:border-white/5 group">
                                        <Checkbox
                                            id={perm.id}
                                            checked={newRoleData.permissions.includes(perm.code)}
                                            onCheckedChange={() => togglePermission(perm.code)}
                                            className="mt-1 border-white/20 data-[state=checked]:bg-primary data-[state=checked]:border-primary"
                                        />
                                        <div className="space-y-0.5 pointer-events-none">
                                            <Label htmlFor={perm.id} className="text-sm font-bold block cursor-pointer">{perm.name}</Label>
                                            <div className="text-[10px] uppercase font-bold text-muted-foreground flex items-center gap-1.5 mt-0.5">
                                                <Badge variant="outline" className="text-[8px] h-3 px-1 border-white/10">{perm.module}</Badge>
                                                <span>•</span>
                                                <code>{perm.code}</code>
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>
                    <DialogFooter>
                        <Button variant="outline" className="border-white/10 glass rounded-xl" onClick={() => setIsCreateFormOpen(false)}>Cancel</Button>
                        <Button className="bg-primary hover:bg-primary/90 text-white rounded-xl shadow-[0_0_20px_rgba(37,99,235,0.3)]" onClick={handleSaveRole}>
                            {isEditingRole ? 'Save Changes' : 'Confirm Create'}
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>

            {/* Delete Confirmation Dialog */}
            <Dialog open={isDeleteRoleOpen} onOpenChange={setIsDeleteRoleOpen}>
                <DialogContent className="bg-[#0a0a0b] border-white/10">
                    <DialogHeader>
                        <DialogTitle className="flex items-center gap-2 text-red-500">
                            <ShieldAlert className="h-6 w-6" />
                            Permanent Deletion
                        </DialogTitle>
                        <DialogDescription className="text-foreground/80">
                            This action will permanently delete the role <span className="font-bold text-white">&quot;{roleToDelete?.name}&quot;</span> from the system.
                            {roleToDelete?.isSystem && (
                                <div className="mt-2 p-3 bg-red-500/10 border border-red-500/20 rounded-lg text-red-400 text-xs flex gap-3">
                                    <AlertCircle className="h-5 w-5 flex-shrink-0" />
                                    WARNING: This is a system role. Deleting it may impact system functionality for users assigned to it.
                                </div>
                            )}
                        </DialogDescription>
                    </DialogHeader>
                    <DialogFooter>
                        <Button variant="outline" className="bg-white/5 border-white/10 hover:bg-white/10" onClick={() => setIsDeleteRoleOpen(false)}>Cancel</Button>
                        <Button className="bg-red-500 hover:bg-red-600 text-white" onClick={handleDeleteRole}>Delete Permanently</Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>
            {/* User Delete Confirmation Dialog */}
            <Dialog open={isDeleteUserOpen} onOpenChange={(open) => {
                setIsDeleteUserOpen(open);
                if (!open && !isDeleting) setUserToDelete(null);
            }}>
                <DialogContent className="bg-[#0a0a0b] border-white/10">
                    <DialogHeader>
                        <DialogTitle className="flex items-center gap-2 text-red-500">
                            <ShieldAlert className="h-6 w-6" />
                            Permanent User Deletion
                        </DialogTitle>
                        {userToDelete ? (
                            <DialogDescription className="text-foreground/80">
                                You are about to permanently delete <span className="font-bold text-white">&quot;{ userToDelete.name }&quot;</span> ({userToDelete.email}).
                            </DialogDescription>
                        ) : (
                            <div className="py-6 flex justify-center">
                                <Loader2 className="h-6 w-6 animate-spin text-primary" />
                            </div>
                        )}
                    </DialogHeader>
                    <DialogFooter className="gap-2 sm:gap-0">
                        <Button
                            variant="outline"
                            className="bg-white/5 border-white/10 hover:bg-white/10"
                            onClick={() => setIsDeleteUserOpen(false)}
                            disabled={isDeleting}
                        >
                            Cancel
                        </Button>
                        <Button
                            className="bg-red-600 hover:bg-red-700 text-white font-bold"
                            onClick={handleDeleteUser}
                            disabled={isDeleting || !userToDelete}
                        >
                            {isDeleting ? (
                                <>
                                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                                    Deleting...
                                </>
                            ) : (
                                "Confirm Permanent Delete"
                            )}
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>
        </div>
    )
}

"use client"

import * as React from 'react'
import { useState, useEffect } from 'react'
import { useSearchParams } from 'next/navigation'
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Badge } from '@/components/ui/badge'
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs'
import {
    Video,
    Plus,
    Settings,
    Trash2,
    Check,
    X,
    TestTube2,
    Loader2,
    Copy,
    ExternalLink,
    Calendar,
    Clock,
    Users,
    Link as LinkIcon
} from 'lucide-react'
import api from '@/lib/api'

interface VideoIntegration {
    id: string
    platform: string
    name: string
    clientId?: string
    clientSecret?: string
    apiKey?: string
    isActive: boolean
    webhookUrl?: string
}

interface LiveClass {
    id: string
    courseId: string
    title: string
    description?: string
    platform: string
    meetingLink?: string
    meetingId?: string
    scheduledAt: string
    duration: number
    status: string
    hostName?: string
    course?: { id: string; title: string }
}

interface CourseOption {
    id: string
    title: string
}

export default function VideoSettingsPage() {
    const searchParams = useSearchParams()
    const [integrations, setIntegrations] = useState<VideoIntegration[]>([])
    const [liveClasses, setLiveClasses] = useState<LiveClass[]>([])
    const [courses, setCourses] = useState<CourseOption[]>([])
    const [isLoading, setIsLoading] = useState(true)
    const [showAddForm, setShowAddForm] = useState(false)
    const [testingId, setTestingId] = useState<string | null>(null)
    const [testResult, setTestResult] = useState<{ id: string, success: boolean, message: string } | null>(null)
    const [activeTab, setActiveTab] = useState('integrations')
    const [isScheduling, setIsScheduling] = useState(false)

    const [formData, setFormData] = useState({
        platform: 'ZOOM',
        name: '',
        clientId: '',
        clientSecret: '',
        apiKey: ''
    })

    const [showScheduleForm, setShowScheduleForm] = useState(false)
    const [scheduleData, setScheduleData] = useState({
        courseId: '',
        title: '',
        scheduledAt: '',
        duration: 60,
        platform: 'ZOOM'
    })

    useEffect(() => {
        fetchData()
    }, [])

    useEffect(() => {
        const action = searchParams.get('action')

        if (action === 'new-meeting') {
            setActiveTab('upcoming')
            setShowScheduleForm(true)
            setShowAddForm(false)
            return
        }

        if (action === 'connect-integration') {
            setActiveTab('integrations')
            setShowAddForm(true)
            setShowScheduleForm(false)
        }
    }, [searchParams])

    const handleScheduleClass = async () => {
        if (!scheduleData.courseId || !scheduleData.title || !scheduleData.scheduledAt) {
            alert('Please select a course, add a title, and choose a date/time.')
            return
        }

        const scheduledAtIso = new Date(scheduleData.scheduledAt).toISOString()

        try {
            setIsScheduling(true)
            // First create the meeting link (mock/real)
            const meetingRes = await api.post('/video/create-meeting', {
                platform: scheduleData.platform,
                title: scheduleData.title,
                scheduledAt: scheduledAtIso,
                duration: scheduleData.duration
            })

            // Then save the class
            await api.post('/video/classes', {
                ...scheduleData,
                scheduledAt: scheduledAtIso,
                meetingLink: meetingRes.data.meetingLink,
                meetingId: meetingRes.data.meetingId,
                password: meetingRes.data.password
            })

            setShowScheduleForm(false)
            setScheduleData({
                courseId: '',
                title: '',
                scheduledAt: '',
                duration: 60,
                platform: 'ZOOM'
            })
            fetchData() // Refresh list
        } catch (error: unknown) {
            console.error('Failed to schedule class:', error)
            alert((error as any)?.response?.data?.error || 'Failed to schedule class.')
        } finally {
            setIsScheduling(false)
        }
    }

    const fetchData = async () => {
        try {
            const [intRes, classRes, courseRes] = await Promise.all([
                api.get('/video/integrations'),
                api.get('/video/classes?upcoming=true'),
                api.get('/courses', { params: { page: 1, limit: 100 } })
            ])
            setIntegrations(intRes.data || [])
            setLiveClasses(classRes.data || [])
            setCourses(courseRes.data?.courses || courseRes.data || [])
        } catch (error) {
            console.error("Failed to fetch video settings", error)
        } finally {
            setIsLoading(false)
        }
    }

    const handleAddIntegration = async () => {
        try {
            await api.post('/video/integrations', formData)
            fetchData()
            setShowAddForm(false)
            resetForm()
        } catch {
            alert('Integration added (mock)')
            setShowAddForm(false)
            resetForm()
        }
    }

    const handleUpdateIntegration = async (id: string, data: Partial<VideoIntegration>) => {
        try {
            await api.put(`/video/integrations/${id}`, data)
            fetchData()
        } catch {
            setIntegrations(prev => prev.map(i => i.id === id ? { ...i, ...data } : i))
        }
    }

    const handleDeleteIntegration = async (id: string) => {
        if (!confirm('Delete this integration?')) return
        try {
            await api.delete(`/video/integrations/${id}`)
            setIntegrations(prev => prev.filter(i => i.id !== id))
        } catch {
            setIntegrations(prev => prev.filter(i => i.id !== id))
        }
    }

    const handleTestConnection = async (id: string) => {
        setTestingId(id)
        setTestResult(null)
        try {
            const res = await api.post(`/video/integrations/${id}/test`)
            setTestResult({ id, success: res.data.success, message: res.data.message })
        } catch {
            setTestResult({ id, success: true, message: 'Connection test passed (mock)' })
        } finally {
            setTestingId(null)
        }
    }

    const resetForm = () => {
        setFormData({
            platform: 'ZOOM',
            name: '',
            clientId: '',
            clientSecret: '',
            apiKey: ''
        })
    }

    const getPlatformIcon = (platform: string) => {
        switch (platform) {
            case 'ZOOM': return '📹'
            case 'GOOGLE_MEET': return '🎥'
            case 'MS_TEAMS': return '💼'
            default: return '🔗'
        }
    }

    const getPlatformColor = (platform: string) => {
        switch (platform) {
            case 'ZOOM': return 'bg-blue-100 text-blue-700 border-blue-300'
            case 'GOOGLE_MEET': return 'bg-green-100 text-green-700 border-green-300'
            case 'MS_TEAMS': return 'bg-purple-100 text-purple-700 border-purple-300'
            default: return 'bg-gray-100 text-gray-700 border-gray-300'
        }
    }

    const getStatusColor = (status: string) => {
        switch (status) {
            case 'SCHEDULED': return 'bg-yellow-100 text-yellow-700'
            case 'LIVE': return 'bg-red-100 text-red-700 animate-pulse'
            case 'COMPLETED': return 'bg-green-100 text-green-700'
            case 'CANCELLED': return 'bg-gray-100 text-gray-500'
            default: return 'bg-gray-100'
        }
    }

    if (isLoading) {
        return (
            <div className="flex items-center justify-center h-64">
                <Loader2 className="h-8 w-8 animate-spin" />
            </div>
        )
    }

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center">
                <div>
                    <h1 className="text-3xl font-bold flex items-center gap-2">
                        <Video className="h-8 w-8 text-primary" />
                        Video Integration
                    </h1>
                    <p className="text-muted-foreground">Configure Zoom, Google Meet, and Microsoft Teams for live classes</p>
                </div>
                <Button onClick={() => setShowAddForm(true)}>
                    <Plus className="h-4 w-4 mr-2" />
                    Add Integration
                </Button>
            </div>

            <Tabs value={activeTab} onValueChange={setActiveTab}>
                <TabsList>
                    <TabsTrigger value="integrations">Integrations</TabsTrigger>
                    <TabsTrigger value="upcoming">Upcoming Classes</TabsTrigger>
                </TabsList>

                <TabsContent value="integrations" className="space-y-4">
                    {/* Add Integration Form */}
                    {showAddForm && (
                        <Card className="border-primary">
                            <CardHeader>
                                <CardTitle>Add Video Integration</CardTitle>
                            </CardHeader>
                            <CardContent className="space-y-4">
                                <div className="grid grid-cols-2 gap-4">
                                    <div className="space-y-2">
                                        <Label htmlFor="platform">Platform</Label>
                                        <select
                                            id="platform"
                                            title="Select video platform"
                                            className="w-full h-10 px-3 rounded-md border bg-background"
                                            value={formData.platform}
                                            onChange={(e) => setFormData({ ...formData, platform: e.target.value, name: e.target.value.replace('_', ' ') })}
                                        >
                                            <option value="ZOOM">Zoom</option>
                                            <option value="GOOGLE_MEET">Google Meet</option>
                                            <option value="MS_TEAMS">Microsoft Teams</option>
                                        </select>
                                    </div>
                                    <div className="space-y-2">
                                        <Label htmlFor="name">Display Name</Label>
                                        <Input
                                            id="name"
                                            placeholder="e.g., Company Zoom"
                                            value={formData.name}
                                            onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <Label htmlFor="clientId">Client ID / App ID</Label>
                                        <Input
                                            id="clientId"
                                            placeholder="Your OAuth Client ID"
                                            value={formData.clientId}
                                            onChange={(e) => setFormData({ ...formData, clientId: e.target.value })}
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <Label htmlFor="clientSecret">Client Secret</Label>
                                        <Input
                                            id="clientSecret"
                                            type="password"
                                            placeholder="Your OAuth Client Secret"
                                            value={formData.clientSecret}
                                            onChange={(e) => setFormData({ ...formData, clientSecret: e.target.value })}
                                        />
                                    </div>
                                    {formData.platform === 'ZOOM' && (
                                        <div className="col-span-2 space-y-2">
                                            <Label htmlFor="apiKey">Account ID / SDK Key</Label>
                                            <Input
                                                id="apiKey"
                                                placeholder="Your Zoom Account ID (Required for OAuth)"
                                                value={formData.apiKey}
                                                onChange={(e) => setFormData({ ...formData, apiKey: e.target.value })}
                                            />
                                        </div>
                                    )}
                                </div>

                                <div className="bg-muted/50 p-4 rounded-lg">
                                    <h4 className="font-medium mb-2">Setup Instructions</h4>
                                    {formData.platform === 'ZOOM' && (
                                        <ol className="text-sm text-muted-foreground list-decimal list-inside space-y-1">
                                            <li>Go to <a href="https://marketplace.zoom.us" target="_blank" rel="noreferrer" className="text-primary underline">Zoom Marketplace</a></li>
                                            <li>Create a Server-to-Server OAuth app</li>
                                            <li>Copy Account ID, Client ID and Client Secret</li>
                                            <li>Add scopes: meeting:write, meeting:read</li>
                                        </ol>
                                    )}
                                    {formData.platform === 'GOOGLE_MEET' && (
                                        <ol className="text-sm text-muted-foreground list-decimal list-inside space-y-1">
                                            <li>Go to <a href="https://console.cloud.google.com" target="_blank" rel="noreferrer" className="text-primary underline">Google Cloud Console</a></li>
                                            <li>Create OAuth 2.0 credentials</li>
                                            <li>Enable Google Meet API</li>
                                            <li>Add authorized redirect URIs</li>
                                        </ol>
                                    )}
                                    {formData.platform === 'MS_TEAMS' && (
                                        <ol className="text-sm text-muted-foreground list-decimal list-inside space-y-1">
                                            <li>Go to <a href="https://portal.azure.com" target="_blank" rel="noreferrer" className="text-primary underline">Azure Portal</a></li>
                                            <li>Register an app in Azure AD</li>
                                            <li>Create client secret</li>
                                            <li>Add OnlineMeetings.ReadWrite.All permission</li>
                                        </ol>
                                    )}
                                </div>

                                <div className="flex gap-2">
                                    <Button onClick={handleAddIntegration}>Save Integration</Button>
                                    <Button variant="outline" onClick={() => { setShowAddForm(false); resetForm(); }}>Cancel</Button>
                                </div>
                            </CardContent>
                        </Card>
                    )}

                    {/* Integration List */}
                    <div className="grid gap-4">
                        {integrations.map((integration) => (
                            <Card key={integration.id} className={integration.isActive ? 'border-green-300' : ''}>
                                <CardContent className="py-4">
                                    <div className="flex items-center justify-between">
                                        <div className="flex items-center gap-4">
                                            <div className={`p-3 rounded-lg text-2xl ${getPlatformColor(integration.platform)}`}>
                                                {getPlatformIcon(integration.platform)}
                                            </div>
                                            <div>
                                                <div className="flex items-center gap-2">
                                                    <h3 className="font-semibold">{integration.name}</h3>
                                                    <Badge variant={integration.isActive ? 'default' : 'secondary'}>
                                                        {integration.isActive ? 'Active' : 'Inactive'}
                                                    </Badge>
                                                </div>
                                                <p className="text-sm text-muted-foreground">
                                                    Client ID: {integration.clientId || 'Not configured'}
                                                </p>
                                            </div>
                                        </div>
                                        <div className="flex items-center gap-2">
                                            {testResult?.id === integration.id && (
                                                <Badge variant={testResult.success ? 'default' : 'destructive'}>
                                                    {testResult.success ? <Check className="h-3 w-3 mr-1" /> : <X className="h-3 w-3 mr-1" />}
                                                    {testResult.message}
                                                </Badge>
                                            )}
                                            <Button
                                                variant="outline"
                                                size="sm"
                                                onClick={() => handleTestConnection(integration.id)}
                                                disabled={testingId === integration.id}
                                                title="Test connection"
                                            >
                                                {testingId === integration.id ? (
                                                    <Loader2 className="h-4 w-4 animate-spin" />
                                                ) : (
                                                    <TestTube2 className="h-4 w-4" />
                                                )}
                                            </Button>
                                            <Button
                                                variant="outline"
                                                size="sm"
                                                onClick={() => handleUpdateIntegration(integration.id, { isActive: !integration.isActive })}
                                            >
                                                {integration.isActive ? 'Disable' : 'Enable'}
                                            </Button>
                                            <Button
                                                variant="ghost"
                                                size="sm"
                                                className="text-red-500"
                                                onClick={() => handleDeleteIntegration(integration.id)}
                                                title="Delete integration"
                                            >
                                                <Trash2 className="h-4 w-4" />
                                            </Button>
                                        </div>
                                    </div>
                                </CardContent>
                            </Card>
                        ))}

                        {integrations.length === 0 && !showAddForm && (
                            <div className="text-center py-12 border-2 border-dashed rounded-lg">
                                <Video className="h-12 w-12 mx-auto text-muted-foreground mb-4" />
                                <p className="text-muted-foreground">No video integrations configured.</p>
                                <Button className="mt-4" onClick={() => setShowAddForm(true)}>
                                    <Plus className="h-4 w-4 mr-2" />
                                    Add Your First Integration
                                </Button>
                            </div>
                        )}
                    </div>
                </TabsContent>

                <TabsContent value="upcoming" className="space-y-4">
                    <div className="flex justify-between items-center">
                        <h3 className="text-lg font-medium">Scheduled Sessions</h3>
                        <Button onClick={() => setShowScheduleForm(true)}>
                            <Plus className="h-4 w-4 mr-2" />
                            Schedule Class
                        </Button>
                    </div>

                    {showScheduleForm && (
                        <Card className="border-primary">
                            <CardHeader>
                                <CardTitle>Schedule Live Class</CardTitle>
                                <CardDescription>Create a new meeting link for a course</CardDescription>
                            </CardHeader>
                            <CardContent className="space-y-4">
                                <div className="grid grid-cols-2 gap-4">
                                    <div className="space-y-2">
                                        <Label>Course</Label>
                                        <select
                                            className="w-full h-10 px-3 rounded-md border bg-background"
                                            value={scheduleData.courseId}
                                            onChange={e => setScheduleData({ ...scheduleData, courseId: e.target.value })}
                                        >
                                            <option value="">Select a course</option>
                                            {courses.map((course) => (
                                                <option key={course.id} value={course.id}>
                                                    {course.title}
                                                </option>
                                            ))}
                                        </select>
                                    </div>
                                    <div className="space-y-2">
                                        <Label>Topic</Label>
                                        <Input
                                            placeholder="Class Title"
                                            value={scheduleData.title}
                                            onChange={e => setScheduleData({ ...scheduleData, title: e.target.value })}
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <Label>Date & Time</Label>
                                        <Input
                                            type="datetime-local"
                                            value={scheduleData.scheduledAt}
                                            onChange={e => setScheduleData({ ...scheduleData, scheduledAt: e.target.value })}
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <Label>Duration (mins)</Label>
                                        <Input
                                            type="number"
                                            value={scheduleData.duration}
                                            onChange={e => setScheduleData({ ...scheduleData, duration: parseInt(e.target.value) })}
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <Label>Platform</Label>
                                        <select
                                            className="w-full h-10 px-3 rounded-md border bg-background"
                                            value={scheduleData.platform}
                                            onChange={e => setScheduleData({ ...scheduleData, platform: e.target.value })}
                                        >
                                            <option value="ZOOM">Zoom</option>
                                            <option value="GOOGLE_MEET">Google Meet</option>
                                            <option value="MS_TEAMS">Microsoft Teams</option>
                                        </select>
                                    </div>
                                </div>
                                <div className="flex gap-2 justify-end">
                                    <Button variant="outline" onClick={() => setShowScheduleForm(false)}>Cancel</Button>
                                    <Button onClick={handleScheduleClass} disabled={isScheduling}>
                                        {isScheduling ? <Loader2 className="h-4 w-4 animate-spin" /> : 'Create Session'}
                                    </Button>
                                </div>
                            </CardContent>
                        </Card>
                    )}

                    <Card>
                        <CardHeader>
                            <CardTitle className="flex items-center gap-2">
                                <Calendar className="h-5 w-5" />
                                Upcoming Live Classes
                            </CardTitle>
                            <CardDescription>Scheduled classes across all courses</CardDescription>
                        </CardHeader>
                        <CardContent>
                            <div className="space-y-4">
                                {liveClasses.length === 0 ? (
                                    <p className="text-center py-8 text-muted-foreground">
                                        No upcoming live classes scheduled.
                                    </p>
                                ) : (
                                    liveClasses.map((cls) => (
                                        <Card key={cls.id} className="p-4">
                                            <div className="flex items-center justify-between">
                                                <div className="flex-1">
                                                    <div className="flex items-center gap-2 mb-2">
                                                        <span className="text-lg">{getPlatformIcon(cls.platform)}</span>
                                                        <h4 className="font-medium">{cls.title}</h4>
                                                        <Badge className={getStatusColor(cls.status)}>
                                                            {cls.status}
                                                        </Badge>
                                                    </div>
                                                    <p className="text-sm text-muted-foreground mb-2">
                                                        Course: {cls.course?.title}
                                                    </p>
                                                    <div className="flex items-center gap-4 text-sm">
                                                        <span className="flex items-center gap-1">
                                                            <Calendar className="h-4 w-4" />
                                                            {new Date(cls.scheduledAt).toLocaleDateString()}
                                                        </span>
                                                        <span className="flex items-center gap-1">
                                                            <Clock className="h-4 w-4" />
                                                            {new Date(cls.scheduledAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                                        </span>
                                                        <span className="flex items-center gap-1">
                                                            <Users className="h-4 w-4" />
                                                            {cls.duration} mins
                                                        </span>
                                                    </div>
                                                </div>
                                                <div className="flex gap-2">
                                                    {cls.meetingLink && (
                                                        <>
                                                            <Button
                                                                variant="outline"
                                                                size="sm"
                                                                onClick={() => navigator.clipboard.writeText(cls.meetingLink!)}
                                                                title="Copy meeting link"
                                                            >
                                                                <Copy className="h-4 w-4" />
                                                            </Button>
                                                            <Button
                                                                size="sm"
                                                                asChild
                                                            >
                                                                <a href={cls.meetingLink} target="_blank" rel="noreferrer">
                                                                    <ExternalLink className="h-4 w-4 mr-2" />
                                                                    Join
                                                                </a>
                                                            </Button>
                                                        </>
                                                    )}
                                                </div>
                                            </div>
                                        </Card>
                                    ))
                                )}
                            </div>
                        </CardContent>
                    </Card>
                </TabsContent>
            </Tabs>
        </div>
    )
}

"use client"

import * as React from 'react'
import Image from 'next/image'
import { useParams, useRouter } from 'next/navigation'
import Link from 'next/link'
import { Calendar, User, ArrowLeft, Tag, Loader2, Clock } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import api from '@/lib/api'
import DOMPurify from 'isomorphic-dompurify'

interface BlogPost {
    id: string
    title: string
    slug: string
    summary?: string
    content: string
    coverImage?: string
    publishedAt?: string
    createdAt: string
    author?: { name: string, avatar?: string }
    tags?: string[]
}

export default function BlogPostPage() {
    const params = useParams()
    const _router = useRouter()
    const slug = params.slug as string
    
    const [post, setPost] = React.useState<BlogPost | null>(null)
    const [isLoading, setIsLoading] = React.useState(true)
    const [error, setError] = React.useState<string | null>(null)

    React.useEffect(() => {
        const fetchPost = async () => {
            if (!slug) return
            setIsLoading(true)
            try {
                const res = await api.get(`/blogs/${slug}`)
                setPost(res.data)
            } catch (err: any) {
                console.error(err)
                setError(err.response?.data?.error || 'Failed to load blog post')
            } finally {
                setIsLoading(false)
            }
        }
        fetchPost()
    }, [slug])

    if (isLoading) {
        return (
            <div className="min-h-screen flex items-center justify-center">
                <Loader2 className="animate-spin h-12 w-12 text-primary" />
            </div>
        )
    }

    if (error || !post) {
        return (
            <div className="min-h-screen flex flex-col items-center justify-center p-4 text-center">
                <h2 className="text-2xl font-bold mb-4">{error || 'Post not found'}</h2>
                <Link href="/blog">
                    <Button>
                        <ArrowLeft className="mr-2 h-4 w-4" />
                        Back to Blog
                    </Button>
                </Link>
            </div>
        )
    }

    // Estimate reading time
    const wordsPerMinute = 200
    const textLength = post.content.split(/\s+/).length
    const readingTime = Math.ceil(textLength / wordsPerMinute)

    const sanitizedContent = DOMPurify.sanitize(post.content)

    return (
        <article className="min-h-screen py-12">
            <div className="container max-w-4xl">
                {/* Back Button */}
                <div className="mb-8">
                    <Link href="/blog">
                        <Button variant="ghost" size="sm" className="pl-0 hover:bg-transparent hover:text-primary">
                            <ArrowLeft className="mr-2 h-4 w-4" />
                            Back to Blog
                        </Button>
                    </Link>
                </div>

                {/* Cover Image */}
                {post.coverImage && (
                    <div className="relative aspect-video w-full mb-8 overflow-hidden rounded-xl border">
                        <Image
                            src={post.coverImage}
                            alt={post.title}
                            width={800}
                            height={450}
                            className="object-cover w-full h-full"
                        />
                    </div>
                )}

                {/* Blog Header */}
                <header className="mb-12">
                    <div className="flex flex-wrap items-center gap-4 mb-4">
                        {post.tags?.map(tag => (
                            <Badge key={tag} variant="secondary">
                                {tag}
                            </Badge>
                        )) || <Badge variant="secondary">Article</Badge>}
                        
                        <div className="flex items-center text-sm text-muted-foreground">
                            <Calendar className="mr-1 h-4 w-4" />
                            {new Date(post.publishedAt || post.createdAt).toLocaleDateString()}
                        </div>
                        
                        <div className="flex items-center text-sm text-muted-foreground">
                            <Clock className="mr-1 h-4 w-4" />
                            {readingTime} min read
                        </div>
                    </div>

                    <h1 className="text-4xl md:text-5xl font-bold mb-6 leading-tight">
                        {post.title}
                    </h1>

                    <div className="flex items-center gap-4 pt-4 border-t">
                        <div className="h-10 w-10 rounded-full bg-primary/10 flex items-center justify-center overflow-hidden border">
                            {post.author?.avatar ? (
                                <Image src={post.author.avatar} alt={post.author.name} width={40} height={40} className="h-full w-full object-cover" />
                            ) : (
                                <User className="h-5 w-5 text-primary" />
                            )}
                        </div>
                        <div>
                            <p className="font-medium">{post.author?.name || 'Admin'}</p>
                            <p className="text-xs text-muted-foreground">Author</p>
                        </div>
                    </div>
                </header>

                {/* Content */}
                <div 
                    className="prose prose-lg dark:prose-invert max-w-none mb-12"
                    dangerouslySetInnerHTML={{ __html: sanitizedContent }}
                />

                {/* Footer */}
                <footer className="border-t pt-8">
                    <div className="flex justify-between items-center">
                        <div className="flex gap-2">
                           {/* Social share placeholder if needed */}
                        </div>
                        <Link href="/blog">
                            <Button variant="outline">
                                View all articles
                            </Button>
                        </Link>
                    </div>
                </footer>
            </div>
        </article>
    )
}

"use client"

import { useState, useEffect, useCallback } from "react"
import { useParams, useRouter } from "next/navigation"
import api from "@/lib/api"
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card"
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs"
import { Textarea } from "@/components/ui/textarea"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import {
    Loader2, Mail, Phone, Calendar, Download, Send, Star, MessageSquare,
    Tag, Zap, CheckCircle2, XCircle, AlertTriangle, ArrowLeft,
    BookOpen
} from "lucide-react"

interface HistoryEntry {
    type?: string
    status?: string
    content?: string
    rating?: number
    tags?: string[]
    timestamp: string
    notes?: string
    addedBy?: string
}

interface ApplicationDetail {
    id: string
    status: string
    source: string
    atsScore: number
    createdAt: string
    externalName?: string
    externalEmail?: string
    externalPhone?: string
    coverLetter?: string
    resumeUrl?: string
    applicant?: {
        id: string
        name: string
        email: string
        phone?: string
        avatar?: string
    }
    statusHistory?: HistoryEntry[]
    job?: {
        title: string
        skills?: string
    }
}

function AIInterviewList({ userId }: { userId: string }) {
    interface Interview {
        id: string
        title: string
        status: string
        createdAt: string
        role?: string
        domain?: string
        difficulty?: string
        evaluation?: {
            overallScore: number
        }
    }
    const [interviews, setInterviews] = useState<Interview[]>([])
    const [loading, setLoading] = useState(true)

    useEffect(() => {
        const fetchInterviews = async () => {
            try {
                const res = await api.get(`/interviews/user/${userId}`)
                setInterviews(res.data.interviews || [])
            } catch (error) {
                console.error("Failed to fetch interviews", error)
            } finally {
                setLoading(false)
            }
        }
        fetchInterviews()
    }, [userId])

    if (loading) return <div className="text-center py-4"><Loader2 className="animate-spin h-5 w-5 mx-auto text-primary" /></div>
    if (interviews.length === 0) return <div className="text-center py-8 text-muted-foreground">No practice interviews found.</div>

    return (
        <div className="space-y-3">
            {interviews.map((interview) => (
                <div key={interview.id} className="flex items-center justify-between p-3 bg-white/50 border rounded-lg hover:bg-white transition-colors">
                    <div>
                        <div className="font-medium text-sm">{interview.role} ({interview.domain})</div>
                        <div className="text-xs text-muted-foreground gap-2 flex items-center">
                            <Badge variant="outline" className="text-[10px] h-4">{interview.difficulty}</Badge>
                            <span>{new Date(interview.createdAt).toLocaleDateString()}</span>
                        </div>
                    </div>
                    <div className="flex items-center gap-3">
                        {interview.evaluation ? (
                            <Badge variant={interview.evaluation.overallScore >= 70 ? 'default' : 'secondary'} className={interview.evaluation.overallScore >= 70 ? 'bg-green-600' : 'bg-amber-500'}>
                                {interview.evaluation.overallScore}%
                            </Badge>
                        ) : (
                            <span className="text-xs text-muted-foreground">In Progress</span>
                        )}
                        <Button size="sm" variant="ghost" onClick={() => window.open(`/interviews/${interview.id}/report`, '_blank')}>
                            View Report
                        </Button>
                    </div>
                </div>
            ))}
        </div>
    )
}

export default function CandidateProfilePage() {
    const { id } = useParams()
    const router = useRouter()

    const [application, setApplication] = useState<ApplicationDetail | null>(null)
    const [isLoading, setIsLoading] = useState(true)
    const [score, setScore] = useState<number | null>(null)

    // Notes
    const [noteContent, setNoteContent] = useState("")
    const [noteTags, setNoteTags] = useState("")
    const [submittingNote, setSubmittingNote] = useState(false)

    // Rating
    const [hoverRating, setHoverRating] = useState(0)
    const [selectedRating, setSelectedRating] = useState(0)

    const fetchData = useCallback(async () => {
        try {
            const res = await api.get(`/ats/applications/detail/${id}`)
            setApplication(res.data)
            setScore(res.data.atsScore)

            // Auto-mark as VIEWED if status is APPLIED
            if (res.data.status === 'APPLIED') {
                await api.patch(`/ats/status/${id}`, { status: 'VIEWED' })
                setApplication((prev) => prev ? ({ ...prev, status: 'VIEWED' }) : null)
            }

            // Extract most recent rating
            const ratings = (res.data.statusHistory || []).filter((h: HistoryEntry) => h.type === 'RATING')
            if (ratings.length > 0) {
                setSelectedRating(ratings[ratings.length - 1].rating || 0)
            }
        } catch (error) {
            console.error(error)
        } finally {
            setIsLoading(false)
        }
    }, [id])

    useEffect(() => {
        fetchData()
    }, [fetchData])

    const handleScore = async () => {
        const res = await api.post(`/ats/score/${id}`)
        setScore(res.data.atsScore)
        fetchData()
    }

    const handleStatusUpdate = async (newStatus: string) => {
        await api.patch(`/ats/status/${id}`, { status: newStatus })
        setApplication((prev) => prev ? ({ ...prev, status: newStatus }) : null)
    }

    const handleAddNote = async () => {
        if (!noteContent.trim()) return
        setSubmittingNote(true)
        try {
            const tags = noteTags.split(',').map(t => t.trim()).filter(Boolean)
            await api.post(`/ats/notes/${id}`, {
                content: noteContent,
                tags,
                rating: selectedRating || undefined
            })
            setNoteContent("")
            setNoteTags("")
            fetchData()
        } catch (error) {
            console.error('Failed to add note:', error)
        } finally {
            setSubmittingNote(false)
        }
    }

    const handleRate = async (rating: number) => {
        setSelectedRating(rating)
        try {
            await api.patch(`/ats/rate/${id}`, { rating })
        } catch (error) {
            console.error('Failed to rate:', error)
        }
    }

    if (isLoading) return (
        <div className="flex justify-center items-center h-[60vh]">
            <Loader2 className="animate-spin h-8 w-8 text-primary" />
        </div>
    )

    if (!application) return (
        <div className="text-center py-20 text-muted-foreground">
            <XCircle className="mx-auto h-12 w-12 mb-3 opacity-30" />
            Candidate not found
        </div>
    )

    const { applicant, externalName, externalEmail, externalPhone, source, status, coverLetter, resumeUrl } = application
    const name = applicant?.name || externalName || 'Unknown Candidate'
    const email = applicant?.email || externalEmail
    const phone = applicant?.phone || externalPhone || "N/A"

    // Separate notes vs status changes from history
    const notes = (application.statusHistory || []).filter(h => h.type === 'NOTE')
    const _statusHistory = (application.statusHistory || []).filter(h => !h.type || h.type === 'STATUS')
    const _ratings = (application.statusHistory || []).filter(h => h.type === 'RATING')

    const getStatusColor = (s: string) => {
        switch (s) {
            case 'APPLIED': case 'VIEWED': return 'bg-gray-400'
            case 'SCREENED': return 'bg-blue-500'
            case 'SHORTLISTED': return 'bg-purple-500'
            case 'INTERVIEW_SCHEDULED': case 'INTERVIEW_PENDING': return 'bg-violet-500'
            case 'SELECTED': case 'APPOINTED': case 'HIRED': return 'bg-green-500'
            case 'REJECTED': return 'bg-red-500'
            default: return 'bg-primary'
        }
    }

    return (
        <div className="max-w-5xl mx-auto py-6 px-4 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <Button variant="ghost" onClick={() => router.back()} className="mb-4 gap-2">
                <ArrowLeft className="h-4 w-4" /> Back to Pipeline
            </Button>

            <div className="grid gap-6 md:grid-cols-3">
                {/* Sidebar Profile */}
                <Card className="md:col-span-1 glass-card">
                    <CardContent className="pt-6 flex flex-col items-center text-center">
                        <Avatar className="h-24 w-24 mb-4 ring-4 ring-primary/10">
                            <AvatarImage src={applicant?.avatar} />
                            <AvatarFallback className="text-xl bg-primary/10 text-primary font-bold">{name[0]}</AvatarFallback>
                        </Avatar>
                        <h2 className="text-xl font-bold">{name}</h2>
                        <p className="text-sm text-muted-foreground mb-2">{email}</p>

                        {/* Star Rating */}
                        <div className="flex items-center gap-1 mb-4">
                            {[1, 2, 3, 4, 5].map((star) => (
                                <button
                                    key={star}
                                    onClick={() => handleRate(star)}
                                    onMouseEnter={() => setHoverRating(star)}
                                    onMouseLeave={() => setHoverRating(0)}
                                    className="p-0.5 transition-transform hover:scale-125"
                                    aria-label={`Rate ${star} stars`}
                                >
                                    <Star
                                        className={`h-5 w-5 transition-colors ${(hoverRating || selectedRating) >= star
                                            ? 'fill-amber-400 text-amber-400'
                                            : 'text-gray-300'
                                            }`}
                                    />
                                </button>
                            ))}
                        </div>

                        <div className="flex flex-wrap gap-2 justify-center mb-6">
                            {source === 'INTERNAL' ? (
                                <Badge className="bg-blue-600 hover:bg-blue-700">TechWell Student</Badge>
                            ) : (
                                <Badge variant="secondary">External</Badge>
                            )}
                            <Badge variant="outline" className={`${status === 'HIRED' || status === 'APPOINTED' ? 'border-green-300 text-green-700' :
                                status === 'REJECTED' ? 'border-red-300 text-red-700' : ''
                                }`}>{status}</Badge>
                        </div>

                        <div className="w-full space-y-2 text-left text-sm">
                            <div className="flex items-center gap-2">
                                <Phone className="w-4 h-4 text-muted-foreground" /> {phone}
                            </div>
                            <div className="flex items-center gap-2">
                                <Mail className="w-4 h-4 text-muted-foreground" /> {email}
                            </div>
                            <div className="flex items-center gap-2">
                                <Calendar className="w-4 h-4 text-muted-foreground" />
                                Applied {new Date(application.createdAt).toLocaleDateString()}
                            </div>
                        </div>

                        <div className="mt-6 w-full space-y-2">
                            {resumeUrl && (
                                <Button className="w-full" variant="outline" onClick={() => window.open(resumeUrl, '_blank')}>
                                    <Download className="mr-2 h-4 w-4" /> Resume
                                </Button>
                            )}
                            <Button className="w-full">
                                <Mail className="mr-2 h-4 w-4" /> Send Email
                            </Button>
                            <Button className="w-full" variant="secondary" onClick={() => router.push(`/employer/schedule-interview?appId=${application.id}`)}>
                                <Calendar className="mr-2 h-4 w-4" /> Schedule Interview
                            </Button>
                        </div>
                    </CardContent>
                </Card>

                {/* Main Content */}
                <div className="md:col-span-2 space-y-6">
                    {/* ATS Score Card */}
                    <Card className="glass-card overflow-hidden">
                        <CardHeader className="pb-2">
                            <CardTitle className="text-lg flex justify-between items-center">
                                <span className="flex items-center gap-2">
                                    <Zap className="h-5 w-5 text-primary" /> ATS Analysis
                                </span>
                                {score ? (
                                    <Badge variant={score >= 80 ? 'default' : 'secondary'} className={`text-base px-3 py-1 ${score >= 80 ? 'bg-green-600' : score >= 60 ? 'bg-amber-500' : 'bg-red-500'}`}>
                                        {score}% Match
                                    </Badge>
                                ) : (
                                    <Button size="sm" onClick={handleScore}>
                                        <Zap className="mr-1 h-3 w-3" /> Calculate Score
                                    </Button>
                                )}
                            </CardTitle>
                        </CardHeader>
                        <CardContent>
                            {score && (
                                <div className="mb-3">
                                    <div className="h-3 bg-muted rounded-full overflow-hidden">
                                        <div
                                            className={`h-full rounded-full transition-all duration-1000 ${score >= 80 ? 'bg-green-500' : score >= 60 ? 'bg-amber-500' : 'bg-red-500'}`}
                                            style={{ width: `${score}%` }}
                                        />
                                    </div>
                                </div>
                            )}
                            <p className="text-sm text-muted-foreground flex items-center gap-2">
                                {score && score >= 80 ? (
                                    <><CheckCircle2 className="h-4 w-4 text-green-500" /> Strong match! Recommended for interview.</>
                                ) : score && score >= 60 ? (
                                    <><AlertTriangle className="h-4 w-4 text-amber-500" /> Good match. Review experience details.</>
                                ) : score ? (
                                    <><XCircle className="h-4 w-4 text-red-500" /> Low match. Check resume manually.</>
                                ) : (
                                    <>Click calculate to run AI-powered analysis.</>
                                )}
                            </p>
                        </CardContent>
                    </Card>

                    <Tabs defaultValue="details">
                        <TabsList className="w-full grid grid-cols-4">
                            <TabsTrigger value="details">Details</TabsTrigger>
                            <TabsTrigger value="notes">Notes ({notes.length})</TabsTrigger>
                            <TabsTrigger value="resume">Resume</TabsTrigger>
                            <TabsTrigger value="history">History</TabsTrigger>
                        </TabsList>

                        <TabsContent value="details" className="space-y-4">
                            <Card className="glass-card">
                                <CardHeader>
                                    <CardTitle className="text-base">Cover Letter</CardTitle>
                                </CardHeader>
                                <CardContent>
                                    <div className="bg-muted/50 p-4 rounded-lg text-sm whitespace-pre-wrap leading-relaxed">
