import api from '@/lib/api'

interface Submission {
    id: string
    content: string | null
    fileUrl: string | null
    grade: number | null
    feedback: string | null
    status: string
    createdAt: string
    user: {
        id: string
        name: string
        email: string
        avatar: string | null
    }
    lesson: {
        id: string
        title: string
        module: {
            title: string
            course: {
                title: string
            }
        }
    }
}

export default function AssessmentsPage() {
    const [submissions, setSubmissions] = React.useState<Submission[]>([])
    const [loading, setLoading] = React.useState(true)
    const [searchQuery, setSearchQuery] = React.useState('')
    const [activeTab, setActiveTab] = React.useState('pending')

    const [selectedSubmission, setSelectedSubmission] = React.useState<Submission | null>(null)
    const [gradeValue, setGradeValue] = React.useState('')
    const [feedbackValue, setFeedbackValue] = React.useState('')
    const [grading, setGrading] = React.useState(false)

    React.useEffect(() => {
        fetchSubmissions()
    }, [])

    const fetchSubmissions = async () => {
        try {
            const res = await api.get('/trainer/assessments')
            setSubmissions(res.data || [])
        } catch (error) {
            console.error('Failed to fetch submissions:', error)
            // Fallback to empty for now
            setSubmissions([])
        } finally {
            setLoading(false)
        }
    }

    const handleGrade = async () => {
        if (!selectedSubmission || !gradeValue) return

        setGrading(true)
        try {
            await api.post('/trainer/assessments/grade', {
                submissionId: selectedSubmission.id,
                grade: parseInt(gradeValue),
                feedback: feedbackValue,
                status: 'GRADED'
            })
            setSelectedSubmission(null)
            setGradeValue('')
            setFeedbackValue('')
            fetchSubmissions()
        } catch (error) {
            console.error('Failed to grade submission:', error)
            alert('Failed to grade submission')
        } finally {
            setGrading(false)
        }
    }

    const filteredSubmissions = submissions.filter(s => {
        const matchesSearch =
            s.user.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
            s.lesson.title.toLowerCase().includes(searchQuery.toLowerCase())

        if (activeTab === 'pending') return matchesSearch && s.status === 'PENDING'
        if (activeTab === 'graded') return matchesSearch && s.status === 'GRADED'
        return matchesSearch
    })

    const pendingCount = submissions.filter(s => s.status === 'PENDING').length
    const gradedCount = submissions.filter(s => s.status === 'GRADED').length

    const getStatusBadge = (status: string) => {
        switch (status) {
            case 'PENDING':
                return <Badge variant="secondary" className="bg-amber-100 text-amber-700">Pending Review</Badge>
            case 'GRADED':
                return <Badge className="bg-green-100 text-green-700">Graded</Badge>
            case 'REJECTED':
                return <Badge variant="destructive">Rejected</Badge>
            default:
                return <Badge variant="outline">{status}</Badge>
        }
    }

    return (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
            {/* Header */}
            <div>
                <h1 className="text-2xl font-black text-slate-800">Assessment Center</h1>
                <p className="text-sm text-slate-500 mt-1">Review and grade student assignments</p>
            </div>

            {/* Stats */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <Card className="border-none shadow-sm">
                    <CardContent className="p-4 flex items-center gap-4">
                        <div className="p-3 rounded-xl bg-amber-100">
                            <Clock className="h-5 w-5 text-amber-600" />
                        </div>
                        <div>
                            <p className="text-2xl font-bold">{pendingCount}</p>
                            <p className="text-xs text-slate-500 font-medium">Pending Review</p>
                        </div>
                    </CardContent>
                </Card>
                <Card className="border-none shadow-sm">
                    <CardContent className="p-4 flex items-center gap-4">
                        <div className="p-3 rounded-xl bg-green-100">
                            <CheckCircle2 className="h-5 w-5 text-green-600" />
                        </div>
                        <div>
                            <p className="text-2xl font-bold">{gradedCount}</p>
                            <p className="text-xs text-slate-500 font-medium">Graded</p>
                        </div>
                    </CardContent>
                </Card>
                <Card className="border-none shadow-sm">
                    <CardContent className="p-4 flex items-center gap-4">
                        <div className="p-3 rounded-xl bg-primary/10">
                            <FileCheck className="h-5 w-5 text-primary" />
                        </div>
                        <div>
                            <p className="text-2xl font-bold">{submissions.length}</p>
                            <p className="text-xs text-slate-500 font-medium">Total Submissions</p>
                        </div>
                    </CardContent>
                </Card>
            </div>

            {/* Tabs & Search */}
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <Tabs value={activeTab} onValueChange={setActiveTab}>
                    <TabsList>
                        <TabsTrigger value="pending">
                            Pending ({pendingCount})
                        </TabsTrigger>
                        <TabsTrigger value="graded">
                            Graded ({gradedCount})
                        </TabsTrigger>
                        <TabsTrigger value="all">All</TabsTrigger>
                    </TabsList>
                </Tabs>

                <div className="relative max-w-sm">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                    <Input
                        placeholder="Search by student or assignment..."
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        className="pl-10"
                    />
                </div>
            </div>

            {/* Submissions List */}
            {loading ? (
                <div className="flex items-center justify-center py-20">
                    <Loader2 className="h-8 w-8 animate-spin text-primary" />
                </div>
            ) : filteredSubmissions.length === 0 ? (
                <Card className="border-dashed">
                    <CardContent className="flex flex-col items-center justify-center py-16">
                        <FileCheck className="h-16 w-16 text-slate-300 mb-4" />
                        <h3 className="text-lg font-bold text-slate-600">
                            {activeTab === 'pending' ? 'No pending submissions' : 'No submissions found'}
                        </h3>
                        <p className="text-sm text-slate-500 mt-1">
                            {activeTab === 'pending'
                                ? 'All caught up! No assignments waiting for review.'
                                : 'No submissions match your search criteria.'}
                        </p>
                    </CardContent>
                </Card>
            ) : (
                <div className="space-y-4">
                    {filteredSubmissions.map((submission) => (
                        <Card key={submission.id} className="border-none shadow-sm hover:shadow-md transition-all">
                            <CardContent className="p-6">
                                <div className="flex flex-col md:flex-row md:items-center gap-4">
                                    {/* Student Info */}
                                    <div className="flex items-center gap-3 min-w-[200px]">
                                        <div className="h-10 w-10 rounded-full bg-slate-200 flex items-center justify-center">
                                            {submission.user.avatar ? (
                                                <Image src={submission.user.avatar} alt="" width={40} height={40} className="h-10 w-10 rounded-full object-cover" />
                                            ) : (
                                                <User className="h-5 w-5 text-slate-500" />
                                            )}
                                        </div>
                                        <div>
                                            <p className="font-bold text-slate-800">{submission.user.name}</p>
                                            <p className="text-xs text-slate-500">{submission.user.email}</p>
                                        </div>
                                    </div>

                                    {/* Assignment Info */}
                                    <div className="flex-1">
                                        <p className="font-medium text-slate-700">{submission.lesson.title}</p>
                                        <p className="text-xs text-slate-500 flex items-center gap-1">
                                            <BookOpen className="h-3 w-3" />
                                            {submission.lesson.module.course.title} • {submission.lesson.module.title}
                                        </p>
                                    </div>

                                    {/* Status & Grade */}
                                    <div className="flex items-center gap-4">
                                        {getStatusBadge(submission.status)}
                                        {submission.grade !== null && (
                                            <span className="text-lg font-bold text-primary">{submission.grade}%</span>
                                        )}
                                    </div>

                                    {/* Actions */}
                                    <div className="flex items-center gap-2">
                                        <Button
                                            variant="outline"
                                            size="sm"
                                            onClick={() => {
                                                setSelectedSubmission(submission)
                                                setGradeValue(submission.grade?.toString() || '')
                                                setFeedbackValue(submission.feedback || '')
                                            }}
                                        >
                                            <Eye className="h-4 w-4 mr-1" />
                                            {submission.status === 'PENDING' ? 'Review' : 'View'}
                                        </Button>
                                        {submission.fileUrl && (
                                            <Button variant="ghost" size="icon" asChild>
                                                <a href={submission.fileUrl} target="_blank" rel="noopener noreferrer" title="Download attachment">
                                                    <Download className="h-4 w-4" />
                                                </a>
                                            </Button>
                                        )}
                                    </div>
                                </div>

                                {/* Submitted Date */}
                                <div className="mt-4 pt-4 border-t flex items-center justify-between text-xs text-slate-500">
                                    <span>Submitted {new Date(submission.createdAt).toLocaleString()}</span>
                                    {submission.feedback && (
                                        <span className="flex items-center gap-1">
                                            <MessageSquare className="h-3 w-3" />
                                            Feedback provided
                                        </span>
                                    )}
                                </div>
                            </CardContent>
                        </Card>
                    ))}
                </div>
            )}

            {/* Grade Dialog */}
            <Dialog open={!!selectedSubmission} onOpenChange={() => setSelectedSubmission(null)}>
                <DialogContent className="sm:max-w-2xl max-h-[90vh] overflow-y-auto">
                    <DialogHeader>
                        <DialogTitle>Review Submission</DialogTitle>
                        <DialogDescription>
                            {selectedSubmission?.lesson.title} - {selectedSubmission?.user.name}
                        </DialogDescription>
                    </DialogHeader>

                    {selectedSubmission && (
                        <div className="space-y-6 py-4">
                            {/* Submission Content */}
                            <div className="space-y-2">
                                <label className="text-sm font-medium">Submission Content</label>
                                <div className="p-4 bg-slate-50 rounded-lg border min-h-[100px]">
                                    {selectedSubmission.content ? (
                                        <p className="text-sm whitespace-pre-wrap">{selectedSubmission.content}</p>
                                    ) : (
                                        <p className="text-sm text-slate-500 italic">No text content submitted</p>
                                    )}
                                </div>
                                {selectedSubmission.fileUrl && (
                                    <Button variant="outline" size="sm" asChild className="mt-2">
                                        <a href={selectedSubmission.fileUrl} target="_blank" rel="noopener noreferrer">
                                            <Download className="h-4 w-4 mr-2" />
                                            Download Attachment
                                        </a>
                                    </Button>
                                )}
                            </div>

                            {/* Grade Input */}
                            <div className="space-y-2">
                                <label className="text-sm font-medium">Grade (0-100) *</label>
                                <Input
                                    type="number"
                                    min="0"
                                    max="100"
                                    placeholder="Enter grade..."
                                    value={gradeValue}
                                    onChange={(e) => setGradeValue(e.target.value)}
                                />
                            </div>

                            {/* Feedback */}
                            <div className="space-y-2">
                                <label className="text-sm font-medium">Feedback</label>
                                <Textarea
                                    placeholder="Provide constructive feedback to the student..."
                                    value={feedbackValue}
                                    onChange={(e) => setFeedbackValue(e.target.value)}
                                    rows={4}
                                />
                            </div>
                        </div>
                    )}

                    <DialogFooter className="gap-2">
                        <Button variant="outline" onClick={() => setSelectedSubmission(null)}>
                            Cancel
                        </Button>
                        {selectedSubmission?.status === 'PENDING' && (
                            <Button
                                onClick={handleGrade}
                                disabled={grading || !gradeValue}
                            >
                                {grading && <Loader2 className="h-4 w-4 mr-2 animate-spin" />}
                                Submit Grade
                            </Button>
                        )}
                    </DialogFooter>
                </DialogContent>
            </Dialog>
        </div>
    )
}

"use client"

import * as React from 'react'
import Image from 'next/image'
import {
    Users,
    Search,
    Filter,
    Loader2,
    User,
    BookOpen,
    TrendingUp,
    TrendingDown,
    AlertTriangle,
    ArrowUpRight,
    BarChart3,
    Target,
    ChevronDown
} from 'lucide-react'
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Badge } from '@/components/ui/badge'
import { Progress } from '@/components/ui/progress'
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogDescription
} from '@/components/ui/dialog'
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuTrigger
} from '@/components/ui/dropdown-menu'
import api from '@/lib/api'

interface Student {
    id: string
    name: string
    email: string
    avatar: string | null
    enrollments: {
        course: { id: string; title: string }
        progress: number
        completedAt: string | null
    }[]
}

interface Batch {
    id: string
    name: string
    course: { title: string }
}

interface StudentProgress {
    student: { name: string; email: string }
    course: { title: string }
    overallProgress: number
    modules: {
        title: string
        progress: number
        lessons: {
            title: string
            completed: boolean
            score: number | null
        }[]
    }[]
}

export default function InstructorStudentsPage() {
    const [students, setStudents] = React.useState<Student[]>([])
    const [batches, setBatches] = React.useState<Batch[]>([])
    const [loading, setLoading] = React.useState(true)
    const [searchQuery, setSearchQuery] = React.useState('')
    const [selectedBatch, setSelectedBatch] = React.useState<string>('')
    const [progressFilter, setProgressFilter] = React.useState<string>('all')

    const [selectedStudent, setSelectedStudent] = React.useState<Student | null>(null)
    const [selectedCourseId, setSelectedCourseId] = React.useState<string>('')
    const [studentProgress, setStudentProgress] = React.useState<StudentProgress | null>(null)
    const [loadingProgress, setLoadingProgress] = React.useState(false)

    React.useEffect(() => {
        fetchData()
    }, [selectedBatch])

    const fetchData = async () => {
        setLoading(true)
        try {
            const [studentsRes, batchesRes] = await Promise.all([
                api.get('/trainer/students', { params: { batchId: selectedBatch || undefined } }),
                api.get('/trainer/batches')
            ])
            setStudents(studentsRes.data || [])
            setBatches(batchesRes.data || [])
        } catch (error) {
            console.error('Failed to fetch data:', error)
        } finally {
            setLoading(false)
        }
    }

    const fetchStudentProgress = async (studentId: string, courseId: string) => {
        setLoadingProgress(true)
        try {
            const res = await api.get(`/trainer/students/${studentId}/progress`, {
                params: { courseId }
            })
            setStudentProgress(res.data)
        } catch (error) {
            console.error('Failed to fetch progress:', error)
            setStudentProgress(null)
        } finally {
            setLoadingProgress(false)
        }
    }

    const handleViewProgress = (student: Student, courseId: string) => {
        setSelectedStudent(student)
        setSelectedCourseId(courseId)
        fetchStudentProgress(student.id, courseId)
    }

    const getProgressColor = (progress: number) => {
        if (progress >= 80) return 'text-green-600 bg-green-100'
        if (progress >= 50) return 'text-amber-600 bg-amber-100'
        return 'text-red-600 bg-red-100'
    }

    const getProgressIcon = (progress: number) => {
        if (progress >= 80) return TrendingUp
        if (progress >= 50) return Target
        return TrendingDown
    }

    const filteredStudents = students.filter(s => {
        const matchesSearch = s.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
            s.email.toLowerCase().includes(searchQuery.toLowerCase())

        if (progressFilter === 'all') return matchesSearch

        const avgProgress = s.enrollments.reduce((acc, e) => acc + e.progress, 0) / (s.enrollments.length || 1)

        if (progressFilter === 'at-risk') return matchesSearch && avgProgress < 30
        if (progressFilter === 'on-track') return matchesSearch && avgProgress >= 30 && avgProgress < 80
        if (progressFilter === 'top') return matchesSearch && avgProgress >= 80

        return matchesSearch
    })

    const atRiskCount = students.filter(s => {
        const avg = s.enrollments.reduce((acc, e) => acc + e.progress, 0) / (s.enrollments.length || 1)
        return avg < 30
    }).length

    return (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
            {/* Header */}
            <div>
                <h1 className="text-2xl font-black text-slate-800">Student Progress</h1>
                <p className="text-sm text-slate-500 mt-1">Monitor and track student performance across your courses</p>
            </div>

            {/* Stats */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                <Card className="border-none shadow-sm">
                    <CardContent className="p-4 flex items-center gap-4">
                        <div className="p-3 rounded-xl bg-primary/10">
                            <Users className="h-5 w-5 text-primary" />
                        </div>
                        <div>
                            <p className="text-2xl font-bold">{students.length}</p>
                            <p className="text-xs text-slate-500 font-medium">Total Students</p>
                        </div>
                    </CardContent>
                </Card>
                <Card className="border-none shadow-sm cursor-pointer hover:shadow-md transition-all"
                    onClick={() => setProgressFilter('top')}>
                    <CardContent className="p-4 flex items-center gap-4">
                        <div className="p-3 rounded-xl bg-green-100">
                            <TrendingUp className="h-5 w-5 text-green-600" />
                        </div>
                        <div>
                            <p className="text-2xl font-bold">
                                {students.filter(s => {
                                    const avg = s.enrollments.reduce((acc, e) => acc + e.progress, 0) / (s.enrollments.length || 1)
                                    return avg >= 80
                                }).length}
                            </p>
                            <p className="text-xs text-slate-500 font-medium">Top Performers</p>
                        </div>
                    </CardContent>
                </Card>
                <Card className="border-none shadow-sm cursor-pointer hover:shadow-md transition-all"
                    onClick={() => setProgressFilter('on-track')}>
                    <CardContent className="p-4 flex items-center gap-4">
                        <div className="p-3 rounded-xl bg-amber-100">
                            <Target className="h-5 w-5 text-amber-600" />
                        </div>
                        <div>
                            <p className="text-2xl font-bold">
                                {students.filter(s => {
                                    const avg = s.enrollments.reduce((acc, e) => acc + e.progress, 0) / (s.enrollments.length || 1)
                                    return avg >= 30 && avg < 80
                                }).length}
                            </p>
                            <p className="text-xs text-slate-500 font-medium">On Track</p>
                        </div>
                    </CardContent>
                </Card>
                <Card className="border-none shadow-sm cursor-pointer hover:shadow-md transition-all border-red-200"
                    onClick={() => setProgressFilter('at-risk')}>
                    <CardContent className="p-4 flex items-center gap-4">
                        <div className="p-3 rounded-xl bg-red-100">
                            <AlertTriangle className="h-5 w-5 text-red-600" />
                        </div>
                        <div>
                            <p className="text-2xl font-bold text-red-600">{atRiskCount}</p>
                            <p className="text-xs text-slate-500 font-medium">At Risk</p>
                        </div>
                    </CardContent>
                </Card>
            </div>

            {/* Filters */}
            <div className="flex flex-col md:flex-row md:items-center gap-4">
                <div className="relative flex-1 max-w-md">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                    <Input
                        placeholder="Search students..."
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        className="pl-10"
                    />
                </div>

                <DropdownMenu>
                    <DropdownMenuTrigger asChild>
                        <Button variant="outline" className="gap-2">
                            <Filter className="h-4 w-4" />
                            {selectedBatch ? batches.find(b => b.id === selectedBatch)?.name : 'All Batches'}
                            <ChevronDown className="h-4 w-4" />
                        </Button>
                    </DropdownMenuTrigger>
                    <DropdownMenuContent>
                        <DropdownMenuItem onClick={() => setSelectedBatch('')}>All Batches</DropdownMenuItem>
                        {batches.map(batch => (
                            <DropdownMenuItem key={batch.id} onClick={() => setSelectedBatch(batch.id)}>
                                {batch.name}
                            </DropdownMenuItem>
                        ))}
                    </DropdownMenuContent>
                </DropdownMenu>

                {progressFilter !== 'all' && (
                    <Button variant="ghost" size="sm" onClick={() => setProgressFilter('all')}>
                        Clear filter
                    </Button>
                )}
            </div>

            {/* Students List */}
            {loading ? (
                <div className="flex items-center justify-center py-20">
                    <Loader2 className="h-8 w-8 animate-spin text-primary" />
                </div>
            ) : filteredStudents.length === 0 ? (
                <Card className="border-dashed">
                    <CardContent className="flex flex-col items-center justify-center py-16">
                        <Users className="h-16 w-16 text-slate-300 mb-4" />
                        <h3 className="text-lg font-bold text-slate-600">No students found</h3>
                        <p className="text-sm text-slate-500 mt-1">
                            {searchQuery ? 'Try adjusting your search' : 'No students enrolled yet'}
                        </p>
                    </CardContent>
                </Card>
            ) : (
                <div className="space-y-4">
                    {filteredStudents.map((student) => {
                        const avgProgress = student.enrollments.reduce((acc, e) => acc + e.progress, 0) / (student.enrollments.length || 1)
                        const ProgressIcon = getProgressIcon(avgProgress)

                        return (
                            <Card key={student.id} className="border-none shadow-sm hover:shadow-md transition-all">
                                <CardContent className="p-6">
                                    <div className="flex flex-col md:flex-row md:items-center gap-4">
                                        {/* Student Info */}
                                        <div className="flex items-center gap-4 min-w-[250px]">
                                            <div className="h-12 w-12 rounded-full bg-slate-200 flex items-center justify-center">
                                                {student.avatar ? (
                                                    <Image src={student.avatar} alt="" width={48} height={48} className="h-12 w-12 rounded-full object-cover" />
                                                ) : (
                                                    <User className="h-6 w-6 text-slate-500" />
                                                )}
                                            </div>
                                            <div>
                                                <p className="font-bold text-slate-800">{student.name}</p>
                                                <p className="text-xs text-slate-500">{student.email}</p>
                                            </div>
                                        </div>

                                        {/* Progress Overview */}
                                        <div className="flex-1">
                                            <div className="flex items-center gap-4 mb-2">
                                                <div className={`flex items-center gap-1 px-2 py-1 rounded-full text-xs font-bold ${getProgressColor(avgProgress)}`}>
                                                    <ProgressIcon className="h-3 w-3" />
                                                    {Math.round(avgProgress)}% avg
                                                </div>
                                                <span className="text-xs text-slate-500">
                                                    {student.enrollments.length} course{student.enrollments.length !== 1 ? 's' : ''}
                                                </span>
                                            </div>
                                            <Progress value={avgProgress} className="h-2" />
                                        </div>

                                        {/* Courses */}
                                        <div className="flex flex-wrap gap-2">
                                            {student.enrollments.slice(0, 2).map((enrollment) => (
                                                <Button
                                                    key={enrollment.course.id}
                                                    variant="outline"
                                                    size="sm"
                                                    className="text-xs"
                                                    onClick={() => handleViewProgress(student, enrollment.course.id)}
                                                >
                                                    <BookOpen className="h-3 w-3 mr-1" />
                                                    {enrollment.course.title.substring(0, 20)}...
                                                    <Badge variant="secondary" className="ml-2 text-[10px]">
                                                        {enrollment.progress}%
                                                    </Badge>
                                                </Button>
                                            ))}
                                            {student.enrollments.length > 2 && (
                                                <Badge variant="outline">+{student.enrollments.length - 2} more</Badge>
                                            )}
                                        </div>
                                    </div>
                                </CardContent>
                            </Card>
                        )
                    })}
                </div>
            )}

            {/* Progress Detail Dialog */}
            <Dialog open={!!selectedStudent && !!selectedCourseId} onOpenChange={() => {
                setSelectedStudent(null)
                setSelectedCourseId('')
                setStudentProgress(null)
            }}>
                <DialogContent className="sm:max-w-2xl max-h-[90vh] overflow-y-auto">
                    <DialogHeader>
                        <DialogTitle>Student Progress Details</DialogTitle>
                        <DialogDescription>
                            {selectedStudent?.name} - {studentProgress?.course.title || 'Loading...'}
                        </DialogDescription>
                    </DialogHeader>

                    {loadingProgress ? (
                        <div className="flex items-center justify-center py-12">
                            <Loader2 className="h-8 w-8 animate-spin text-primary" />
                        </div>
                    ) : studentProgress ? (
                        <div className="space-y-6 py-4">
                            {/* Overall Progress */}
                            <div className="p-4 bg-slate-50 rounded-xl">
                                <div className="flex items-center justify-between mb-2">
                                    <span className="font-medium">Overall Progress</span>
                                    <span className="text-lg font-bold text-primary">{studentProgress.overallProgress}%</span>
                                </div>
                                <Progress value={studentProgress.overallProgress} className="h-3" />
                            </div>

                            {/* Module-wise Progress */}
                            <div className="space-y-4">
                                <h3 className="font-bold text-slate-800">Module Breakdown</h3>
                                {studentProgress.modules.map((module, idx) => (
                                    <Card key={idx} className="border">
                                        <CardHeader className="py-3 px-4">
                                            <div className="flex items-center justify-between">
                                                <CardTitle className="text-sm">{module.title}</CardTitle>
                                                <Badge variant={module.progress === 100 ? "default" : "secondary"}>
                                                    {module.progress}%
                                                </Badge>
                                            </div>
                                        </CardHeader>
                                        <CardContent className="px-4 pb-4 pt-0">
                                            <div className="space-y-2">
                                                {module.lessons.map((lesson, lidx) => (
                                                    <div key={lidx} className="flex items-center justify-between text-sm py-1 border-b last:border-0">
                                                        <span className={lesson.completed ? 'text-slate-800' : 'text-slate-500'}>
                                                            {lesson.title}
                                                        </span>
                                                        <div className="flex items-center gap-2">
                                                            {lesson.score !== null && (
                                                                <Badge variant="outline" className="text-xs">
                                                                    Score: {lesson.score}%
                                                                </Badge>
                                                            )}
                                                            {lesson.completed ? (
                                                                <Badge className="bg-green-100 text-green-700 text-xs">Done</Badge>
                                                            ) : (
                                                                <Badge variant="secondary" className="text-xs">Pending</Badge>
                                                            )}
                                                        </div>
                                                    </div>
                                                ))}
                                            </div>
                                        </CardContent>
                                    </Card>
                                ))}
                            </div>
                        </div>
                    ) : (
                        <div className="text-center py-12 text-slate-500">
                            <p>Unable to load progress details</p>
                        </div>
                    )}
                </DialogContent>
            </Dialog>
        </div>
    )
}

"use client"

import * as React from 'react'
import { useRouter, useParams } from 'next/navigation'
import { useAuth } from '@/lib/auth-context'
import { interviewApi } from '@/lib/api'
import { Button } from '@/components/ui/button'
import { Card, CardContent } from '@/components/ui/card'
import {
    Video,
    VideoOff,
    Mic,
    MicOff,
    Phone,
    ChevronRight,
    Clock,
    Bot,
    Loader2,
    CheckCircle2,
    ArrowLeft,
    Send,
    Briefcase,
    AlertTriangle,
    Maximize,
    Minimize,
    Volume2,
    VolumeX
} from 'lucide-react'
import { useToast } from '@/components/ui/use-toast'

// Speech Recognition Types
interface ISpeechRecognitionEvent extends Event {
    resultIndex: number
    results: {
        [key: number]: {
            [key: number]: {
                transcript: string
            }
            length: number
            isFinal: boolean
        }
        length: number
    }
}

interface ISpeechRecognitionErrorEvent extends Event {
    error: string
}

interface ISpeechRecognition extends EventTarget {
    continuous: boolean
    interimResults: boolean
    onresult: (event: ISpeechRecognitionEvent) => void
    onerror: (event: ISpeechRecognitionErrorEvent) => void
    onend: () => void
    start: () => void
    stop: () => void
}

declare global {
    interface Window {
        SpeechRecognition: new () => ISpeechRecognition
        webkitSpeechRecognition: new () => ISpeechRecognition
    }
}

interface Message {
    id: string
    role: 'interviewer' | 'user'
    content: string
    timestamp: Date
}

interface Question {
    id: string
    question: string
    type: string
    avatarRole: string // 'Technical', 'HR', etc.
}

interface AvatarConfig {
    name: string
    role: string
    color: string
    icon: React.ElementType
}

const AVATARS: Record<string, AvatarConfig> = {
    'tech-1': { name: "Alex Chen", role: "Technical Lead", color: "from-blue-500/20 to-cyan-500/20", icon: Bot },
    'tech-2': { name: "Sarah Johnson", role: "Senior Engineer", color: "from-indigo-500/20 to-blue-500/20", icon: Bot },
    'hr-1': { name: "Emma Williams", role: "HR Manager", color: "from-purple-500/20 to-pink-500/20", icon: Briefcase },
    'hr-2': { name: "David Smith", role: "Talent Acquisition", color: "from-slate-500/20 to-gray-500/20", icon: Briefcase },
    // Fallbacks
    'Technical': { name: "AI Interviewer", role: "Technical", color: "from-blue-500/20 to-cyan-500/20", icon: Bot },
    'HR': { name: "AI Recruiter", role: "HR", color: "from-purple-500/20 to-pink-500/20", icon: Briefcase }
}

// Success Overlay Component
function SuccessOverlay({ onRedirect, onDashboard }: { onRedirect: () => void, onDashboard: () => void }) {
    React.useEffect(() => {
        // Reduced auto-redirect time to let user choose
        const timer = setTimeout(onRedirect, 10000);
        return () => clearTimeout(timer);
    }, [onRedirect]);

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-background/80 backdrop-blur-sm animate-in fade-in duration-500">
            <div className="text-center space-y-6 p-8 bg-card border rounded-2xl shadow-2xl max-w-md w-full animate-in zoom-in-50 duration-500 delay-150">
                <div className="mx-auto h-24 w-24 bg-green-100 rounded-full flex items-center justify-center mb-4">
                    <CheckCircle2 className="h-12 w-12 text-green-600 animate-in zoom-in duration-300 delay-300" />
                </div>
                <div className="space-y-2">
                    <h2 className="text-3xl font-bold tracking-tight">Interview Completed!</h2>
                    <p className="text-muted-foreground">Great job! We are generating your performance report now.</p>
                </div>
                
                <div className="flex flex-col gap-3 pt-4">
                    <Button 
                        onClick={onRedirect}
                        className="w-full h-12 rounded-xl font-bold"
                    >
                        View Performance Report
                        <ChevronRight className="ml-2 h-4 w-4" />
                    </Button>
                    <Button 
                        variant="outline"
                        onClick={onDashboard}
                        className="w-full h-12 rounded-xl font-bold"
                    >
                        <ArrowLeft className="mr-2 h-4 w-4" />
                        Back to Dashboard
                    </Button>
                </div>

                <div className="flex justify-center gap-2 mt-4">
                    <div className="h-2 w-2 bg-primary rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                    <div className="h-2 w-2 bg-primary rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                    <div className="h-2 w-2 bg-primary rounded-full animate-bounce"></div>
                </div>
            </div>
        </div>
    );
}

export default function InterviewRoomPage() {
    const router = useRouter()
    const params = useParams()
    const { isAuthenticated, isLoading: authLoading } = useAuth()
    const { toast } = useToast()

    const videoRef = React.useRef<HTMLVideoElement>(null)
    const [stream, setStream] = React.useState<MediaStream | null>(null)
    const [isVideoOn, setIsVideoOn] = React.useState(true)
    const [isMicOn, setIsMicOn] = React.useState(true)

    // AI State
    const [currentQuestion, setCurrentQuestion] = React.useState<Question | null>(null)
    const [questionCount, setQuestionCount] = React.useState(0)

    const [_messages, setMessages] = React.useState<Message[]>([])
    const [userResponse, setUserResponse] = React.useState('')
    const [codeResponse, setCodeResponse] = React.useState('') // New: Code Editor State
    const [isThinking, setIsThinking] = React.useState(false)
    const [isAIProcessing, setIsAIProcessing] = React.useState(false)

    // 2026 Features: Real-time Analysis
    const [wpm, setWpm] = React.useState(0)
    const [fillerCount, setFillerCount] = React.useState(0)
    const [speechStartTime, setSpeechStartTime] = React.useState<number | null>(null)
    const [_tabSwitchCount, setTabSwitchCount] = React.useState(0)
    const [isTabActive, setIsTabActive] = React.useState(true)
    const [isStarted, setIsStarted] = React.useState(false)
    const [isFullscreen, setIsFullscreen] = React.useState(false)
    const [isVoiceEnabled, setIsVoiceEnabled] = React.useState(true)

    // Fullscreen Toggle
    const toggleFullscreen = React.useCallback(() => {
        if (!document.fullscreenElement) {
            document.documentElement.requestFullscreen().then(() => setIsFullscreen(true)).catch(err => {
                console.error(`Error attempting to enable full-screen mode: ${err.message}`);
            });
        } else {
            document.exitFullscreen().then(() => setIsFullscreen(false));
        }
    }, [])

    // Listen for fullscreen change (e.g. Esc key)
    React.useEffect(() => {
        const handleFullscreenChange = () => {
            setIsFullscreen(!!document.fullscreenElement)
        }
        document.addEventListener('fullscreenchange', handleFullscreenChange)
        return () => document.removeEventListener('fullscreenchange', handleFullscreenChange)
    }, [])

    // Anti-Cheat: Tab Visibility
    React.useEffect(() => {
        const handleVisibilityChange = () => {
            if (document.hidden) {
                setTabSwitchCount(prev => prev + 1)
                setIsTabActive(false)
                toast({
                    variant: "destructive",
                    title: "Warning: Tab Switch Detected",
                    description: "Please stay on this tab during the interview. This event has been logged."
                })
            } else {
                setIsTabActive(true)
            }
        }
        document.addEventListener("visibilitychange", handleVisibilityChange)
        return () => document.removeEventListener("visibilitychange", handleVisibilityChange)
    }, [toast])

    // Real-time Speech Logic
    const analyzeSpeech = React.useCallback((transcript: string) => {
        if (!speechStartTime) return

        const words = transcript.trim().split(/\s+/).length
        const durationMin = (Date.now() - speechStartTime) / 60000
        const currentWpm = durationMin > 0 ? Math.round(words / durationMin) : 0
        setWpm(currentWpm)

        const fillers = (transcript.match(/\b(um|uh|like|you know|sort of)\b/gi) || []).length
        setFillerCount(fillers)
    }, [speechStartTime])

    interface Interview {
        id: string
        role: string
        company?: string
        technology?: string
        difficulty?: string
        duration?: number
        panelCount?: number
        selectedAvatars?: string[]
    }

    const [interview, setInterview] = React.useState<Interview | null>(null)
    const [timeLeft, setTimeLeft] = React.useState(0) // Seconds
    const [isCompleted, setIsCompleted] = React.useState(false)

    const [showSuccess, setShowSuccess] = React.useState(false)

    React.useEffect(() => {
        if (!authLoading && !isAuthenticated) {
            router.push('/login')
        }
    }, [authLoading, isAuthenticated, router])

    // Load Interview & Init Timer
    React.useEffect(() => {
        const fetchInterview = async () => {
            try {
                const res = await interviewApi.getById(params.id as string)
                setInterview(res.data.interview)
                // Initialize timer (default 30 mins if missing)
                if (res.data.interview.duration) {
                    setTimeLeft(res.data.interview.duration * 60)
                } else {
                    setTimeLeft(30 * 60)
                }
            } catch (error) {
                console.error('Failed to fetch interview:', error)
            }
        }
        if (params.id) {
            fetchInterview()
        }
    }, [params.id])

    // Countdown Timer
    React.useEffect(() => {
        if (!isCompleted && timeLeft > 0) {
            const timer = setInterval(() => {
                setTimeLeft(prev => {
                    if (prev <= 1) {
                        clearInterval(timer)
                        handleEndInterview() // Auto-end
                        return 0
                    }
                    return prev - 1
                })
            }, 1000)
            return () => clearInterval(timer)
        }
    }, [isCompleted, timeLeft])

    // Initialize camera stream
    React.useEffect(() => {
        const initCamera = async () => {
            try {
                const mediaStream = await navigator.mediaDevices.getUserMedia({
                    video: true,
                    audio: true
                })
                setStream(mediaStream)
                if (videoRef.current) {
                    videoRef.current.srcObject = mediaStream
                }
            } catch (error) {
                console.error('Failed to access camera:', error)
                toast({
                    variant: "destructive",
                    title: "Hardware Access Error",
                    description: "Could not access camera/microphone. Please check permissions."
                })
                setIsMicOn(false)
                setIsVideoOn(false)
            }
        }
        initCamera()

        return () => {
            if (stream) {
                stream.getTracks().forEach(track => track.stop())
            }
        }
    }, [])

    // Sync Mic State with Stream
    React.useEffect(() => {
        if (stream) {
            stream.getAudioTracks().forEach(track => {
                track.enabled = isMicOn
            })
        }
    }, [isMicOn, stream])

    // Initial Question Fetch
    React.useEffect(() => {
        const startInterview = async () => {
            // Only trigger if started AND no question has been loaded yet AND not already loading
            if (isStarted && !isCompleted && !currentQuestion && !isAIProcessing) {
                console.log("[InterviewRoom] Triggering initial question fetch...");
                await fetchNextQuestion();
            }
        }
        startInterview();
        // Removed currentQuestion and isAIProcessing from dependencies to prevent infinite loops on failure
    }, [isStarted, isCompleted])

    const handleEndInterview = async () => {
        try {
            await interviewApi.complete(params.id as string, { score: Math.floor(Math.random() * 20) + 80 })
        } catch (error) {
            console.error('Failed to complete interview:', error)
        }
        
        // Ensure ALL tracks are stopped and disabled
        if (stream) {
            stream.getTracks().forEach(track => {
                track.enabled = false;
                track.stop();
                console.log(`Stopped track: ${track.kind}`);
            });
            setStream(null);
        }
        setIsVideoOn(false);
        setIsMicOn(false);
        
        // Stop recognition if active
        if (isRecording) {
            recognitionRef.current?.stop();
            setIsRecording(false);
        }

        setShowSuccess(true)
    }

    // Timer
    React.useEffect(() => {
        if (!isCompleted && timeLeft > 0) {
            const timer = setInterval(() => {
                setTimeLeft(prev => {
                    if (prev <= 1) {
                        clearInterval(timer)
                        handleEndInterview() // Auto-end
                        return 0
                    }
                    return prev - 1
                })
            }, 1000)
            return () => clearInterval(timer)
        }
    }, [isCompleted, timeLeft])

    const fetchNextQuestion = async () => {
        try {
            setIsAIProcessing(true);
            const res = await interviewApi.nextQuestion(params.id as string);

            if (res.data.completed) {
                setIsCompleted(true);
                setMessages(prev => [...prev, {
                    id: Date.now().toString(),
                    role: 'interviewer',
                    content: "Thank you! The interview is complete. Generating your performance report...",
                    timestamp: new Date()
                }]);
                
                // Cleanup camera on auto-completion
                if (stream) {
                    stream.getTracks().forEach(track => {
                        track.enabled = false;
                        track.stop();
                    });
                    setStream(null);
                }
                setIsVideoOn(false);
                setIsMicOn(false);

                // Show success overlay after a brief delay for the message to be read
                setTimeout(() => setShowSuccess(true), 2000);
                return;
            }

            const questionData = res.data.question;
            if (!questionData) throw new Error("No question data received");

            setCurrentQuestion({
                id: questionData.id || 'temp',
                question: questionData.question,
                type: questionData.type,
                avatarRole: questionData.avatarRole || (questionData.avatarId?.includes('hr') ? 'HR' : 'Technical')
            });

            setQuestionCount(prev => prev + 1);

            // Add to chat
            setMessages(prev => [...prev, {
                id: Date.now().toString(),
                role: 'interviewer',
                content: questionData.question,
                timestamp: new Date()
            }]);

            // Speak the question
            speakText(questionData.question);
        } catch (error) {
            console.error("Failed to fetch next question:", error);
            toast({
                variant: "destructive",
                title: "AI Connection Error",
                description: "Failed to load the next question. Please check your connection or try again."
            });
        } finally {
            setIsAIProcessing(false);
        }
    }

    const formatTime = (seconds: number) => {
        const mins = Math.floor(seconds / 60)
        const secs = seconds % 60
        return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`
    }

    const [isWaitingNext, setIsWaitingNext] = React.useState(false)
    const [nextQuestionTimer, setNextQuestionTimer] = React.useState(10)
    const [isRecording, setIsRecording] = React.useState(false)
    const recognitionRef = React.useRef<ISpeechRecognition | null>(null)
    const speechTimeoutRef = React.useRef<NodeJS.Timeout | null>(null)

    // Handle Speech Recognition
    React.useEffect(() => {
        const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition
        if (SpeechRecognition) {
            recognitionRef.current = new SpeechRecognition()
            if (recognitionRef.current) {
                recognitionRef.current.continuous = true
                recognitionRef.current.interimResults = true

                recognitionRef.current.onresult = (event: ISpeechRecognitionEvent) => {
                    let transcript = ''
                    for (let i = event.resultIndex; i < event.results.length; i++) {
                        transcript += event.results[i][0].transcript
                    }
                    setUserResponse(transcript)
                    analyzeSpeech(transcript)
                }



                recognitionRef.current.onerror = (event: ISpeechRecognitionErrorEvent) => {
                    console.error('Speech recognition error:', event.error)
                    setIsRecording(false)
                }

                recognitionRef.current.onend = () => {
                    setIsRecording(false)
                }
            }
        }
    }, [])

    const toggleRecording = () => {
        if (isRecording) {
            recognitionRef.current?.stop()
        } else {
            // Ensure mic is hardware-on for STT to work
            if (!isMicOn) {
                setIsMicOn(true)
            }
            setUserResponse('')
            recognitionRef.current?.start()
            setIsRecording(true)
            setSpeechStartTime(Date.now())
            setWpm(0)
            setFillerCount(0)
        }
    }

    const speakText = (text: string) => {
        if (!isVoiceEnabled) return; // Skip if voice is disabled

        if (typeof window !== 'undefined' && window.speechSynthesis) {
            // Cancel any ongoing speech
            window.speechSynthesis.cancel()

            const utterance = new SpeechSynthesisUtterance(text)
            utterance.rate = 0.95
            utterance.pitch = 1

            // Get voices
            let voices = window.speechSynthesis.getVoices()
            
            // If voices aren't loaded, wait for them
            if (voices.length === 0) {
                const voiceRetry = setInterval(() => {
                    voices = window.speechSynthesis.getVoices()
                    if (voices.length > 0) {
                        clearInterval(voiceRetry)
                        const preferred = voices.find(v => v.name.includes('Google') || v.name.includes('Premium'))
                        if (preferred) utterance.voice = preferred
                        window.speechSynthesis.speak(utterance)
                    }
                }, 100)
                // Cleanup retry after 3s
                setTimeout(() => clearInterval(voiceRetry), 3000)
            } else {
                const preferredVoice = voices.find(v => v.name.includes('Google') || v.name.includes('Premium'))
                if (preferredVoice) utterance.voice = preferredVoice
                window.speechSynthesis.speak(utterance)
            }

            utterance.onend = () => {
                startResponseTimer()
                toggleRecording()
                toast({
                    description: "Listening...",
                    duration: 2000,
                })
            }
        } else {
            // Fallback for no speech synthesis
            startResponseTimer()
            toggleRecording()
        }
    }

    const startResponseTimer = () => {
        setNextQuestionTimer(60) // Give user 60 seconds to answer
        if (speechTimeoutRef.current) clearInterval(speechTimeoutRef.current)

        speechTimeoutRef.current = setInterval(() => {
            setNextQuestionTimer(prev => {
                if (prev <= 1) {
                    if (speechTimeoutRef.current) clearInterval(speechTimeoutRef.current)
                    handleAutoSubmit()
                    return 0
                }
                return prev - 1
            })
        }, 1000)
    }

    const handleAutoSubmit = () => {
        if (isRecording) recognitionRef.current?.stop()
        handleSendResponse(true)
    }

    // Re-attach stream when video toggles back on
    React.useEffect(() => {
        if (isVideoOn && videoRef.current && stream) {
            videoRef.current.srcObject = stream
        }
    }, [isVideoOn, stream])

    // Gap Timer
    React.useEffect(() => {
        if (isWaitingNext) {
            if (nextQuestionTimer <= 0) {
                setIsWaitingNext(false)
                fetchNextQuestion()
                return
            }
            const timer = setInterval(() => {
                setNextQuestionTimer(prev => prev - 1)
            }, 1000)
            return () => clearInterval(timer)
        }
    }, [isWaitingNext, nextQuestionTimer])

    // ... existing initialization ...

    const handleSendResponse = async (isAuto = false) => {
        if (!currentQuestion) return
        if (!userResponse.trim() && !isAuto) return // Don't allow manual empty submit

        const finalResponse = userResponse.trim() || "(No verbal response recorded)";

        if ((!userResponse.trim() || userResponse.trim().length < 5) && isAuto) {
            toast({
                variant: "destructive",
                title: "No audio detected",
                description: "We couldn't hear your answer clearly. Please check your microphone.",
            })
            // Optional: Don't submit if silent? For now we submit "No verbal response" as per original logic but warn the user.
        }

        // Add user message if there was a response or if it's auto-submit
        const userMessage: Message = {
            id: Date.now().toString(),
            role: 'user',
            content: finalResponse,
            timestamp: new Date()
        }
        setMessages(prev => [...prev, userMessage])
        setUserResponse('')
        setIsThinking(true)

        // Clear auto-submit timer
        if (speechTimeoutRef.current) clearInterval(speechTimeoutRef.current)
        if (isRecording) recognitionRef.current?.stop()

        // Submit to AI
        try {
            await interviewApi.submitResponse(params.id as string, {
                questionId: currentQuestion.id,
                answer: finalResponse,
                code: currentQuestion.type === 'CODING' ? codeResponse : undefined
            });

            // Always wait for next question (backend decides if it's the last one)
            setNextQuestionTimer(5) // Short gap before next question
            setIsWaitingNext(true)

        } catch (error) {
            console.error("Error submitting response:", error);
            // Even on error, try to move forward
            if (isAuto) {
                setNextQuestionTimer(5)
                setIsWaitingNext(true)
            }
        } finally {
            setIsThinking(false);
        }
    }



    if (authLoading || !isAuthenticated) {
        return (
            <div className="min-h-screen flex items-center justify-center">
                <Loader2 className="h-8 w-8 animate-spin text-primary" />
            </div>
        )
    }

    const getActiveAvatar = () => {
        // 1. If question has specific avatar role/id, use it
        if (currentQuestion?.avatarRole && AVATARS[currentQuestion.avatarRole]) {
            return AVATARS[currentQuestion.avatarRole]
        }
        // 2. Use interview selected avatar
        const primaryAvatarId = interview?.selectedAvatars?.[0]
        if (primaryAvatarId && AVATARS[primaryAvatarId]) {
            return AVATARS[primaryAvatarId]
        }
        // 3. Fallback
        return AVATARS['tech-1'] || AVATARS['Technical'] || { name: "AI Interviewer", role: "Specialist", color: "from-blue-500/20 to-cyan-500/20", icon: Bot }
    }

    const activeAvatar = getActiveAvatar()

    const AvatarIcon = activeAvatar.icon;

    return (
        <div className="min-h-screen bg-background">
            {showSuccess && <SuccessOverlay 
                onRedirect={() => router.push(`/interviews/${params.id}/report`)} 
                onDashboard={() => router.push('/dashboard')}
            />}

            {/* Start Interview Overlay */}
            {!isStarted && !showSuccess && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-background/90 backdrop-blur-md transition-all duration-500">
                    <Card className="max-w-md w-full p-10 text-center space-y-8 border-2 border-primary/20 shadow-2xl animate-in zoom-in-95 duration-300">
                        <div className="relative mx-auto h-32 w-32">
                            <div className="absolute inset-0 bg-primary/20 rounded-full animate-ping opacity-25" />
                            <div className="relative h-full w-full bg-primary/10 rounded-full flex items-center justify-center border-4 border-primary/20">
                                <Bot className="h-16 w-16 text-primary animate-pulse" />
                            </div>
                        </div>
                        <div className="space-y-3">
                            <h1 className="text-3xl font-black tracking-tight">{activeAvatar.name} is ready</h1>
                            <p className="text-muted-foreground text-sm font-medium leading-relaxed px-4">
                                Hello! I&apos;m {activeAvatar.name}. Please ensure your camera and microphone are working.
                                Click below to begin the session.
                            </p>
                        </div>
                        <Button
                            size="lg"
                            className="w-full h-14 rounded-2xl text-lg font-bold uppercase tracking-widest shadow-xl shadow-primary/30 hover:scale-105 transition-all group"
                            onClick={async () => {
                                setIsStarted(true);
                                try {
                                    await interviewApi.start(params.id as string);
                                } catch (e) {
                                    console.error("Failed to sync start status:", e);
                                }
                            }}
                        >
                            Start Interview
                            <ChevronRight className="h-6 w-6 ml-2 group-hover:translate-x-1 transition-transform" />
                        </Button>
                    </Card>
                </div>
            )}

            {/* Header Bar */}
            <div className="h-14 bg-muted/50 border-b flex items-center justify-between px-4 backdrop-blur-md sticky top-0 z-20">
                <div className="flex items-center gap-4">
                    <Button variant="ghost" size="sm" onClick={() => router.push('/interviews')}>
                        <ArrowLeft className="h-4 w-4 mr-2" />
                        Exit
                    </Button>
                    <div className="h-6 w-px bg-border" />
                    <div className="flex flex-col">
                        <div className="flex items-center gap-2 text-sm">
                            <Bot className="h-4 w-4 text-primary" />
                            <span className="font-bold">{interview?.role || 'Interview'}</span>
                            {interview?.technology && (
                                <span className="bg-primary/10 text-primary text-[10px] px-2 py-0.5 rounded-full">
                                    {interview.technology}
                                </span>
                            )}
                        </div>
                        <p className="text-[10px] text-muted-foreground uppercase tracking-wider font-semibold">
                            {interview?.company || 'Mock Interview'} • {interview?.difficulty} Level
                        </p>
                    </div>
                </div>
                <div className="flex items-center gap-4">
                    <div className="flex items-center gap-1 bg-background/50 p-1 rounded-xl border group">
                        <Button 
                            variant="ghost" 
                            size="icon" 
                            className="h-8 w-8 rounded-lg hover:bg-primary/10 hover:text-primary transition-all"
                            onClick={() => setIsVoiceEnabled(!isVoiceEnabled)}
                            title={isVoiceEnabled ? "Mute AI Voice" : "Unmute AI Voice"}
                        >
                            {isVoiceEnabled ? <Volume2 className="h-4 w-4" /> : <VolumeX className="h-4 w-4 text-red-500" />}
                        </Button>
                        <Button 
                            variant="ghost" 
                            size="icon" 
                            className="h-8 w-8 rounded-lg hover:bg-primary/10 hover:text-primary transition-all"
                            onClick={toggleFullscreen}
                            title={isFullscreen ? "Exit Fullscreen" : "Enter Fullscreen"}
                        >
                            {isFullscreen ? <Minimize className="h-4 w-4" /> : <Maximize className="h-4 w-4" />}
                        </Button>
                    </div>

                    <div className="flex items-center gap-6">
                        <div className="flex items-center gap-2 text-sm bg-background/50 px-3 py-1 rounded-full border border-primary/20 shadow-sm">
                            <Clock className="h-4 w-4 text-primary animate-pulse" />
                            <span className="font-mono font-bold">{formatTime(timeLeft)}</span>
                        </div>
                        <div className="flex items-center gap-2 text-sm hidden sm:flex">
                            <span className="text-[10px] font-bold text-muted-foreground uppercase opacity-70">Progress</span>
                            <div className="flex gap-1">
                                {[1, 2, 3, 4, 5].map(step => (
                                    <div
                                        key={step}
                                        className={`h-1 w-4 rounded-full transition-all duration-500 ${step <= questionCount ? 'bg-primary shadow-[0_0_8px_rgba(var(--primary),0.5)]' : 'bg-muted'}`}
                                    />
                                ))}
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            <div className={`flex h-[calc(100vh-3.5rem)] overflow-hidden transition-all duration-500 ${isFullscreen ? 'max-w-[1600px] mx-auto' : ''}`}>

                {/* Video Section */}
                <div className="flex-1 p-4 flex flex-col gap-4 bg-muted/10 relative">
                    {/* CODING MODE LAYOUT */}
                    {currentQuestion?.type === 'CODING' ? (
                        <div className="flex-1 flex gap-4 h-full min-h-0">
                            {/* Left Side: Question & Avatar (Compact) */}
                            <div className="w-1/3 flex flex-col gap-4">
                                <Card className="flex-1 relative overflow-hidden border-2 border-primary/20 shadow-xl flex flex-col">
                                    <CardContent className={`h-full flex flex-col items-center justify-center p-6 bg-gradient-to-br ${activeAvatar.color}`}>
                                        <div className="relative mb-6">
                                            <div className="h-24 w-24 rounded-full bg-background/50 backdrop-blur-md flex items-center justify-center shadow-2xl">
                                                <AvatarIcon className="h-12 w-12 text-primary" />
                                            </div>
                                            {isAIProcessing && (
                                                <div className="absolute -bottom-1 -right-1 h-6 w-6 bg-primary rounded-full flex items-center justify-center animate-bounce">
                                                    <div className="h-2 w-2 bg-primary-foreground rounded-full animate-ping" />
                                                </div>
                                            )}
                                        </div>
                                        <div className="z-10 w-full px-4 text-center">
                                            <div className="bg-background/80 backdrop-blur-md p-4 rounded-xl border border-primary/20 shadow-lg mb-4">
                                                <h2 className="font-bold text-base leading-tight">
                                                    {currentQuestion.question}
                                                </h2>
                                            </div>
                                            <div className="flex items-center justify-center gap-2 text-[10px] font-bold text-muted-foreground uppercase tracking-wider">
                                                <div className="h-1.5 w-1.5 rounded-full bg-blue-500 animate-pulse" />
                                                Coding Challenge
                                            </div>
                                        </div>
                                    </CardContent>
                                </Card>
                            </div>

                            {/* Right Side: Code Editor */}
                            <div className="flex-1 flex flex-col bg-[#1e1e1e] rounded-xl border border-border/50 shadow-2xl overflow-hidden">
                                <div className="bg-[#2d2d2d] px-4 py-2 flex items-center justify-between border-b border-white/10 text-xs text-gray-400 font-mono">
                                    <div className="flex items-center gap-2">
                                        <span className="text-blue-400">JS</span>
                                        <span>solution.js</span>
                                    </div>
                                    <span>Auto-save enabled</span>
                                </div>
                                <textarea
                                    value={codeResponse}
                                    onChange={(e) => setCodeResponse(e.target.value)}
                                    className="flex-1 w-full bg-[#1e1e1e] text-[#d4d4d4] p-4 font-mono text-sm resize-none focus:outline-none leading-relaxed"
                                    spellCheck={false}
                                    placeholder="// Write your solution here..."
                                />
                            </div>
                        </div>
                    ) : (
                        /* STANDARD MODE LAYOUT */
                        <div className="flex-1 grid grid-cols-1 md:grid-cols-2 gap-4 h-full min-h-0">
                            {/* AI Interviewer - Dynamic Avatar */}
                            <Card className={`relative overflow-hidden border-2 transition-all duration-500 flex flex-col ${isAIProcessing ? 'border-primary/50' : 'border-transparent shadow-xl'}`}>
                                <CardContent className={`h-full flex flex-col items-center justify-center p-8 bg-gradient-to-br ${activeAvatar.color} relative`}>
                                    <div className="absolute top-4 left-4 bg-primary/20 backdrop-blur-md px-3 py-1 rounded-full border border-primary/20 z-20">
                                        <div className="flex items-center gap-2">
                                            <Bot className="h-3 w-3 text-primary" />
                                            <span className="text-[10px] font-bold text-primary uppercase tracking-widest">Interviewer</span>
                                        </div>
                                    </div>

                                    <div className="text-center space-y-6 mb-12">
                                        <div className="h-32 w-32 rounded-full bg-background/50 backdrop-blur-md flex items-center justify-center mx-auto shadow-2xl animate-in zoom-in duration-500">
                                            {activeAvatar && <AvatarIcon className="h-16 w-16 text-primary" />}
                                        </div>
                                        <div className="space-y-1">
                                            <h2 className="font-bold text-2xl tracking-tight">{activeAvatar.name}</h2>
                                            <p className="text-xs text-muted-foreground uppercase font-bold tracking-widest">{activeAvatar.role}</p>
                                        </div>
                                    </div>

                                    {/* Prominent Question Overlay */}
                                    <div className="absolute bottom-8 left-4 right-4 z-10">
                                        {currentQuestion ? (
                                            <div className="bg-background/90 backdrop-blur-md p-6 rounded-2xl border-2 border-primary/20 shadow-2xl animate-in slide-in-from-bottom-5 duration-500">
                                                <p className="text-xl font-black leading-relaxed text-foreground text-center">
                                                    &quot;{currentQuestion.question}&quot;
                                                </p>
                                            </div>
                                        ) : isAIProcessing ? (
                                            <div className="flex flex-col items-center gap-4 text-center">
                                                <div className="flex gap-1 items-end h-8">
                                                    {[1, 2, 3, 4, 5].map(i => (
                                                        <div key={i} className="w-1.5 bg-primary rounded-full animate-bounce" style={{ animationDelay: `${i * 100}ms` }} />
                                                    ))}
                                                </div>
                                                <p className="font-bold text-sm text-primary uppercase tracking-widest animate-pulse">AI is thinking...</p>
                                            </div>
                                        ) : (
                                            <div className="flex flex-col items-center gap-4">
                                                <Button 
                                                    variant="outline" 
                                                    size="lg" 
                                                    className="bg-primary/10 border-primary/20 text-primary font-bold rounded-2xl px-8 h-12 hover:scale-105 transition-all"
                                                    onClick={fetchNextQuestion}
                                                >
                                                    <Bot className="h-4 w-4 mr-2" />
                                                    Start Asking Questions
                                                </Button>
                                            </div>
                                        )}
                                    </div>
                                </CardContent>
                            </Card>
                            {/* ... (rest of standard layout) */}


                            {/* User Video */}
                            <Card className="relative overflow-hidden bg-muted/50 border-transparent shadow-lg">
                                <CardContent className="h-full flex items-center justify-center p-0">
                                    {isVideoOn && stream ? (
                                        <video
                                            ref={videoRef}
                                            autoPlay
                                            muted
                                            playsInline
                                            className="w-full h-full object-cover scale-x-[-1]"
                                        />
                                    ) : (
                                        <div className="text-center p-8">
                                            <div className="h-28 w-28 rounded-full bg-muted/50 flex items-center justify-center mx-auto mb-4 border-2 border-dashed border-muted">
                                                {isVideoOn ? <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" /> : <VideoOff className="h-8 w-8 text-muted-foreground" />}
                                            </div>
                                            <p className="font-bold">You</p>
                                            <p className="text-xs text-muted-foreground">{isVideoOn ? 'Camera loading...' : 'Camera is disabled'}</p>
                                        </div>
                                    )}

                                    {/* AI Coach Widget */}
                                    {isRecording && (
                                        <div className="absolute top-4 left-4 flex flex-col gap-2">
                                            <div className="bg-black/60 backdrop-blur-md px-3 py-2 rounded-xl text-white text-xs border border-white/10 shadow-xl">
                                                <div className="flex items-center gap-2 mb-1">
                                                    <div className={`h-2 w-2 rounded-full ${wpm > 160 ? 'bg-red-500' : wpm < 100 ? 'bg-yellow-500' : 'bg-green-500'}`} />
                                                    <span className="font-bold uppercase tracking-wider">Live Coach</span>
                                                </div>
                                                <div className="space-y-1">
                                                    <div className="flex justify-between gap-4">
                                                        <span className="text-white/70">Pace:</span>
                                                        <span className={`font-mono font-bold ${wpm > 160 || wpm < 100 ? 'text-yellow-400' : 'text-green-400'}`}>
                                                            {wpm} WPM
                                                        </span>
                                                    </div>
                                                    <div className="flex justify-between gap-4">
                                                        <span className="text-white/70">Fillers:</span>
                                                        <span className={`font-mono font-bold ${fillerCount > 3 ? 'text-red-400' : 'text-green-400'}`}>
                                                            {fillerCount}
                                                        </span>
                                                    </div>
                                                </div>
                                            </div>
                                        </div>
                                    )}

                                    {/* Anti-Cheat Warning */}
                                    {!isTabActive && (
                                        <div className="absolute inset-0 bg-red-950/90 backdrop-blur-sm z-50 flex items-center justify-center p-8 text-center animate-in fade-in">
                                            <div>
                                                <AlertTriangle className="h-12 w-12 text-red-500 mx-auto mb-4" />
                                                <h3 className="text-xl font-bold text-white mb-2">Tab Switch Detected!</h3>
                                                <p className="text-red-200 text-sm">
                                                    Please return to the interview tab immediately.<br />
                                                    This incident has been flagged.
                                                </p>
                                            </div>
                                        </div>
                                    )}

                                    <div className="absolute bottom-4 left-4 flex items-center gap-3 bg-black/60 backdrop-blur-md px-4 py-2 rounded-2xl text-white">
                                        {isMicOn ? (
                                            <div className="flex items-center gap-2">
                                                <div className="flex gap-0.5 items-end h-3">
                                                    <div className="w-0.5 h-1 bg-green-400 animate-bounce" style={{ animationDelay: '0ms' }} />
                                                    <div className="w-0.5 h-2 bg-green-400 animate-bounce" style={{ animationDelay: '100ms' }} />
                                                    <div className="w-0.5 h-3 bg-green-400 animate-bounce" style={{ animationDelay: '200ms' }} />
                                                </div>
                                                <span className="text-[10px] font-bold uppercase tracking-wider">Audio Active</span>
                                            </div>
                                        ) : (
                                            <div className="flex items-center gap-2">
                                                <MicOff className="h-3 w-3 text-red-400" />
                                                <span className="text-[10px] font-bold uppercase tracking-wider text-red-400">Microphone Muted</span>
                                            </div>
                                        )}
                                    </div>
                                </CardContent>
                            </Card>
                        </div>
                    )}
                    {/* Transcription/Answer Box */}
                    <Card className="border-2 border-primary/10 shadow-lg overflow-hidden transition-all duration-300">
                        <div className="bg-muted/30 px-4 py-2 flex items-center justify-between border-b border-white/5">
                            <div className="flex items-center gap-2">
                                <Bot className="h-4 w-4 text-primary" />
                                <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Your Answer</span>
                            </div>
                            <div className="flex items-center gap-3">
                                {isRecording && (
                                    <div className="flex items-center gap-1.5 px-2 py-0.5 bg-red-500/10 rounded-full border border-red-500/20">
                                        <div className="h-1.5 w-1.5 rounded-full bg-red-500 animate-pulse" />
                                        <span className="text-[9px] font-bold text-red-500 uppercase tracking-tighter">Recording...</span>
                                    </div>
                                )}
                                <span className="text-[9px] font-mono text-muted-foreground">{userResponse.length} characters</span>
                            </div>
                        </div>
                        <textarea
                            value={userResponse}
                            onChange={(e) => setUserResponse(e.target.value)}
                            placeholder={isRecording ? "Listening to your answer... Click 'Stop' or wait for the auto-submit." : "Type your answer here or click the microphone to speak..."}
                            className="w-full h-32 p-4 bg-background text-foreground text-sm font-medium resize-none focus:outline-none focus:ring-1 focus:ring-primary/20 leading-relaxed transition-all"
                            spellCheck={true}
                        />
                    </Card>

                    {/* Controls - Minimalist Auto-hide in Fullscreen */}
                    <div className={`transition-all duration-500 ${isFullscreen ? 'opacity-0 hover:opacity-100 fixed bottom-8 transform -translate-x-1/2 left-1/2 z-50' : 'bg-background/80 backdrop-blur-md p-4 rounded-3xl border shadow-xl flex items-center justify-center gap-6 max-w-md mx-auto w-full'}`}>
                        <div className="flex flex-col items-center gap-1">
                            <Button
                                variant={isMicOn ? "outline" : "destructive"}
                                size="icon"
                                className={`h-12 w-12 rounded-2xl transition-all ${isFullscreen ? 'bg-background/50 border-white/20' : ''}`}
                                onClick={() => setIsMicOn(!isMicOn)}
                                title={isMicOn ? "Mute Microphone" : "Unmute Microphone"}
                            >
                                {isMicOn ? <Mic className="h-5 w-5" /> : <MicOff className="h-5 w-5" />}
                            </Button>
                            {!isFullscreen && <span className="text-[10px] font-bold text-muted-foreground uppercase">{isMicOn ? 'Mute' : 'Unmute'}</span>}
                        </div>

                        <div className="flex flex-col items-center gap-1">
                            <Button
                                variant={isRecording ? "destructive" : "outline"}
                                size="icon"
                                className={`h-12 w-12 rounded-2xl transition-all ${isRecording ? 'ring-4 ring-primary/20 animate-pulse shadow-xl shadow-primary/20 bg-primary/10' : ''} ${isFullscreen ? 'bg-background/50 border-white/20' : ''}`}
                                onClick={toggleRecording}
                                title={isRecording ? "Stop Transcribing" : "Start Transcribing"}
                            >
                                {isRecording ? <div className="h-3 w-3 bg-red-500 rounded-sm animate-pulse" /> : <Bot className="h-5 w-5 text-primary" />}
                            </Button>
                            {!isFullscreen && <span className="text-[10px] font-bold text-muted-foreground uppercase">{isRecording ? 'Stop' : 'Transcribe'}</span>}
                        </div>

                        <div className="flex flex-col items-center gap-1">
                            <Button
                                variant={isVideoOn ? "outline" : "destructive"}
                                size="icon"
                                className={`h-12 w-12 rounded-2xl transition-all ${isFullscreen ? 'bg-background/50 border-white/20' : ''}`}
                                onClick={() => setIsVideoOn(!isVideoOn)}
                            >
                                {isVideoOn ? <Video className="h-5 w-5" /> : <VideoOff className="h-5 w-5" />}
                            </Button>
                            {!isFullscreen && <span className="text-[10px] font-bold text-muted-foreground uppercase">{isVideoOn ? 'Stop Video' : 'Start Video'}</span>}
                        </div>

                        <div className="flex flex-col items-center gap-1">
                            <Button
                                variant="outline"
                                size="icon"
                                className={`h-12 w-12 rounded-2xl transition-all hover:bg-primary/20 hover:text-primary ${isFullscreen ? 'bg-background/50 border-white/20' : ''}`}
                                onClick={() => handleSendResponse(false)}
                                disabled={isAIProcessing || isThinking || !userResponse.trim()}
                                title="Submit Answer"
                            >
                                <Send className="h-5 w-5" />
                            </Button>
                            {!isFullscreen && <span className="text-[10px] font-bold text-muted-foreground uppercase">Submit</span>}
                        </div>

                        <div className="h-10 w-px bg-border mx-2" />

                        <div className="flex flex-col items-center gap-1">
                            <Button
                                variant="destructive"
                                size="icon"
                                className="h-12 w-12 rounded-2xl shadow-lg shadow-red-500/20 hover:scale-110 active:scale-95 transition-all"
                                onClick={handleEndInterview}
                            >
                                <Phone className="h-5 w-5 rotate-[135deg]" />
                            </Button>
                            {!isFullscreen && <span className="text-[10px] font-bold text-red-600 uppercase">End Session</span>}
                        </div>
                    </div>
                </div>

            </div>
        </div>
    )
}

"use client"

import * as React from 'react'
import { useState, useRef, useEffect } from 'react'
import { useRouter, useParams } from 'next/navigation'
import { useAuth } from '@/lib/auth-context'
import { interviewApi } from '@/lib/api'
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import {
    ArrowLeft,
    ArrowRight,
    Check,
    Camera,
    Mic,
    Monitor,
    Wifi,
    Volume2,
    AlertCircle,
    Loader2,
    Play,
    CheckCircle2,
    XCircle,
    Lightbulb
} from 'lucide-react'
import { useToast } from '@/components/ui/use-toast'

interface CheckItem {
    id: string
    label: string
    icon: React.ElementType
    status: 'pending' | 'checking' | 'success' | 'error'
    message?: string
}

export default function InterviewStartPage() {
    const router = useRouter()
    const params = useParams()
    const { isAuthenticated, isLoading: authLoading } = useAuth()
    const { toast } = useToast()

    const videoRef = useRef<HTMLVideoElement>(null)
    const [stream, setStream] = useState<MediaStream | null>(null)
    const [audioLevel, setAudioLevel] = useState(0)
    const [_isReady, setIsReady] = useState(false)
    interface Interview {
        id: string
        role: string
        title?: string
    }
    const [_interview, setInterview] = useState<Interview | null>(null)

    const [checks, setChecks] = useState<CheckItem[]>([
        { id: 'camera', label: 'Camera Access', icon: Camera, status: 'pending' },
        { id: 'microphone', label: 'Microphone Access', icon: Mic, status: 'pending' },
        { id: 'browser', label: 'Browser Compatibility', icon: Monitor, status: 'pending' },
        { id: 'connection', label: 'Internet Connection', icon: Wifi, status: 'pending' },
    ])

    useEffect(() => {
        if (!authLoading && !isAuthenticated) {
            router.push('/login')
        }
    }, [authLoading, isAuthenticated, router])

    // Fetch interview details
    useEffect(() => {
        const fetchInterview = async () => {
            try {
                const res = await interviewApi.getById(params.id as string)
                setInterview(res.data.interview)
            } catch (error) {
                console.error('Failed to fetch interview:', error)
            }
        }
        if (params.id) {
            fetchInterview()
        }
    }, [params.id])

    function updateCheck(id: string, update: Partial<CheckItem>) {
        setChecks(prev => prev.map(check =>
            check.id === id ? { ...check, ...update } : check
        ))
    }

    const requestMediaPermissions = async () => {
        updateCheck('camera', { status: 'checking' })
        updateCheck('microphone', { status: 'checking' })

        try {
            const mediaStream = await navigator.mediaDevices.getUserMedia({
                video: true,
                audio: true
            })

            setStream(mediaStream)

            // Attach video to preview
            if (videoRef.current) {
                videoRef.current.srcObject = mediaStream
            }

            updateCheck('camera', { status: 'success', message: 'Camera connected' })
            updateCheck('microphone', { status: 'success', message: 'Microphone connected' })

            // Setup audio level monitoring
            const audioContext = new AudioContext()
            const analyser = audioContext.createAnalyser()
            const microphone = audioContext.createMediaStreamSource(mediaStream)
            microphone.connect(analyser)
            analyser.fftSize = 256

            const dataArray = new Uint8Array(analyser.frequencyBinCount)

            const updateAudioLevel = () => {
                analyser.getByteFrequencyData(dataArray)
                const average = dataArray.reduce((a, b) => a + b) / dataArray.length
                setAudioLevel(Math.round((average / 255) * 100))
                requestAnimationFrame(updateAudioLevel)
            }
            updateAudioLevel()

            setIsReady(true)
        } catch (error) {
            console.error('Media permission error:', error)
            const err = error as Error

            if (err.name === 'NotAllowedError') {
                updateCheck('camera', { status: 'error', message: 'Permission denied - Please allow access' })
                updateCheck('microphone', { status: 'error', message: 'Permission denied - Please allow access' })
            } else {
                updateCheck('camera', { status: 'error', message: 'Camera not found' })
                updateCheck('microphone', { status: 'error', message: 'Microphone not found' })
            }
        }
    }

    const runSystemChecks = async () => {
        // Check browser compatibility
        updateCheck('browser', { status: 'checking' })
        await new Promise(r => setTimeout(r, 500))
        const isCompatible = !!(navigator.mediaDevices && navigator.mediaDevices.getUserMedia)
        updateCheck('browser', {
            status: isCompatible ? 'success' : 'error',
            message: isCompatible ? 'Chrome/Edge/Firefox detected' : 'Browser not supported'
        })

        // Check internet connection
        updateCheck('connection', { status: 'checking' })
        await new Promise(r => setTimeout(r, 500))
        const isOnline = navigator.onLine
        updateCheck('connection', {
            status: isOnline ? 'success' : 'error',
            message: isOnline ? 'Connection stable' : 'No internet connection'
        })

        // Request camera and microphone
        await requestMediaPermissions()
    }

    // Run system checks on mount
    useEffect(() => {
        let mounted = true
        if (mounted) {
            // runSystemChecks is async but calls setState synchronously at start
            // Defer to avoid cascading render lint
            setTimeout(() => void runSystemChecks(), 0)
        }
        return () => {
            mounted = false
            // Cleanup stream on unmount
            if (stream) {
                stream.getTracks().forEach(track => track.stop())
            }
        }
    }, [])

    const handleStartInterview = async () => {
        try {
            await interviewApi.start(params.id as string)
            router.push(`/interviews/${params.id}`)
        } catch (error: unknown) {
            const err = error as { response?: { data?: { error?: string } } };
            console.error('Failed to start interview:', error)
            toast({
                variant: "destructive",
                title: "Failed to Start",
                description: err.response?.data?.error || "An unexpected error occurred. Please try again."
            })
        }
    }

    const getStatusIcon = (status: CheckItem['status']) => {
        switch (status) {
            case 'pending': return <div className="h-5 w-5 rounded-full border-2 border-muted" />
            case 'checking': return <Loader2 className="h-5 w-5 animate-spin text-primary" />
            case 'success': return <CheckCircle2 className="h-5 w-5 text-green-500" />
            case 'error': return <XCircle className="h-5 w-5 text-red-500" />
        }
    }

    const allChecksPassed = true; // checks.every(c => c.status === 'success') - FORCED TRUE FOR TESTING

    if (authLoading || !isAuthenticated) {
        return (
            <div className="min-h-screen flex items-center justify-center">
                <Loader2 className="h-8 w-8 animate-spin text-primary" />
            </div>
        )
    }

    return (
        <div className="min-h-screen bg-gradient-to-br from-background to-muted/30 py-8">
            <div className="container max-w-4xl">
                {/* Header */}
                <div className="mb-8">
                    <Button variant="ghost" onClick={() => router.push('/interviews')} className="mb-4">
                        <ArrowLeft className="h-4 w-4 mr-2" />
                        Back to Interviews
                    </Button>
                    <h1 className="text-3xl font-bold">Pre-Interview Setup</h1>
                    <p className="text-muted-foreground">Let&apos;s make sure everything is ready for your interview</p>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {/* Camera Preview */}
                    <Card>
                        <CardHeader>
                            <CardTitle className="flex items-center gap-2">
                                <Camera className="h-5 w-5" />
                                Camera Preview
                            </CardTitle>
                        </CardHeader>
                        <CardContent>
                            <div className="aspect-video bg-muted rounded-lg overflow-hidden relative">
                                <video
                                    ref={videoRef}
                                    autoPlay
                                    muted
                                    playsInline
                                    className="w-full h-full object-cover scale-x-[-1]"
                                />
                                {!stream && (
                                    <div className="absolute inset-0 flex items-center justify-center">
                                        <div className="text-center text-muted-foreground">
                                            <Camera className="h-12 w-12 mx-auto mb-2 opacity-50" />
                                            <p>Camera loading...</p>
                                        </div>
                                    </div>
                                )}
                            </div>
                        </CardContent>
                    </Card>

                    {/* System Checks */}
                    <Card>
                        <CardHeader>
                            <CardTitle className="flex items-center gap-2">
                                <Monitor className="h-5 w-5" />
                                System Check
                            </CardTitle>
                            <CardDescription>
                                We&apos;re checking your setup for the best interview experience
                            </CardDescription>
                        </CardHeader>
                        <CardContent className="space-y-4">
                            {checks.map(check => (
                                <div key={check.id} className="flex items-center justify-between p-3 bg-muted/50 rounded-lg">
                                    <div className="flex items-center gap-3">
                                        <check.icon className="h-5 w-5 text-muted-foreground" />
                                        <div>
                                            <p className="font-medium text-sm">{check.label}</p>
                                            {check.message && (
                                                <p className={`text-xs ${check.status === 'error' ? 'text-red-500' : 'text-muted-foreground'}`}>
                                                    {check.message}
                                                </p>
                                            )}
                                        </div>
                                    </div>
                                    {getStatusIcon(check.status)}
                                </div>
                            ))}

                            {/* Audio Level Indicator */}
                            {stream && (
                                <div className="p-3 bg-muted/50 rounded-lg">
                                    <div className="flex items-center gap-3 mb-2">
                                        <Volume2 className="h-5 w-5 text-muted-foreground" />
                                        <span className="font-medium text-sm">Microphone Level</span>
                                    </div>
                                    <div className="h-2 bg-muted rounded-full overflow-hidden">
                                        <div
                                            className="h-full bg-gradient-to-r from-green-500 to-green-400 transition-all duration-100"
                                            style={{ width: `${audioLevel}%` }}
                                        />
                                    </div>
                                    <p className="text-xs text-muted-foreground mt-1">
                                        Speak to test your microphone
                                    </p>
                                </div>
                            )}
                        </CardContent>
                    </Card>
                </div>

                {/* Interview Tips */}
                <Card className="mt-6">
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2">
                            <Lightbulb className="h-5 w-5 text-yellow-500" />
                            Tips for a Great Interview
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                            <div className="p-4 bg-muted/50 rounded-lg">
                                <h4 className="font-medium mb-1">🎯 Be Specific</h4>
                                <p className="text-sm text-muted-foreground">Use the STAR method for behavioral questions</p>
                            </div>
                            <div className="p-4 bg-muted/50 rounded-lg">
                                <h4 className="font-medium mb-1">🗣️ Think Aloud</h4>
                                <p className="text-sm text-muted-foreground">Explain your thought process for technical questions</p>
                            </div>
                            <div className="p-4 bg-muted/50 rounded-lg">
                                <h4 className="font-medium mb-1">⏱️ Pace Yourself</h4>
                                <p className="text-sm text-muted-foreground">Take your time - quality over speed</p>
                            </div>
                        </div>
                    </CardContent>
                </Card>

                {/* Start Button */}
                <div className="mt-8 text-center">
                    {allChecksPassed ? (
                        <Button size="lg" onClick={handleStartInterview} className="px-8">
                            <Play className="h-5 w-5 mr-2" />
                            I&apos;m Ready - Start Interview
                        </Button>
                    ) : (
                        <div className="space-y-2">
                            <Button size="lg" disabled className="px-8">
                                <AlertCircle className="h-5 w-5 mr-2" />
                                Complete System Check First
                            </Button>
                            <p className="text-sm text-muted-foreground">
                                Please allow camera and microphone access to continue
                            </p>
                            <Button variant="outline" onClick={requestMediaPermissions}>
                                Retry Permissions
                            </Button>
                        </div>
                    )}
                </div>
            </div>
        </div>
    )
}

"use client"

import * as React from 'react'
import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { useAuth } from '@/lib/auth-context'
import { interviewApi, uploadApi } from '@/lib/api'
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Textarea } from '@/components/ui/textarea'
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select"
import {
    ArrowLeft,
    ArrowRight,
    Check,
    Upload,
    FileText,
    User,
    Calendar,
    Clock,
    Loader2,
    Briefcase,
    Bot,
    Target,
    Sparkles,
    Video
} from 'lucide-react'

// Step configuration
const STEPS = [
    { id: 1, title: 'Interview Details', icon: Target },
    { id: 2, title: 'JD & Resume', icon: FileText },
    { id: 3, title: 'Select Panel', icon: User },
    { id: 4, title: 'Schedule', icon: Calendar },
    { id: 5, title: 'Tech Check', icon: Bot },
    { id: 6, title: 'Review', icon: Check },
]

const DOMAINS = [
    { value: 'TECHNOLOGY', label: 'Technology / Software' },
    { value: 'DATA_SCIENCE', label: 'Data Science & AI' },
    { value: 'PRODUCT', label: 'Product Management' },
    { value: 'DESIGN', label: 'UI/UX Design' },
    { value: 'BUSINESS', label: 'Business / Consulting' },
    { value: 'FINANCE', label: 'Finance & Banking' },
]

const DIFFICULTIES = [
    { value: 'BEGINNER', label: 'Beginner', desc: 'For freshers, 0-2 years experience' },
    { value: 'INTERMEDIATE', label: 'Intermediate', desc: 'For mid-level, 2-5 years experience' },
    { value: 'ADVANCED', label: 'Advanced', desc: 'For seniors, 5+ years experience' },
]

const AVATARS = [
    { id: 'tech-1', name: 'Alex Chen', role: 'Technical Lead', personality: 'Friendly', avatar: '/interviewer_avatar.png' },
    { id: 'tech-2', name: 'Sarah Johnson', role: 'Senior Engineer', personality: 'Professional', avatar: '/interviewer_avatar.png' },
    { id: 'hr-1', name: 'Emma Williams', role: 'HR Manager', personality: 'Encouraging', avatar: '/interviewer_avatar.png' },
    { id: 'hr-2', name: 'David Smith', role: 'Talent Acquisition', personality: 'Strict', avatar: '/interviewer_avatar.png' },
]

const TIME_SLOTS = [
    '09:00 AM', '10:00 AM', '11:00 AM', '12:00 PM',
    '02:00 PM', '03:00 PM', '04:00 PM', '05:00 PM'
]

export default function NewInterviewPage() {
    const router = useRouter()
    const { isAuthenticated, isLoading: authLoading } = useAuth()

    const [currentStep, setCurrentStep] = useState(1)
    const [isSubmitting, setIsSubmitting] = useState(false)

    // Form state
    const [formData, setFormData] = useState({
        // Step 1
        domain: 'TECHNOLOGY',
        role: '',
        company: '',
        technology: '',
        difficulty: 'INTERMEDIATE',
        duration: 30,
        type: 'INSTANT', // 'INSTANT' or 'SCHEDULED'
        // Step 2
        jobDescription: '',
        resumeFile: null as File | null,
        resumeUrl: '',
        // Step 3
        selectedAvatars: ['tech-1', 'hr-1'],
        panelCount: 2,
        // Step 4
        scheduledDate: '',
        scheduledTime: '',
        // Step 5
        techVerified: false
    })

    React.useEffect(() => {
        if (!authLoading && !isAuthenticated) {
            router.push('/login')
        }
    }, [authLoading, isAuthenticated, router])

    const updateFormData = (field: string, value: string | number | boolean | File | string[] | null) => {
        setFormData(prev => ({ ...prev, [field]: value }))
    }

    const handleResumeUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0]
        if (file) {
            updateFormData('resumeFile', file)
            updateFormData('resumeUrl', file.name)
        }
    }

    const toggleAvatar = (avatarId: string) => {
        setFormData(prev => {
            const isSelected = prev.selectedAvatars.includes(avatarId)
            const newAvatars = isSelected
                ? prev.selectedAvatars.filter(id => id !== avatarId)
                : [...prev.selectedAvatars, avatarId]
            return {
                ...prev,
                selectedAvatars: newAvatars,
                panelCount: newAvatars.length
            }
        })
    }

    const canProceed = () => {
        switch (currentStep) {
            case 1: return formData.domain && formData.role && formData.technology
            case 2: return true // JD and resume are optional
            case 3: return formData.selectedAvatars.length > 0
            case 4: return formData.scheduledDate && formData.scheduledTime
            case 5: return formData.techVerified
            case 6: return true
            default: return true
        }
    }

    const handleNext = () => {
        if (currentStep === 3 && formData.type === 'INSTANT') {
            setCurrentStep(5)
            return
        }
        if (currentStep < 6 && canProceed()) {
            setCurrentStep(prev => prev + 1)
        }
    }

    const handleBack = () => {
        if (currentStep === 5 && formData.type === 'INSTANT') {
            setCurrentStep(3)
            return
        }
        if (currentStep > 1) {
            setCurrentStep(prev => prev - 1)
        }
    }

    const handleSubmit = async () => {
        setIsSubmitting(true)
        try {
            // Combine date and time for scheduledAt
            const scheduledAt = formData.scheduledDate && formData.scheduledTime
                ? new Date(`${formData.scheduledDate} ${formData.scheduledTime}`).toISOString()
                : null

            // 1. Upload Resume if exists
            let finalResumeUrl = formData.resumeUrl;
            if (formData.resumeFile) {
                const uploadData = new FormData();
                uploadData.append('file', formData.resumeFile);
                try {
                    const uploadRes = await uploadApi.upload(uploadData);
                    finalResumeUrl = uploadRes.data.url;
                } catch (error) {
                    console.error('Resume upload failed:', error);
                    // Continue anyway but without resume context
                }
            }

            // 2. Create Interview
            const response = await interviewApi.create({
                domain: formData.domain,
                role: formData.role,
                company: formData.company,
                difficulty: formData.difficulty,
                jobDescription: formData.jobDescription,
                panelCount: formData.panelCount,
                scheduledAt,
                duration: formData.duration,
                selectedAvatars: formData.selectedAvatars,
                technology: formData.technology,
                resumeUrl: finalResumeUrl
            })

            const interviewId = response.data.interview.id
            router.push(`/interviews/${interviewId}/start`)
        } catch (error) {
            console.error('Failed to create interview:', error)
            alert('Failed to schedule interview. Please try again.')
        } finally {
            setIsSubmitting(false)
        }
    }

    // Dynamic duration estimation helper
    React.useEffect(() => {
        let estimatedDuration = 30 // Base

        if (formData.jobDescription) estimatedDuration += 10
        if (formData.resumeFile) estimatedDuration += 5
        if (formData.difficulty === 'ADVANCED') estimatedDuration += 15
        if (formData.difficulty === 'BEGINNER') estimatedDuration -= 5
        if (formData.panelCount > 1) estimatedDuration += (formData.panelCount - 1) * 5

        if (estimatedDuration !== formData.duration) {
            updateFormData('duration', estimatedDuration)
        }
    }, [formData.jobDescription, formData.resumeFile, formData.difficulty, formData.panelCount])


    if (authLoading || !isAuthenticated) {
        return (
            <div className="min-h-screen flex items-center justify-center">
                <Loader2 className="h-8 w-8 animate-spin text-primary" />
            </div>
        )
    }

    return (
        <div className="min-h-screen bg-gradient-to-br from-background to-muted/30 py-8">
            <div className="container max-w-4xl">
                {/* Header */}
                <div className="mb-8">
                    <Button variant="ghost" onClick={() => router.push('/interviews')} className="mb-4">
                        <ArrowLeft className="h-4 w-4 mr-2" />
                        Back to Interviews
                    </Button>
                    <h1 className="text-3xl font-bold">Schedule AI Interview</h1>
                    <p className="text-muted-foreground">Complete the steps below to set up your personalized mock interview</p>
                </div>

                {/* Progress Steps */}
                <div className="mb-8">
                    <div className="flex items-center justify-between">
                        {STEPS.map((step, idx) => (
                            <div key={step.id} className="flex items-center">
                                <div className={`flex items-center justify-center w-10 h-10 rounded-full border-2 transition-colors ${currentStep > step.id
                                    ? 'bg-primary border-primary text-primary-foreground'
                                    : currentStep === step.id
                                        ? 'border-primary text-primary'
                                        : 'border-muted text-muted-foreground'
                                    }`}>
                                    {currentStep > step.id ? (
                                        <Check className="h-5 w-5" />
                                    ) : (
                                        <step.icon className="h-5 w-5" />
                                    )}
                                </div>
                                {idx < STEPS.length - 1 && (
                                    <div className={`w-16 md:w-24 h-0.5 mx-2 ${currentStep > step.id ? 'bg-primary' : 'bg-muted'
                                        }`} />
                                )}
                            </div>
                        ))}
                    </div>
                    <div className="flex justify-between mt-2">
                        {STEPS.map(step => (
                            <span key={step.id} className={`text-xs ${currentStep === step.id ? 'text-primary font-medium' : 'text-muted-foreground'
                                }`}>
                                {step.title}
                            </span>
                        ))}
                    </div>
                </div>

                {/* Step Content */}
                <Card className="mb-6">
                    <CardHeader>
                        <CardTitle>{STEPS[currentStep - 1].title}</CardTitle>
                        <CardDescription>
                            {currentStep === 1 && 'Tell us about the role you want to practice for'}
                            {currentStep === 2 && 'Upload your resume and job description for personalized questions'}
                            {currentStep === 3 && 'Choose your interviewer panel'}
                            {currentStep === 4 && 'Pick a convenient time for your interview'}
                            {currentStep === 5 && 'Review your interview setup'}
                        </CardDescription>
                    </CardHeader>
                    <CardContent>
                        {/* Step 1: Interview Details */}
                        {currentStep === 1 && (
                            <div className="space-y-6">
                                <div className="space-y-4">
                                    <Label className="text-base">Interview Type</Label>
                                    <div className="grid grid-cols-2 gap-4">
                                        <Card
                                            className={`cursor-pointer transition-all ${formData.type === 'INSTANT' ? 'border-primary ring-2 ring-primary/20' : 'hover:border-primary/50'}`}
                                            onClick={() => updateFormData('type', 'INSTANT')}
                                        >
                                            <CardContent className="p-4 flex flex-col items-center gap-2 text-center">
                                                <Sparkles className={`h-8 w-8 ${formData.type === 'INSTANT' ? 'text-primary' : 'text-muted-foreground'}`} />
                                                <div className="font-bold">Instant Start</div>
                                                <div className="text-xs text-muted-foreground">Start practicing immediately</div>
                                            </CardContent>
                                        </Card>
                                        <Card
                                            className={`cursor-pointer transition-all ${formData.type === 'SCHEDULED' ? 'border-primary ring-2 ring-primary/20' : 'hover:border-primary/50'}`}
                                            onClick={() => updateFormData('type', 'SCHEDULED')}
                                        >
                                            <CardContent className="p-4 flex flex-col items-center gap-2 text-center">
                                                <Calendar className={`h-8 w-8 ${formData.type === 'SCHEDULED' ? 'text-primary' : 'text-muted-foreground'}`} />
                                                <div className="font-bold">Schedule Later</div>
                                                <div className="text-xs text-muted-foreground">Pick a time for your session</div>
                                            </CardContent>
                                        </Card>
                                    </div>
                                </div>

                                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                    <div className="space-y-2">
                                        <Label>Domain / Industry</Label>
                                        <Select value={formData.domain} onValueChange={(v) => updateFormData('domain', v)}>
                                            <SelectTrigger>
                                                <SelectValue />
                                            </SelectTrigger>
                                            <SelectContent>
                                                {DOMAINS.map(d => (
                                                    <SelectItem key={d.value} value={d.value}>{d.label}</SelectItem>
                                                ))}
                                            </SelectContent>
                                        </Select>
                                    </div>
                                    <div className="space-y-2">
                                        <Label>Role / Position *</Label>
                                        <Input
                                            placeholder="e.g., Frontend Developer"
                                            value={formData.role}
                                            onChange={(e) => updateFormData('role', e.target.value)}
                                            required
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <Label>Primary Technology Stack *</Label>
                                        <Input
                                            placeholder="e.g., React, Node.js, Python"
                                            value={formData.technology}
                                            onChange={(e) => updateFormData('technology', e.target.value)}
                                            required
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <Label>Target Company (Optional)</Label>
                                        <Input
                                            placeholder="e.g., Google, Amazon"
                                            value={formData.company}
                                            onChange={(e) => updateFormData('company', e.target.value)}
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <Label>Difficulty Level</Label>
                                        <Select value={formData.difficulty} onValueChange={(v) => updateFormData('difficulty', v)}>
                                            <SelectTrigger>
                                                <SelectValue />
                                            </SelectTrigger>
                                            <SelectContent>
                                                {DIFFICULTIES.map(d => (
                                                    <SelectItem key={d.value} value={d.value}>
                                                        <div>
                                                            <div className="font-medium">{d.label}</div>
                                                            <div className="text-xs text-muted-foreground">{d.desc}</div>
                                                        </div>
                                                    </SelectItem>
                                                ))}
                                            </SelectContent>
                                        </Select>
                                    </div>
                                    <div className="space-y-2">
                                        <Label>Duration (Minutes)</Label>
                                        <Select value={String(formData.duration)} onValueChange={(v) => updateFormData('duration', Number(v))}>
                                            <SelectTrigger>
                                                <SelectValue />
                                            </SelectTrigger>
                                            <SelectContent>
                                                {[15, 30, 45, 60].map(m => (
                                                    <SelectItem key={m} value={String(m)}>{m} Minutes</SelectItem>
                                                ))}
                                            </SelectContent>
                                        </Select>
                                    </div>
                                </div>
                            </div>
                        )}

                        {/* Step 2: JD & Resume */}
                        {currentStep === 2 && (
                            <div className="space-y-6">
                                <div className="space-y-2">
                                    <Label>Job Description</Label>
                                    <p className="text-sm text-muted-foreground mb-2">
                                        Paste the job description for more relevant questions
                                    </p>
                                    <Textarea
                                        placeholder="Paste the job description here..."
                                        value={formData.jobDescription}
                                        onChange={(e) => updateFormData('jobDescription', e.target.value)}
                                        rows={6}
                                    />
                                </div>
                                <div className="space-y-2">
                                    <Label>Resume Upload</Label>
                                    <p className="text-sm text-muted-foreground mb-2">
                                        Upload your resume to get experience-based questions
                                    </p>
                                    <div className="border-2 border-dashed rounded-lg p-8 text-center hover:border-primary transition-colors">
                                        <input
                                            type="file"
                                            accept=".pdf,.doc,.docx"
                                            onChange={handleResumeUpload}
                                            className="hidden"
                                            id="resume-upload"
                                        />
                                        <label htmlFor="resume-upload" className="cursor-pointer">
                                            {formData.resumeFile ? (
                                                <div className="flex items-center justify-center gap-2">
                                                    <FileText className="h-8 w-8 text-primary" />
                                                    <div className="text-left">
                                                        <p className="font-medium">{formData.resumeFile.name}</p>
                                                        <p className="text-sm text-muted-foreground">Click to change</p>
                                                    </div>
                                                </div>
                                            ) : (
                                                <>
                                                    <Upload className="h-8 w-8 mx-auto text-muted-foreground mb-2" />
                                                    <p className="font-medium">Drop your resume here or click to upload</p>
                                                    <p className="text-sm text-muted-foreground">PDF, DOC, DOCX (Max 5MB)</p>
                                                </>
                                            )}
                                        </label>
                                    </div>
                                </div>
                            </div>
                        )}

                        {/* Step 3: Panel Selection */}
                        {currentStep === 3 && (
                            <div className="space-y-6">
                                <p className="text-sm text-muted-foreground">
                                    Select the interviewers for your panel. Mix technical and HR for a realistic experience.
                                </p>
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    {AVATARS.map(avatar => {
                                        const isSelected = formData.selectedAvatars.includes(avatar.id)
                                        return (
                                            <Card
                                                key={avatar.id}
                                                className={`cursor-pointer transition-all ${isSelected ? 'border-primary ring-2 ring-primary/20' : 'hover:border-primary/50'
                                                    }`}
                                                onClick={() => toggleAvatar(avatar.id)}
                                            >
                                                <CardContent className="flex items-center gap-4 p-4">
                                                    <div className={`w-14 h-14 rounded-full flex items-center justify-center ${avatar.role.includes('Technical') || avatar.role.includes('Engineer')
                                                        ? 'bg-blue-100 text-blue-600'
                                                        : 'bg-purple-100 text-purple-600'
                                                        }`}>
                                                        {avatar.role.includes('Technical') || avatar.role.includes('Engineer') ? (
                                                            <Bot className="h-7 w-7" />
                                                        ) : (
                                                            <Briefcase className="h-7 w-7" />
                                                        )}
                                                    </div>
                                                    <div className="flex-1">
                                                        <h4 className="font-medium">{avatar.name}</h4>
                                                        <p className="text-sm text-muted-foreground">{avatar.role}</p>
                                                        <p className="text-xs text-muted-foreground">Style: {avatar.personality}</p>
                                                    </div>
                                                    <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center ${isSelected ? 'border-primary bg-primary text-primary-foreground' : 'border-muted'
                                                        }`}>
                                                        {isSelected && <Check className="h-4 w-4" />}
                                                    </div>
                                                </CardContent>
                                            </Card>
                                        )
                                    })}
                                </div>
                                <p className="text-sm font-medium">
                                    Selected: {formData.selectedAvatars.length} interviewer(s)
                                </p>
                            </div>
                        )}

                        {/* Step 4: Schedule */}
                        {currentStep === 4 && (
                            <div className="space-y-6">
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                    <div className="space-y-2">
                                        <Label>Select Date</Label>
                                        <Input
                                            type="date"
                                            value={formData.scheduledDate}
                                            onChange={(e) => updateFormData('scheduledDate', e.target.value)}
                                            min={new Date().toISOString().split('T')[0]}
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <Label>Select Time Slot</Label>
                                        <div className="grid grid-cols-2 gap-2">
                                            {TIME_SLOTS.map(slot => (
                                                <Button
                                                    key={slot}
                                                    variant={formData.scheduledTime === slot ? 'default' : 'outline'}
                                                    size="sm"
                                                    onClick={() => updateFormData('scheduledTime', slot)}
                                                    className="justify-start"
                                                >
                                                    <Clock className="h-4 w-4 mr-2" />
                                                    {slot}
                                                </Button>
                                            ))}
                                        </div>
                                    </div>
                                </div>
                                <div className="p-4 bg-muted/50 rounded-lg">
                                    <div className="flex items-center gap-2 text-sm">
                                        <Sparkles className="h-4 w-4 text-primary" />
                                        <span className="font-medium">Pro Tip:</span>
                                        <span className="text-muted-foreground">Schedule when you&apos;re most alert for best performance</span>
                                    </div>
                                </div>
                            </div>
                        )}

                        {/* Step 5: Tech Check */}
                        {currentStep === 5 && (
                            <div className="space-y-6">
                                <p className="text-sm text-muted-foreground">
                                    Before we begin, let&apos;s ensure your technical setup is ready for a professional interview.
                                </p>
                                <div className="space-y-4">
                                    <div className="flex items-center justify-between p-4 border rounded-lg bg-background/50">
                                        <div className="flex items-center gap-3">
                                            <div className="p-2 bg-blue-100 text-blue-600 rounded-full">
                                                <Video className="h-5 w-5" />
                                            </div>
                                            <div>
                                                <p className="font-medium">Camera Check</p>
                                                <p className="text-xs text-muted-foreground">Ensure you are clearly visible</p>
                                            </div>
                                        </div>
                                        <Check className="h-5 w-5 text-green-500" />
                                    </div>
                                    <div className="flex items-center justify-between p-4 border rounded-lg bg-background/50">
                                        <div className="flex items-center gap-3">
                                            <div className="p-2 bg-purple-100 text-purple-600 rounded-full">
                                                <Clock className="h-5 w-5" />
                                            </div>
                                            <div>
                                                <p className="font-medium">Microphone Check</p>
                                                <p className="text-xs text-muted-foreground">Audio should be clear and loud</p>
                                            </div>
                                        </div>
                                        <Check className="h-5 w-5 text-green-500" />
                                    </div>
                                    <div className="flex items-center justify-between p-4 border rounded-lg bg-background/50">
                                        <div className="flex items-center gap-3">
                                            <div className="p-2 bg-orange-100 text-orange-600 rounded-full">
                                                <Sparkles className="h-5 w-5" />
                                            </div>
                                            <div>
                                                <p className="font-medium">Internet Stability</p>
                                                <p className="text-xs text-muted-foreground">High-speed connection required</p>
                                            </div>
                                        </div>
                                        <Check className="h-5 w-5 text-green-500" />
                                    </div>
                                </div>
                                <div className="flex items-center space-x-2 pt-4">
                                    <input
                                        type="checkbox"
                                        id="tech-confirm"
                                        aria-label="Confirm technical setup"
                                        className="h-4 w-4 rounded border-gray-300 text-primary focus:ring-primary"
                                        checked={formData.techVerified}
                                        onChange={(e) => updateFormData('techVerified', e.target.checked)}
                                    />
                                    <Label htmlFor="tech-confirm" className="text-sm cursor-pointer">
                                        I confirm that my camera, microphone, and internet are working properly.
                                    </Label>
                                </div>
                            </div>
                        )}

                        {/* Step 6: Review */}
                        {currentStep === 6 && (
                            <div className="space-y-6">
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                    <div className="space-y-4">
                                        <h4 className="font-medium flex items-center gap-2">
                                            <Target className="h-4 w-4 text-primary" />
                                            Role & Technology
                                        </h4>
                                        <div className="space-y-2 text-sm">
                                            <div className="flex justify-between">
                                                <span className="text-muted-foreground">Domain:</span>
                                                <span className="font-medium">{DOMAINS.find(d => d.value === formData.domain)?.label}</span>
                                            </div>
                                            <div className="flex justify-between">
                                                <span className="text-muted-foreground">Role:</span>
                                                <span className="font-medium">{formData.role}</span>
                                            </div>
                                            <div className="flex justify-between">
                                                <span className="text-muted-foreground">Technology:</span>
                                                <span className="font-medium">{formData.technology}</span>
                                            </div>
                                            {formData.company && (
                                                <div className="flex justify-between">
                                                    <span className="text-muted-foreground">Company:</span>
                                                    <span className="font-medium">{formData.company}</span>
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                    <div className="space-y-4">
                                        <h4 className="font-medium flex items-center gap-2">
                                            <Calendar className="h-4 w-4 text-primary" />
                                            Schedule & Panel
                                        </h4>
                                        <div className="space-y-2 text-sm">
                                            <div className="flex justify-between">
                                                <span className="text-muted-foreground">Type:</span>
                                                <span className="font-medium uppercase">{formData.type}</span>
                                            </div>
                                            {formData.type === 'SCHEDULED' && (
                                                <>
                                                    <div className="flex justify-between">
                                                        <span className="text-muted-foreground">Date:</span>
                                                        <span className="font-medium">
                                                            {formData.scheduledDate ? new Date(formData.scheduledDate).toLocaleDateString() : 'Not set'}
                                                        </span>
                                                    </div>
                                                    <div className="flex justify-between">
                                                        <span className="text-muted-foreground">Time:</span>
                                                        <span className="font-medium">{formData.scheduledTime || 'Not set'}</span>
                                                    </div>
                                                </>
                                            )}
                                            <div className="flex justify-between">
                                                <span className="text-muted-foreground">Panel Size:</span>
                                                <span className="font-medium">{formData.panelCount} interviewer(s)</span>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                                {formData.jobDescription && (
                                    <div className="p-4 bg-muted/50 rounded-lg border">
                                        <h4 className="font-medium mb-1 text-sm">Job Description</h4>
                                        <p className="text-xs text-muted-foreground line-clamp-3">{formData.jobDescription}</p>
                                    </div>
                                )}
                                {formData.resumeFile && (
                                    <div className="p-4 bg-muted/50 rounded-lg flex items-center gap-2 border">
                                        <FileText className="h-4 w-4 text-primary" />
                                        <span className="text-sm font-medium">Resume Uploaded:</span>
                                        <span className="text-xs text-muted-foreground">{formData.resumeFile.name}</span>
                                    </div>
                                )}
                                <div className="p-4 bg-green-50 border border-green-100 rounded-lg flex items-center gap-2">
                                    <Check className="h-4 w-4 text-green-600" />
                                    <span className="text-sm text-green-700 font-medium">Technical Setup Verified</span>
                                </div>
                            </div>
                        )}
                    </CardContent>
                </Card>

                {/* Navigation Buttons */}
                <div className="flex justify-between">
                    <Button variant="outline" onClick={handleBack} disabled={currentStep === 1}>
                        <ArrowLeft className="h-4 w-4 mr-2" />
                        Back
                    </Button>
                    {currentStep < 6 ? (
                        <Button onClick={handleNext} disabled={!canProceed()}>
                            Next
                            <ArrowRight className="h-4 w-4 ml-2" />
                        </Button>
                    ) : (
                        <Button onClick={handleSubmit} disabled={isSubmitting} className="bg-primary hover:bg-primary/90">
                            {isSubmitting ? (
                                <>
                                    <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                                    Initializing...
                                </>
                            ) : (
                                <>
                                    <Sparkles className="h-4 w-4 mr-2" />
                                    {formData.type === 'INSTANT' ? 'Start Interview Now' : 'Confirm & Schedule'}
                                </>
                            )}
                        </Button>
                    )}
                </div>
            </div>
        </div>
    )
}

"use client"

import * as React from 'react'
import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { interviewApi } from '@/lib/api'
import { useAuth } from '@/lib/auth-context'
import { Card, CardContent } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Textarea } from '@/components/ui/textarea'
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
} from "@/components/ui/dialog"
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select"
import {
    Video,
    Calendar,
    Clock,
    CheckCircle2,
    XCircle,
    PlayCircle,
    Loader2,
    Plus,
    Sparkles,
    FileText,
    Upload,
    Bot,
    Briefcase,
    Check,
    ArrowRight
} from 'lucide-react'
import { NewInterviewDialog } from '@/components/interviews/NewInterviewDialog'


interface Interview {
    id: string
    domain: string
    role: string
    company?: string
    difficulty: string
    status: string
    scheduledAt: string
    score?: number
}

const _DOMAINS = [
    { value: 'TECHNOLOGY', label: 'Technology / Software' },
    { value: 'DATA_SCIENCE', label: 'Data Science & AI' },
    { value: 'PRODUCT', label: 'Product Management' },
    { value: 'DESIGN', label: 'UI/UX Design' },
    { value: 'BUSINESS', label: 'Business / Consulting' },
    { value: 'FINANCE', label: 'Finance & Banking' },
]

const _DIFFICULTIES = [
    { value: 'BEGINNER', label: 'Beginner', desc: 'For freshers, 0-2 years experience' },
    { value: 'INTERMEDIATE', label: 'Intermediate', desc: 'For mid-level, 2-5 years experience' },
    { value: 'ADVANCED', label: 'Advanced', desc: 'For seniors, 5+ years experience' },
]

export default function InterviewsPage() {
    const router = useRouter()
    const { isAuthenticated, isLoading: authLoading } = useAuth()

    const [interviews, setInterviews] = React.useState<Interview[]>([])
    const [stats, setStats] = React.useState<{ total: number; completed: number; averageScore: number } | null>(null)
    const [isLoading, setIsLoading] = React.useState(true)
    // const [isPotentialModalOpen, setPotentialModalOpen] = useState(false) // Removed unused state

    // New Interview Form State
    const [isOpen, setIsOpen] = useState(false)
    const [_isSubmitting, setIsSubmitting] = useState(false)
    const [_step, _setStep] = useState(1) // 1: Details, 2: JD/Resume, 3: Review/Launch
    const [formData, setFormData] = useState({
        domain: 'TECHNOLOGY',
        role: '',
        company: '',
        technology: '',
        difficulty: 'INTERMEDIATE',
        duration: 30,
        jobDescription: '',
        resumeFile: null as File | null,
        resumeUrl: '',
        panelCount: 1, // Simplified for quick start
        type: 'INSTANT'
    })

    React.useEffect(() => {
        if (!authLoading && !isAuthenticated) {
            router.push('/login')
        }
    }, [authLoading, isAuthenticated, router])

    React.useEffect(() => {
        const fetchData = async () => {
            if (!isAuthenticated) return

            try {
                const [interviewsRes, statsRes] = await Promise.all([
                    interviewApi.getAll(),
                    interviewApi.getStats(),
                ])
                setInterviews(interviewsRes.data.interviews || [])
                setStats(statsRes.data.stats)
            } catch (error) {
                console.error('Failed to fetch interviews:', error)
            } finally {
                setIsLoading(false)
            }
        }

        if (isAuthenticated) {
            fetchData()
        }
    }, [isAuthenticated])

    const handleStartInterview = async (id: string) => {
        try {
            await interviewApi.start(id)
            setInterviews(interviews.map(i =>
                i.id === id ? { ...i, status: 'IN_PROGRESS' } : i
            ))
            router.push(`/interviews/${id}`)
        } catch (error) {
            console.error('Failed to start interview:', error)
        }
    }

    const updateFormData = (field: string, value: any) => {
        setFormData(prev => ({ ...prev, [field]: value }))
    }

    const _handleResumeUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0]
        if (file) {
            updateFormData('resumeFile', file)
            updateFormData('resumeUrl', file.name)
        }
    }

    const _handleCreateInterview = async () => {
        if (!formData.role || !formData.technology) return

        setIsSubmitting(true)
        try {
            const response = await interviewApi.create({
                domain: formData.domain,
                role: formData.role,
                company: formData.company,
                difficulty: formData.difficulty,
                jobDescription: formData.jobDescription,
                panelCount: 1, // Defaulting to 1 for quick start
                duration: formData.duration,
                technology: formData.technology,
                selectedAvatars: ['tech-1'] // Default avatar
            })

            const interviewId = response.data.interview.id
            setIsOpen(false)
            // Redirect to start page (Tech Check)
            router.push(`/interviews/${interviewId}/start`)
        } catch (error) {
            console.error('Failed to create interview:', error)
        } finally {
            setIsSubmitting(false)
        }
    }

    const getStatusIcon = (status: string) => {
        switch (status) {
            case 'SCHEDULED': return <Calendar className="h-4 w-4 text-blue-500" />
            case 'IN_PROGRESS': return <PlayCircle className="h-4 w-4 text-yellow-500" />
            case 'COMPLETED': return <CheckCircle2 className="h-4 w-4 text-green-500" />
            case 'CANCELLED': return <XCircle className="h-4 w-4 text-red-500" />
            default: return <Clock className="h-4 w-4" />
        }
    }

    const getStatusColor = (status: string) => {
        switch (status) {
            case 'SCHEDULED': return 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400'
            case 'IN_PROGRESS': return 'bg-yellow-100 text-yellow-700 dark:bg-yellow-900/30 dark:text-yellow-400'
            case 'COMPLETED': return 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400'
            case 'CANCELLED': return 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400'
            default: return 'bg-gray-100 text-gray-700'
        }
    }

    if (authLoading || !isAuthenticated) {
        return (
            <div className="min-h-[calc(100vh-4rem)] flex items-center justify-center">
                <Loader2 className="h-8 w-8 animate-spin text-primary" />
            </div>
        )
    }

    return (
        <div className="container py-8">
            {/* Header */}
            <div className="flex items-center justify-between mb-8">
                <div>
                    <h1 className="text-3xl font-bold mb-2">AI Interview Prep</h1>
                    <p className="text-muted-foreground">
                        Practice with AI-powered mock interviews and get instant feedback
                    </p>
                </div>

                <NewInterviewDialog
                    open={isOpen}
                    onOpenChange={setIsOpen}
                    trigger={
                        <Button className="rounded-xl shadow-lg shadow-primary/20 hover:scale-105 transition-all">
                            <Plus className="mr-2 h-4 w-4" /> New Interview
                        </Button>
                    }
                />
            </div>

            {/* Stats Overview */}
            {stats && (
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8">
                    <div className="bg-card border border-border rounded-xl p-5">
                        <p className="text-sm font-medium text-muted-foreground">Total Interviews</p>
                        <p className="text-3xl font-bold text-foreground mt-1">{stats.total}</p>
                    </div>
                    <div className="bg-card border border-border rounded-xl p-5">
                        <p className="text-sm font-medium text-muted-foreground">Completed</p>
                        <p className="text-3xl font-bold text-foreground mt-1">{stats.completed}</p>
                    </div>
                    <div className="bg-card border border-border rounded-xl p-5">
                        <p className="text-sm font-medium text-muted-foreground">Average Score</p>
                        <p className="text-3xl font-bold text-foreground mt-1">{Math.round(stats.averageScore || 0)}%</p>
                    </div>
                </div>
            )}

            {/* Interview History */}
            <div className="flex items-center justify-between mb-4">
                <h2 className="text-xl font-semibold">Recent History</h2>
            </div>

            {isLoading ? (
                <div className="flex items-center justify-center py-20">
                    <Loader2 className="h-8 w-8 animate-spin text-primary" />
                </div>
            ) : interviews.length === 0 ? (
                <div className="text-center py-20 bg-muted/30 rounded-3xl border border-dashed border-muted-foreground/20">
                    <Video className="h-12 w-12 mx-auto text-muted-foreground mb-4 opacity-50" />
                    <h3 className="text-xl font-bold">No sessions practiced yet</h3>
                    <p className="text-muted-foreground mb-6">Launch your first AI mock interview to sharpen your skills.</p>
                    <Button size="lg" onClick={() => setIsOpen(true)} className="rounded-xl shadow-xl shadow-primary/20">
                        <Plus className="mr-2 h-5 w-5" /> Start Practice Interview
                    </Button>
                </div>
            ) : (
                <div className="space-y-4">
                    {interviews.map((interview) => (
                        <Card key={interview.id} className="hover:shadow-md transition-shadow">
                            <CardContent className="flex items-center justify-between py-4">
                                <div className="flex items-center gap-4">
                                    <div className="h-12 w-12 rounded-full bg-primary/10 flex items-center justify-center">
                                        <Video className="h-6 w-6 text-primary" />
                                    </div>
                                    <div>
                                        <h3 className="font-medium">{interview.role}</h3>
                                        <div className="flex items-center gap-2 text-sm text-muted-foreground">
                                            <span>{interview.domain}</span>
                                            {interview.company && <span>• {interview.company}</span>}
                                            <span>• {interview.difficulty}</span>
                                        </div>
                                    </div>
                                </div>
                                <div className="flex items-center gap-4">
                                    <span className={`inline-flex items-center gap-1 text-xs px-2 py-1 rounded-full ${getStatusColor(interview.status)}`}>
                                        {getStatusIcon(interview.status)}
                                        {interview.status}
                                    </span>
                                    {interview.score !== undefined && interview.score !== null && (
                                        <span className="text-sm font-medium">{interview.score}%</span>
                                    )}
                                    {(interview.status === 'SCHEDULED' || interview.status === 'IN_PROGRESS') && (
                                        <Button size="sm" onClick={() => handleStartInterview(interview.id)}>
                                            {interview.status === 'IN_PROGRESS' ? 'Resume' : 'Start'}
                                        </Button>
                                    )}
                                    {interview.status === 'COMPLETED' && (
                                        <Button size="sm" variant="outline" onClick={() => router.push(`/interviews/${interview.id}/report`)}>
                                            View Report
                                        </Button>
                                    )}
                                </div>
                            </CardContent>
                        </Card>
                    ))}
                </div>
            )
            }
        </div >
    )
}

