                <div class="course">"${cert.courseName}"</div>
                <div>
                    ${cert.grade ? `<span class="grade-badge">Grade: ${cert.grade}</span>` : ''}
                    ${cert.score ? `<span class="score-badge">Score: ${cert.score}%</span>` : ''}
                </div>
                <p class="date">Issued on ${new Date(cert.issueDate).toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' })}</p>
                ${cert.signatoryName ? `
                    <div class="signature-section">
                        <div class="signature-line"></div>
                        <div class="signature-name">${cert.signatoryName}</div>
                        <div class="signature-title">${cert.signatoryTitle || ''}</div>
                    </div>
                ` : ''}
                <div class="verify-section">
                    <strong>Certificate ID:</strong> ${cert.uniqueId}<br>
                    <strong>Verify at:</strong> ${verifyUrl}
                </div>
            </div>
            <div class="seal">VERIFIED<br>✓</div>
        </div>
    </div>
</body>
</html>`

    // Share functions
    const handleShareLinkedIn = () => {
        if (!certificate) return
        const url = encodeURIComponent(getVerificationUrl())
        window.open(`https://www.linkedin.com/profile/add?startTask=CERTIFICATION_NAME&name=${encodeURIComponent(certificate.courseName)}&organizationName=${encodeURIComponent(certificate.instituteName || 'TechWell')}&issueYear=2026&issueMonth=1&certUrl=${url}&certId=${certificate.uniqueId}`, '_blank')
    }

    const handleShareTwitter = () => {
        if (!certificate) return
        const text = encodeURIComponent(`I just earned my ${certificate.courseName} certificate from ${certificate.instituteName || 'TechWell'}! 🎓`)
        const url = encodeURIComponent(getVerificationUrl())
        window.open(`https://twitter.com/intent/tweet?text=${text}&url=${url}`, '_blank')
    }

    const handleShareWhatsApp = () => {
        if (!certificate) return
        const text = encodeURIComponent(`Check out my ${certificate.courseName} certificate: ${getVerificationUrl()}`)
        window.open(`https://wa.me/?text=${text}`, '_blank')
    }

    const handleShareEmail = () => {
        if (!certificate) return
        const subject = encodeURIComponent(`My ${certificate.courseName} Certificate`)
        const body = encodeURIComponent(`Hi,\n\nI wanted to share my certificate for completing ${certificate.courseName}.\n\nVerify it here: ${getVerificationUrl()}\n\nCertificate ID: ${certificate.uniqueId}`)
        window.open(`mailto:?subject=${subject}&body=${body}`, '_blank')
    }

    if (isLoading) {
        return (
            <div className="min-h-screen flex items-center justify-center">
                <div className="animate-spin h-8 w-8 border-4 border-primary border-t-transparent rounded-full" />
            </div>
        )
    }

    return (
        <div className="min-h-screen bg-gradient-to-b from-primary/5 to-background py-12 print:bg-white print:py-0">
            <div className="container max-w-3xl print:max-w-none">
                {/* Verification Status - Hide on print */}
                <Card className={`mb-6 ${certificate?.isValid ? 'border-green-500' : 'border-red-500'} border-2 print:hidden`}>
                    <CardContent className="py-6">
                        <div className="flex items-center justify-center gap-3">
                            {certificate?.isValid ? (
                                <>
                                    <CheckCircle className="h-8 w-8 text-green-500" />
                                    <div>
                                        <h2 className="text-xl font-bold text-green-700">Certificate Verified</h2>
                                        <p className="text-sm text-green-600">This certificate is authentic and valid</p>
                                    </div>
                                </>
                            ) : (
                                <>
                                    <XCircle className="h-8 w-8 text-red-500" />
                                    <div>
                                        <h2 className="text-xl font-bold text-red-700">Invalid Certificate</h2>
                                        <p className="text-sm text-red-600">This certificate could not be verified</p>
                                    </div>
                                </>
                            )}
                        </div>
                    </CardContent>
                </Card>

                {certificate && (
                    <>
                        {/* Certificate Display */}
                        <Card className="mb-6 print:shadow-none print:border-0" ref={certificateRef}>
                            <CardContent className="py-12 text-center">
                                <div className="inline-flex items-center gap-2 text-primary mb-4">
                                    <Shield className="h-5 w-5" />
                                    <span className="font-medium">{certificate.instituteName || 'TechWell Academy'}</span>
                                </div>

                                <h1 className="text-3xl font-bold text-primary mb-6">Certificate of Completion</h1>

                                <p className="text-muted-foreground mb-2">This is to certify that</p>
                                <h2 className="text-2xl font-semibold mb-4">{certificate.studentName}</h2>

                                <p className="text-muted-foreground mb-2">has successfully completed</p>
                                <h3 className="text-xl font-medium mb-4">{certificate.courseName}</h3>

                                <div className="flex items-center justify-center gap-4 mb-6">
                                    {certificate.grade && (
                                        <Badge className="text-lg px-4 py-1 bg-green-600">Grade: {certificate.grade}</Badge>
                                    )}
                                    {certificate.score && (
                                        <Badge variant="outline" className="text-lg px-4 py-1">Score: {certificate.score}%</Badge>
                                    )}
                                </div>

                                <div className="flex items-center justify-center gap-2 text-muted-foreground mb-8">
                                    <Calendar className="h-4 w-4" />
                                    <span>Issued on {new Date(certificate.issueDate).toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' })}</span>
                                </div>

                                {certificate.signatoryName && (
                                    <div className="border-t pt-6">
                                        <div className="inline-block border-t-2 border-primary/30 pt-2">
                                            <p className="font-semibold">{certificate.signatoryName}</p>
                                            <p className="text-sm text-muted-foreground">{certificate.signatoryTitle}</p>
                                        </div>
                                    </div>
                                )}

                                <div className="mt-8 p-4 bg-muted/50 rounded-lg print:hidden">
                                    <p className="text-sm text-muted-foreground">
                                        Certificate ID: <code className="font-mono">{certificate.uniqueId}</code>
                                    </p>
                                </div>
                            </CardContent>
                        </Card>

                        {/* Actions - Hide on print */}
                        <div className="space-y-4 print:hidden">
                            {/* Primary Actions */}
                            <div className="flex flex-wrap justify-center gap-3">
                                <Button onClick={handleDownloadPDF} disabled={isExporting}>
                                    {isExporting ? (
                                        <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                                    ) : (
                                        <FileText className="h-4 w-4 mr-2" />
                                    )}
                                    Download PDF
                                </Button>
                                <Button variant="outline" onClick={handlePrint}>
                                    <Printer className="h-4 w-4 mr-2" />
                                    Print
                                </Button>
                                <Button
                                    variant="outline"
                                    onClick={handleCopyLink}
                                    className={copiedLink ? 'bg-green-50 border-green-500 text-green-700' : ''}
                                >
                                    {copiedLink ? (
                                        <CheckCircle className="h-4 w-4 mr-2" />
                                    ) : (
                                        <Link2 className="h-4 w-4 mr-2" />
                                    )}
                                    {copiedLink ? 'Copied!' : 'Copy Link'}
                                </Button>
                            </div>

                            {/* Share Options */}
                            <div className="relative">
                                <div className="flex flex-wrap justify-center gap-2">
                                    <p className="w-full text-center text-sm text-muted-foreground mb-2">Share on:</p>
                                    <Button variant="outline" size="sm" onClick={handleShareLinkedIn} className="bg-[#0077b5]/5 hover:bg-[#0077b5]/10 border-[#0077b5]/30">
                                        <Linkedin className="h-4 w-4 mr-2 text-[#0077b5]" />
                                        LinkedIn
                                    </Button>
                                    <Button variant="outline" size="sm" onClick={handleShareTwitter} className="bg-[#1da1f2]/5 hover:bg-[#1da1f2]/10 border-[#1da1f2]/30">
                                        <Twitter className="h-4 w-4 mr-2 text-[#1da1f2]" />
                                        Twitter
                                    </Button>
                                    <Button variant="outline" size="sm" onClick={handleShareWhatsApp} className="bg-[#25d366]/5 hover:bg-[#25d366]/10 border-[#25d366]/30">
                                        <MessageCircle className="h-4 w-4 mr-2 text-[#25d366]" />
                                        WhatsApp
                                    </Button>
                                    <Button variant="outline" size="sm" onClick={handleShareEmail}>
                                        <Mail className="h-4 w-4 mr-2" />
                                        Email
                                    </Button>
                                </div>
                            </div>

                            {/* Add to LinkedIn Profile */}
                            <Card className="bg-gradient-to-r from-[#0077b5]/5 to-[#0077b5]/10 border-[#0077b5]/20">
                                <CardContent className="py-4 text-center">
                                    <p className="text-sm text-muted-foreground mb-3">
                                        Add this certificate to your LinkedIn profile to showcase your achievements
                                    </p>
                                    <Button onClick={handleShareLinkedIn} className="bg-[#0077b5] hover:bg-[#006097]">
                                        <Linkedin className="h-4 w-4 mr-2" />
                                        Add to LinkedIn Credentials
                                    </Button>
                                </CardContent>
                            </Card>
                        </div>
                    </>
                )}
            </div>
        </div>
    )
}

"use client";

import { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, GraduationCap, Briefcase, Code, Sparkles } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';

const FEATURE_ENABLED = process.env.NEXT_PUBLIC_ENABLE_BEHAVIOR_AI === 'true';
const API_URL = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:5001';
const TRIGGER_DELAY = 100000; // 100 seconds
const STORAGE_KEY = 'intent_popup_shown';

interface IntentOption {
    id: string;
    label: string;
    icon: React.ReactNode;
    description: string;
    color: string;
}

const intentOptions: IntentOption[] = [
    {
        id: 'interview',
        label: 'Interview Prep',
        icon: <Code className="h-5 w-5" />,
        description: 'AI-powered mock interviews',
        color: 'from-blue-500 to-cyan-500'
    },
    {
        id: 'courses',
        label: 'Courses',
        icon: <GraduationCap className="h-5 w-5" />,
        description: 'Learn new skills',
        color: 'from-purple-500 to-pink-500'
    },
    {
        id: 'jobs',
        label: 'Jobs',
        icon: <Briefcase className="h-5 w-5" />,
        description: 'Find opportunities',
        color: 'from-green-500 to-emerald-500'
    },
    {
        id: 'exploring',
        label: 'Just Exploring',
        icon: <Sparkles className="h-5 w-5" />,
        description: 'Browse around',
        color: 'from-orange-500 to-yellow-500'
    }
];

interface SmartIntentPopupProps {
    sessionId: string;
    userId?: string;
}

export function SmartIntentPopup({ sessionId, userId }: SmartIntentPopupProps) {
    const [isVisible, setIsVisible] = useState(false);
    const [selectedIntent, setSelectedIntent] = useState<string | null>(null);

    useEffect(() => {
        if (!FEATURE_ENABLED) return;

        // Don't show popup for logged-in users
        if (userId) return;

        // Check if popup was already shown this session
        const popupShown = sessionStorage.getItem(STORAGE_KEY);
        if (popupShown === 'true') return;

        // Set timer to show popup after delay
        const timer = setTimeout(() => {
            setIsVisible(true);
        }, TRIGGER_DELAY);

        return () => clearTimeout(timer);
    }, [userId]);

    const handleClose = () => {
        setIsVisible(false);
        sessionStorage.setItem(STORAGE_KEY, 'true');
    };

    const handleSelectIntent = async (intentId: string) => {
        setSelectedIntent(intentId);

        try {
            // Record popup response
            await fetch(`${API_URL}/api/behavior/popup-response`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({
                    sessionId,
                    response: intentId
                })
            });
        } catch (error) {
            console.error('[SmartIntentPopup] Error recording response:', error);
        }

        // Close popup after selection
        setTimeout(() => {
            handleClose();
        }, 1000);
    };

    if (!FEATURE_ENABLED) return null;

    return (
        <AnimatePresence>
            {isVisible && (
                <>
                    {/* Backdrop */}
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50"
                        onClick={handleClose}
                    />

                    {/* Popup */}
                    <motion.div
                        initial={{ opacity: 0, scale: 0.9, y: 20 }}
                        animate={{ opacity: 1, scale: 1, y: 0 }}
                        exit={{ opacity: 0, scale: 0.9, y: 20 }}
                        transition={{ type: "spring", duration: 0.5 }}
                        className="fixed top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 z-50 w-full max-w-lg px-4"
                    >
                        <Card className="relative p-6 bg-background/95 backdrop-blur-xl border-2 border-primary/20 shadow-2xl">
                            {/* Close button */}
                            <button
                                onClick={handleClose}
                                className="absolute top-4 right-4 p-2 rounded-full hover:bg-muted transition-colors"
                                aria-label="Close"
                            >
                                <X className="h-4 w-4" />
                            </button>

                            {/* Header */}
                            <div className="text-center mb-6">
                                <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-primary/10 border border-primary/20 mb-4">
                                    <Sparkles className="h-4 w-4 text-primary" />
                                    <span className="text-sm font-semibold text-primary">
                                        Personalized Experience
                                    </span>
                                </div>
                                <h2 className="text-2xl font-bold mb-2">
                                    What brings you here today?
                                </h2>
                                <p className="text-muted-foreground">
                                    Help us personalize your experience
                                </p>
                            </div>

                            {/* Intent options */}
                            <div className="grid grid-cols-2 gap-3">
                                {intentOptions.map((option) => (
                                    <motion.button
                                        key={option.id}
                                        onClick={() => handleSelectIntent(option.id)}
                                        whileHover={{ scale: 1.05 }}
                                        whileTap={{ scale: 0.95 }}
                                        className={`relative p-4 rounded-xl border-2 transition-all ${selectedIntent === option.id
                                            ? 'border-primary bg-primary/10'
                                            : 'border-border hover:border-primary/50 hover:bg-muted/50'
                                            }`}
                                    >
                                        <div className={`absolute inset-0 rounded-xl bg-gradient-to-br ${option.color} opacity-0 hover:opacity-10 transition-opacity`} />
                                        <div className="relative flex flex-col items-center gap-2 text-center">
                                            <div className={`p-2 rounded-lg bg-gradient-to-br ${option.color}`}>
                                                <div className="text-white">
                                                    {option.icon}
                                                </div>
                                            </div>
                                            <div>
                                                <div className="font-semibold text-sm">
                                                    {option.label}
                                                </div>
                                                <div className="text-xs text-muted-foreground">
                                                    {option.description}
                                                </div>
                                            </div>
                                            {selectedIntent === option.id && (
                                                <motion.div
                                                    initial={{ scale: 0 }}
                                                    animate={{ scale: 1 }}
                                                    className="absolute top-2 right-2"
                                                >
                                                    <div className="h-5 w-5 rounded-full bg-primary flex items-center justify-center">
                                                        <svg className="h-3 w-3 text-primary-foreground" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                                                        </svg>
                                                    </div>
                                                </motion.div>
                                            )}
                                        </div>
                                    </motion.button>
                                ))}
                            </div>

                            {/* Footer */}
                            <div className="mt-6 text-center">
                                <button
                                    onClick={handleClose}
                                    className="text-sm text-muted-foreground hover:text-foreground transition-colors"
                                >
                                    Skip for now
                                </button>
                            </div>
                        </Card>
                    </motion.div>
                </>
            )}
        </AnimatePresence>
    );
}

"use client"

import Link from "next/link"
import { usePathname } from "next/navigation"
import { cn } from "@/lib/utils"
import {
    LayoutDashboard,
    Users,
    BookOpen,
    FileText,
    Video,
    Award,
    Settings,
    MessageSquare,
    Calendar,
    Menu,
    X,
    LogOut,
    VideoIcon,
    Magnet,
    Briefcase,
    GraduationCap,
    Image as ImageIcon,
    type LucideIcon
} from "lucide-react"

import { Button } from "@/components/ui/button"
import { useAuth } from "@/lib/auth-context"
import { leadApi } from "@/lib/api"
import { useState, useEffect } from "react"

interface RouteConfig {
    label: string
    icon: LucideIcon
    href: string
    permission?: string
    showLeadCounts?: boolean
}

type SidebarProps = React.HTMLAttributes<HTMLDivElement>

export function AdminSidebar({ className }: SidebarProps) {

    const pathname = usePathname()
    const { logout, hasPermission } = useAuth()
    const [isMobileOpen, setIsMobileOpen] = useState(false)
    const [leadCounts, setLeadCounts] = useState({ totalCount: 0, unreadCount: 0 })

    const canViewLeads = hasPermission("VIEW_LEADS")
    const isViewingLeads =
        pathname === "/admin/leads" ||
        pathname.startsWith("/admin/leads/")

    const routes: RouteConfig[] = [
        { label: "Dashboard", icon: LayoutDashboard, href: "/admin" },
        { label: "Users & Roles", icon: Users, href: "/admin/users", permission: "MANAGE_USERS" },
        { label: "Courses", icon: BookOpen, href: "/admin/courses", permission: "MANAGE_COURSES" },
        { label: "Certificates", icon: Award, href: "/admin/certificates", permission: "MANAGE_CERTIFICATES" },
        { label: "Students", icon: GraduationCap, href: "/admin/students", permission: "MANAGE_USERS" },
        { label: "Employer Requests", icon: Briefcase, href: "/admin/employers", permission: "MANAGE_USERS" },
        { label: "All Leads", icon: Magnet, href: "/admin/leads", permission: "VIEW_LEADS", showLeadCounts: true },
        { label: "Meetings", icon: Calendar, href: "/admin/meetings", permission: "VIEW_LEADS" },
        { label: "Tasks", icon: MessageSquare, href: "/admin/tasks", permission: "VIEW_LEADS" },
        { label: "Messages", icon: MessageSquare, href: "/admin/messages", permission: "VIEW_LEADS" },
        { label: "Blogs", icon: FileText, href: "/admin/blogs", permission: "MANAGE_CONTENT" },
        { label: "Gallery", icon: ImageIcon, href: "/admin/gallery", permission: "MANAGE_CONTENT" },
        { label: "Skillcasts", icon: VideoIcon, href: "/admin/skillcasts", permission: "MANAGE_CONTENT" },
        { label: "Reviews", icon: MessageSquare, href: "/admin/reviews", permission: "MANAGE_CONTENT" },
        { label: "Library", icon: BookOpen, href: "/admin/library", permission: "MANAGE_CONTENT" },
        //  { label: "Job Board", icon: Briefcase, href: "/admin/jobs" },
        // { label: "Projects Market", icon: Briefcase, href: "/admin/projects" },
        //   { label: "Support Tickets", icon: MessageSquare, href: "/admin/support", permission: "VIEW_SUPPORT" },
        // { label: "General Settings", icon: Settings, href: "/admin/settings", permission: "MANAGE_SETTINGS" },
        //  { label: "Video Integration", icon: Video, href: "/admin/video-settings", permission: "MANAGE_SETTINGS" },
        //  { label: "System Logs", icon: FileText, href: "/admin/logs", permission: "MANAGE_SETTINGS" },
    ]

    const availableRoutes = routes.filter(route => {
        if (route.permission && !hasPermission(route.permission)) return false
        return true
    })

    useEffect(() => {
        if (isMobileOpen) {
            setTimeout(() => setIsMobileOpen(false), 0)
        }
    }, [isMobileOpen, pathname])

    useEffect(() => {
        if (!canViewLeads) return

        let isMounted = true

        const loadLeadCounts = async () => {
            try {
                const res = await leadApi.getCounts()

                if (!isMounted) return

                setLeadCounts({
                    totalCount: res.data.totalCount ?? 0,
                    unreadCount: isViewingLeads ? 0 : (res.data.unreadCount ?? 0)
                })
            } catch (error) {
                if (!isMounted) return
                console.error("Failed to load lead counts:", error)
            }
        }

        loadLeadCounts()

        const intervalId = window.setInterval(loadLeadCounts, 30000)
        window.addEventListener("lead-counts:refresh", loadLeadCounts)

        return () => {
            isMounted = false
            window.clearInterval(intervalId)
            window.removeEventListener("lead-counts:refresh", loadLeadCounts)
        }
    }, [canViewLeads, isViewingLeads])

    return (
        <>
            {/* Mobile Toggle */}
            <div className="md:hidden fixed top-4 right-4 z-[9999]">
                <Button
                    variant="outline"
                    size="icon"
                    onClick={() => setIsMobileOpen(!isMobileOpen)}
                >
                    {isMobileOpen ? <X className="h-4 w-4" /> : <Menu className="h-4 w-4" />}
                </Button>
            </div>

            {/* Sidebar */}
            <div
                className={cn(
                    "fixed left-0 top-0 z-40 h-screen w-64 border-r bg-background overflow-y-auto transition-transform duration-300 md:translate-x-0",
                    isMobileOpen ? "translate-x-0" : "-translate-x-full",
                    className
                )}
            >

                {/* Header */}
                <div className="px-6 py-5 border-b flex-shrink-0">
                    <h2 className="text-xl font-bold text-primary">Admin Panel</h2>
                    <p className="text-xs text-muted-foreground">
                        Super Admin Console
                    </p>
                </div>

                {/* Scrollable Menu ✅ */}
                <div className="p-3">
                    <nav className="space-y-1 pb-6">
                        {availableRoutes.map((route) => {

                            const isActive =
                                pathname === route.href ||
                                pathname.startsWith(route.href + "/")

                            return (
                                <Link
                                    key={route.href}
                                    href={route.href}
                                    className={cn(
                                        "text-sm flex items-center justify-between gap-3 p-3 rounded-lg transition",
                                        isActive
                                            ? "text-primary bg-primary/10"
                                            : "text-muted-foreground hover:text-primary hover:bg-primary/10"
                                    )}
                                >
                                    <span className="flex min-w-0 items-center">
                                        <route.icon className="h-5 w-5 mr-3 flex-shrink-0" />
                                        <span className="truncate">{route.label}</span>
                                    </span>

                                    {route.showLeadCounts && canViewLeads && (
                                        <span className="ml-auto flex items-center gap-2">
                                            <span className="inline-flex min-w-5 items-center justify-center rounded-full px-1.5 py-0.5 text-[11px] font-semibold bg-muted">
                                                {leadCounts.totalCount}
                                            </span>

                                            {leadCounts.unreadCount > 0 && (
                                                <span className="inline-flex min-w-5 items-center justify-center rounded-full bg-red-500 px-1.5 py-0.5 text-[11px] font-semibold text-white">
                                                    {leadCounts.unreadCount > 99 ? "99+" : leadCounts.unreadCount}
                                                </span>
                                            )}
                                        </span>
                                    )}
                                </Link>
                            )
                        })}
                    </nav>
                </div>

                {/* Footer */}
                <div className="border-t p-3 flex-shrink-0">
                    <Button
                        variant="ghost"
                        className="w-full justify-start text-red-500 hover:text-red-600 hover:bg-red-50"
                        onClick={logout}
                    >
                        <LogOut className="h-5 w-5 mr-3" />
                        Sign Out
                    </Button>
                </div>

            </div>

            {/* Mobile Overlay */}
            {isMobileOpen && (
                <div
                    className="fixed inset-0 bg-black/50 z-30 md:hidden"
                    onClick={() => setIsMobileOpen(false)}
                />
            )}
        </>
    )
}

"use client"

import * as React from 'react'
import { useRouter } from 'next/navigation'
import api, { courseApi, uploadApi, type CoursePayload } from '@/lib/api'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import Image from "next/image"
import { Textarea } from '@/components/ui/textarea'
import { Badge } from '@/components/ui/badge'
import { Loader2, Wand2, Plus, GripVertical, CheckCircle, ArrowRight, ArrowLeft } from 'lucide-react'
import { VideoUpload } from '@/components/admin/VideoUpload'
import { getFullImageUrl } from '@/lib/image-utils'

interface CourseCreationWizardProps {
    redirectPath: string
    initialCourseId?: string
}

export function CourseCreationWizard({ redirectPath, initialCourseId }: CourseCreationWizardProps) {
    const router = useRouter()

    // Steps: 1=Basic, 2=Curriculum, 3=Review
    const [step, setStep] = React.useState(1)
    const [isLoading, setIsLoading] = React.useState(false)
    const [courseId, setCourseId] = React.useState<string | null>(initialCourseId || null)
    const [bannerFile, setBannerFile] = React.useState<File | null>(null)
    const [bannerPreview, setBannerPreview] = React.useState<string | null>(null)

    // Fetch initial data if editing
    React.useEffect(() => {
        if (initialCourseId) {
            const fetchCourse = async () => {
                try {
                    const res = await courseApi.getById(initialCourseId)
                    const c = res.data.course
                    setBasicData({
                        title: c.title,
                        description: c.description,
                        category: c.category,
                        price: Number(c.price) || 0,
                        discountPrice: Number(c.discountPrice) || 0,
                        difficulty: c.difficulty,
                        courseCode: c.courseCode || '',
                        bannerUrl: c.bannerUrl || '',
                        jobRoles: c.jobRoles || [],
                        courseType: c.courseType || 'RECORDED',
                        hasInterviewPrep: c.hasInterviewPrep || false,
                        interviewPrice: Number(c.interviewPrice) || 0
                    })
                    if (c.modules) {
                        setModules(c.modules)
                    }
                } catch (error) {
                    console.error("Failed to fetch course", error)
                }
            }
            fetchCourse()
        }
    }, [initialCourseId])

    // Step 1 Data
    const [basicData, setBasicData] = React.useState({
        title: '',
        description: '',
        category: 'Development',
        price: 0,
        discountPrice: 0,
        difficulty: 'BEGINNER',
        courseCode: '',
        bannerUrl: '',
        jobRoles: [] as string[],
        // Course Types
        courseType: 'RECORDED' as 'RECORDED' | 'LIVE' | 'HYBRID',
        hasInterviewPrep: false,
        interviewPrice: 0
    })

    // Step 2 Data (Curriculum)
    interface Lesson {
        id?: string
        title: string
        type: 'VIDEO' | 'TEXT' | 'QUIZ' | 'ASSIGNMENT' | 'PDF'
        duration: number
        videoUrl?: string
        content?: string
        isPublished: boolean
    }
    interface Module {
        id?: string
        title: string
        description: string
        orderIndex: number
        isPublished: boolean
        lessons: Lesson[]
    }
    const [modules, setModules] = React.useState<Module[]>([])
    const [aiTopic, setAiTopic] = React.useState('')
    const [isGenerating, setIsGenerating] = React.useState(false)

    // Handlers
    const handleBasicSubmit = async (e: React.FormEvent) => {
        e.preventDefault()

        // Client-side validation
        if (!basicData.title || basicData.title.trim().length < 3) {
            alert('Title must be at least 3 characters')
            return
        }
        if (!basicData.description || basicData.description.trim().length < 10) {
            alert('Description must be at least 10 characters')
            return
        }
        if (!basicData.category || basicData.category.trim().length < 2) {
            alert('Please select a valid category')
            return
        }

        // Validate image file
        const _validateImage = (file: File | null): boolean => {
            if (!file) return true // optional

            const allowedTypes = ["image/jpeg", "image/png", "image/webp", "image/jpg"]

            if (!allowedTypes.includes(file.type)) {
                alert("Only JPG, PNG, or WEBP images are allowed")
                return false
            }

            const maxSize = 2 * 1024 * 1024 // 2MB

            if (file.size > maxSize) {
                alert("Image size must be less than 2MB")
                return false
            }

            return true
        }


        setIsLoading(true)
        try {
            // Upload banner file first if selected
            let uploadedBannerUrl = basicData.bannerUrl;
            if (bannerFile) {
                const formData = new FormData();
                formData.append('file', bannerFile);
                const uploadRes = await uploadApi.upload(formData);
                uploadedBannerUrl = uploadRes.data.url;
            }

            // Clean jobRoles: remove empty strings
            const cleanJobRoles = Array.isArray(basicData.jobRoles) ? basicData.jobRoles.filter(Boolean) : [];

            // Build payload without bannerUrl first, then add it only if it has a value
            const { bannerUrl: _ignoreBanner, ...basicDataWithoutBanner } = basicData;

            // Ensure all numeric fields are actually numbers (not strings)
            const payload: CoursePayload = {
                ...basicDataWithoutBanner,
                difficulty: basicData.difficulty as 'BEGINNER' | 'INTERMEDIATE' | 'ADVANCED',
                jobRoles: cleanJobRoles,
                price: Number(basicData.price) || 0,
                discountPrice: Number(basicData.discountPrice) || 0,
                interviewPrice: Number(basicData.interviewPrice) || 0,
            };

            // Only include bannerUrl if we have a real value
            if (uploadedBannerUrl && uploadedBannerUrl.length > 0) {
                payload.bannerUrl = uploadedBannerUrl;
            }
            if (courseId) {
                // Update existing
                await courseApi.update(courseId, payload)
            } else {
                // Create new
                const res = await courseApi.create(payload)
                setCourseId(res.data.course.id)
                // Pre-fill AI topic with title
                setAiTopic(basicData.title)
            }
            setStep(2)
        } catch (error: any) {
            console.error('Failed to save course:', error)
            console.error('Response data:', error.response?.data)
            // Show backend validation errors with details
            if (error.response?.data?.details && Array.isArray(error.response.data.details)) {
                const validationErrors = error.response.data.details
                    .map((err: any) => `${err.path?.join('.')} - ${err.message}`)
                    .join('\n')
                alert(`Validation Error:\n${validationErrors}`)
            } else if (error.response?.data?.error) {
                alert(`Error: ${error.response.data.error}`)
            } else if (error.response?.status === 400) {
                alert(`Error: Invalid data. Check console for details.\n${JSON.stringify(error.response.data)}`)
            } else {
                alert(`Error: ${error.message || 'Failed to save course details'}`)
            }
        } finally {
            setIsLoading(false)
        }
    }

    const handleGenerateAI = async () => {
        if (!aiTopic) return
        setIsGenerating(true)
        try {
            const res = await courseApi.generate({
                topic: aiTopic,
                difficulty: basicData.difficulty
            })
            // Auto-fill basic data from AI
            setBasicData(prev => ({
                ...prev,
                title: res.data.courseData.title,
                description: res.data.courseData.description,
                price: res.data.courseData.price,
                discountPrice: res.data.courseData.discountPrice,
                courseCode: res.data.courseData.courseCode,
                bannerUrl: res.data.courseData.bannerUrl,
                jobRoles: res.data.courseData.jobRoles || [],
                difficulty: res.data.courseData.difficulty
            }))
            // Replace modules with generated ones
            setModules(res.data.courseData.modules)
        } catch (error) {
            console.error('AI Generation failed:', error)
            alert('AI Generation failed')
        } finally {
            setIsGenerating(false)
        }
    }

    const handleAddModule = () => {
        const newModule: Module = {
            title: 'New Module',
            description: 'Module description',
            orderIndex: modules.length,
            isPublished: false,
            lessons: []
        }
        setModules([...modules, newModule])
    }

    const handleUpdateModule = (idx: number, updates: Partial<Module>) => {
        const newModules = [...modules]
        newModules[idx] = { ...newModules[idx], ...updates }
        setModules(newModules)
    }

    const handleDeleteModule = (idx: number) => {
        const newModules = modules.filter((_, i) => i !== idx)
        // Update orderIndex for remaining modules
        newModules.forEach((m, i) => { m.orderIndex = i })
        setModules(newModules)
    }

    const handleAddLesson = (moduleIdx: number) => {
        const newLesson: Lesson = {
            title: 'New Lesson',
            type: 'VIDEO',
            duration: 5 * 60,
            isPublished: false
        }
        const newModules = [...modules]
        newModules[moduleIdx].lessons.push(newLesson)
        setModules(newModules)
    }

    const handleDeleteLesson = (moduleIdx: number, lessonIdx: number) => {
        const newModules = [...modules]
        newModules[moduleIdx].lessons = newModules[moduleIdx].lessons.filter((_, i) => i !== lessonIdx)
        setModules(newModules)
    }

    const handleSaveCurriculum = async () => {
        if (!courseId) return
        setIsLoading(true)
        try {
            await courseApi.updateCurriculum(courseId, { modules })
            setStep(3)
        } catch (error) {
            console.error('Failed to save curriculum:', error)
            alert('Failed to save curriculum')
        } finally {
            setIsLoading(false)
        }
    }

    const handleStatusUpdate = async (status: 'DRAFT' | 'IN_REVIEW' | 'PUBLISHED') => {
        if (!courseId) return
        setIsLoading(true)
        try {
            await api.patch(`/courses/${courseId}/status`, { status })
            router.push(redirectPath)
        } catch (error) {
            console.error('Failed to update status:', error)
            alert('Failed to update status')
        } finally {
            setIsLoading(false)
        }
    }

    return (
        <div className="container py-8 max-w-4xl">
            <div className="mb-8">
                <h1 className="text-3xl font-bold mb-2">Create New Course</h1>
                <div className="flex items-center gap-2 text-sm text-muted-foreground">
                    <span className={step >= 1 ? "text-primary font-medium" : ""}>1. Basic Details</span>
                    <ArrowRight className="h-4 w-4" />
                    <span className={step >= 2 ? "text-primary font-medium" : ""}>2. Curriculum</span>
                    <ArrowRight className="h-4 w-4" />
                    <span className={step >= 3 ? "text-primary font-medium" : ""}>3. Review</span>
                </div>
            </div>

            {/* STEP 1: BASIC DETAILS */}
            {step === 1 && (
                <Card>
                    <CardHeader>
                        <CardTitle>Basic Information</CardTitle>
                        <CardDescription>Start by providing the core details of your course.</CardDescription>
                    </CardHeader>
                    <CardContent>
                        <form onSubmit={handleBasicSubmit} className="space-y-4">
                            <div className="space-y-2">
                                <label className="text-sm font-medium">Course Title</label>
                                <Input
                                    value={basicData.title}
                                    onChange={e => setBasicData({ ...basicData, title: e.target.value })}
                                    placeholder="e.g. Master ReactJS in 30 Days"
                                    required
                                />
                            </div>

                            <div className="space-y-2">
                                <label className="text-sm font-medium">Description</label>
                                <Textarea
                                    value={basicData.description}
                                    onChange={e => setBasicData({ ...basicData, description: e.target.value })}
                                    placeholder="What will students learn?"
                                    className="min-h-[100px]"
                                    required
                                />
                            </div>

                            <div className="grid grid-cols-2 gap-4">
                                <div className="space-y-2">
                                    <label className="text-sm font-medium">Category</label>
                                    <select
                                        aria-label="Course Category"
                                        className="w-full p-2 border rounded-md bg-background"
                                        value={basicData.category}
                                        onChange={e => setBasicData({ ...basicData, category: e.target.value })}
                                    >
                                        <option value="Development">Development</option>
                                        <option value="Business">Business</option>
                                        <option value="Design">Design</option>
                                        <option value="Marketing">Marketing</option>
                                    </select>
                                </div>
                                <div className="space-y-2">
                                    <label className="text-sm font-medium">Difficulty</label>
                                    <select
                                        aria-label="Course Difficulty"
                                        className="w-full p-2 border rounded-md bg-background"
                                        value={basicData.difficulty}
                                        onChange={e => setBasicData({ ...basicData, difficulty: e.target.value })}
                                    >
                                        <option value="BEGINNER">Beginner</option>
                                        <option value="INTERMEDIATE">Intermediate</option>
                                        <option value="ADVANCED">Advanced</option>
                                    </select>
                                </div>
                            </div>

                            <div className="space-y-2">
                                <label className="text-sm font-medium">Banner Image</label>
                                <Input
                                    type="file"
                                    accept="image/jpeg,image/png,image/webp,image/jpg"
                                    onChange={(e) => {
                                        const file = e.target.files?.[0] || null

                                        if (!file) return

                                        const allowedTypes = [
                                            "image/jpeg",
                                            "image/png",
                                            "image/webp",
                                            "image/jpg"
                                        ]

                                        if (!allowedTypes.includes(file.type)) {
                                            alert("Only JPG, PNG, WEBP allowed")
                                            return
                                        }

                                        const maxSize = 2 * 1024 * 1024

                                        if (file.size > maxSize) {
                                            alert("Image must be under 2MB")
                                            return
                                        }

                                        setBannerFile(file)
                                        setBannerPreview(URL.createObjectURL(file))
                                    }}
                                />
                                {(bannerPreview || basicData.bannerUrl) && (
                                    <div className="mt-2 rounded-lg overflow-hidden border max-w-xs">
                                        <Image
                                            src={
                                                bannerPreview
                                                    ? bannerPreview
                                                    : basicData.bannerUrl
                                                        ? getFullImageUrl(basicData.bannerUrl)
                                                        : "/placeholder.jpg"
                                            }
                                            alt="Banner preview"
                                            width={400}
                                            height={200}
                                            className="w-full h-32 object-cover"
                                        />
                                    </div>
                                )}
                            </div>

                            <div className="grid grid-cols-2 gap-4">
                                <div className="space-y-2">
                                    <label className="text-sm font-medium">Price (₹)</label>
                                    <Input
                                        type="number"
                                        value={basicData.price}
                                        onChange={e => setBasicData({ ...basicData, price: Number(e.target.value) })}
                                        min="0"
                                    />
                                </div>
                                <div className="space-y-2">
                                    <label className="text-sm font-medium">Discount Price (₹)</label>
                                    <Input
                                        type="number"
                                        value={basicData.discountPrice}
                                        onChange={e => setBasicData({ ...basicData, discountPrice: Number(e.target.value) })}
                                        min="0"
                                    />
                                </div>
                            </div>

                            <div className="space-y-2">
                                <label className="text-sm font-medium">Course Code</label>
                                <Input
                                    value={basicData.courseCode}
                                    onChange={e => setBasicData({ ...basicData, courseCode: e.target.value })}
                                    placeholder="e.g. REACT-101"
                                />
                            </div>

                            <div className="space-y-2">
                                <label className="text-sm font-medium">Job Roles (Comma separated)</label>
                                <Input
                                    value={basicData.jobRoles.join(', ')}
                                    onChange={e => {
                                        const roles = e.target.value
                                            .split(',')
                                            .map(s => s.trim())
                                            .filter(Boolean); // Remove empty strings
                                        setBasicData({ ...basicData, jobRoles: roles });
                                    }}
                                    placeholder="Frontend Dev, UI Engineer..."
                                />
                            </div>

                            {/* Course Type */}
                            <div className="space-y-3 pt-4 border-t">
                                <label className="text-sm font-medium">Course Type</label>
                                <div className="grid grid-cols-3 gap-3">
                                    {[
                                        { value: 'RECORDED', label: 'Recorded', desc: 'Pre-recorded video lessons' },
                                        { value: 'LIVE', label: 'Live', desc: 'Scheduled live sessions' },
                                        { value: 'HYBRID', label: 'Hybrid', desc: 'Mix of live + recorded' }
                                    ].map(type => (
                                        <button
                                            key={type.value}
                                            type="button"
                                            onClick={() => setBasicData({ ...basicData, courseType: type.value as 'RECORDED' | 'LIVE' | 'HYBRID' })}
                                            className={`p-3 rounded-lg border-2 text-left transition-all ${basicData.courseType === type.value
                                                ? 'border-primary bg-primary/5'
                                                : 'border-border hover:border-primary/50'
                                                }`}
                                        >
                                            <div className="font-medium">{type.label}</div>
                                            <div className="text-xs text-muted-foreground">{type.desc}</div>
                                        </button>
                                    ))}
                                </div>
                            </div>

                            {/* Interview Integration */}
                            <div className="space-y-3 pt-4 border-t">
                                <div className="flex items-center justify-between">
                                    <div>
                                        <label className="text-sm font-medium">Interview Prep Integration</label>
                                        <p className="text-xs text-muted-foreground">Link AI interview practice with this course</p>
                                    </div>
                                    <button
                                        type="button"
                                        aria-label="Toggle Interview Prep"
                                        onClick={() => setBasicData({ ...basicData, hasInterviewPrep: !basicData.hasInterviewPrep })}
                                        className={`w-12 h-6 rounded-full transition-colors ${basicData.hasInterviewPrep ? 'bg-primary' : 'bg-muted'
                                            } relative`}
                                    >
                                        <span className={`absolute top-1 w-4 h-4 rounded-full bg-white shadow transition-transform ${basicData.hasInterviewPrep ? 'translate-x-7' : 'translate-x-1'
                                            }`} />
                                    </button>
                                </div>
                                {basicData.hasInterviewPrep && (
                                    <div className="space-y-2">
                                        <label className="text-sm font-medium">Interview Prep Price (₹)</label>
                                        <Input
                                            type="number"
                                            value={basicData.interviewPrice}
                                            onChange={e => setBasicData({ ...basicData, interviewPrice: Number(e.target.value) })}
                                            min="0"
                                            placeholder="Add-on price for interview prep"
                                        />
                                    </div>
                                )}
                            </div>

                            <div className="flex justify-end pt-4">
                                <Button type="submit" disabled={isLoading}>
                                    {isLoading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                                    Next: Curriculum
                                </Button>
                            </div>
                        </form>
                    </CardContent>
                </Card>
            )}

            {/* STEP 2: CURRICULUM */}
            {step === 2 && (
                <div className="space-y-6">
                    {/* AI Generator Box */}
                    <Card className="border-primary/50 bg-primary/5">
                        <CardHeader>
                            <CardTitle className="flex items-center gap-2">
                                <Wand2 className="h-5 w-5 text-primary" />
                                AI Curriculum Generator
                            </CardTitle>
                            <CardDescription>
                                Automatically generate modules and lessons structure based on your topic.
                            </CardDescription>
                        </CardHeader>
                        <CardContent>
                            <div className="flex gap-4">
                                <Input
                                    value={aiTopic}
                                    onChange={e => setAiTopic(e.target.value)}
                                    placeholder="Enter topic (e.g. Advanced Python Patterns)"
                                />
                                <Button onClick={handleGenerateAI} disabled={isGenerating}>
                                    {isGenerating ? (
                                        <>
                                            <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                                            Generating...
                                        </>
                                    ) : (
                                        <>
                                            <Wand2 className="mr-2 h-4 w-4" />
                                            Generate
                                        </>
                                    )}
                                </Button>
                            </div>
                        </CardContent>
                    </Card>

                    {/* Modules List */}
                    <Card>
                        <CardHeader className="flex flex-row items-center justify-between">
                            <CardTitle>Course Curriculum</CardTitle>
                            <Button variant="outline" size="sm" onClick={handleAddModule}>
                                <Plus className="mr-2 h-4 w-4" /> Add Module
                            </Button>
                        </CardHeader>
                        <CardContent>
                            {modules.length === 0 ? (
                                <div className="text-center py-12 text-muted-foreground border-dashed border-2 rounded-lg">
                                    No modules yet. Use the AI Generator above or add manually.
                                </div>
                            ) : (
                                <div className="space-y-4">
                                    {modules.map((mod, idx) => (
                                        <div key={idx} className="border rounded-lg p-4 bg-card">
                                            <div className="flex items-center justify-between mb-3">
                                                <div className="flex items-center gap-3 flex-1">
                                                    <GripVertical className="h-5 w-5 text-muted-foreground" />
                                                    <div className="flex-1">
                                                        <Input
                                                            type="text"
                                                            placeholder="Module title"
                                                            className="h-8 font-medium mb-2"
                                                            value={mod.title}
                                                            onChange={(e) => handleUpdateModule(idx, { title: e.target.value })}
                                                        />
                                                        <Textarea
                                                            placeholder="Module description"
                                                            className="text-sm min-h-[50px]"
                                                            value={mod.description}
                                                            onChange={(e) => handleUpdateModule(idx, { description: e.target.value })}
                                                        />
                                                    </div>
                                                </div>
                                                <div className="flex items-center gap-2">
                                                    <Badge variant="secondary">{mod.lessons.length} Lessons</Badge>
                                                    <Button
                                                        variant="destructive"
                                                        size="sm"
                                                        onClick={() => {
                                                            if (confirm('Delete this module?')) {
                                                                handleDeleteModule(idx)
                                                            }
                                                        }}
                                                    >
                                                        Delete
                                                    </Button>
                                                </div>
                                            </div>
                                            <div className="pl-8 space-y-4 border-l-2 ml-2">
                                                {mod.lessons.map((lesson, lIdx) => (
                                                    <div key={lIdx} className="p-4 bg-muted/30 rounded border space-y-3">
                                                        <div className="flex items-center justify-between">
                                                            <div className="flex items-center gap-2">
                                                                <span className="font-medium text-sm">Lesson {lIdx + 1}: {lesson.title}</span>
                                                                <Badge variant="outline" className="text-[10px]">{lesson.type}</Badge>
                                                                <Badge variant={lesson.isPublished ? 'default' : 'secondary'} className="text-[10px]">
                                                                    {lesson.isPublished ? 'Published' : 'Draft'}
                                                                </Badge>
                                                            </div>
                                                            <div className="flex items-center gap-2">
                                                                <span className="text-xs text-muted-foreground">{Math.round(lesson.duration / 60)} min</span>
                                                                {/* Simple Toggle for Publish */}
                                                                <Button
                                                                    variant="ghost"
                                                                    size="sm"
                                                                    onClick={() => {
                                                                        const newModules = [...modules]
                                                                        newModules[idx].lessons[lIdx].isPublished = !lesson.isPublished
                                                                        setModules(newModules)
                                                                    }}
                                                                >
                                                                    {lesson.isPublished ? 'Unpublish' : 'Publish'}
                                                                </Button>
                                                            </div>
                                                        </div>

                                                        {/* Type & Content Editor */}
                                                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                                            <div>
                                                                <label className="text-xs font-medium">Type</label>
                                                                <select
                                                                    aria-label="Lesson Type"
                                                                    className="w-full p-2 h-9 text-sm border rounded bg-background"
                                                                    value={lesson.type}
                                                                    onChange={(e) => {
                                                                        const newModules = [...modules]
                                                                        newModules[idx].lessons[lIdx].type = e.target.value as any
                                                                        setModules(newModules)
                                                                    }}
                                                                >
                                                                    <option value="VIDEO">Video Lesson</option>
                                                                    <option value="TEXT">Text / Article</option>
                                                                    <option value="PDF">PDF Resource</option>
                                                                    <option value="QUIZ">Quiz / Test</option>
                                                                    <option value="ASSIGNMENT">Assignment</option>
                                                                </select>
                                                            </div>
                                                            <div>
                                                                <label className="text-xs font-medium">Duration (sec)</label>
                                                                <Input
                                                                    type="number"
                                                                    className="h-9"
                                                                    value={lesson.duration}
                                                                    onChange={(e) => {
                                                                        const newModules = [...modules]
                                                                        newModules[idx].lessons[lIdx].duration = Number(e.target.value)
                                                                        setModules(newModules)
                                                                    }}
                                                                />
                                                            </div>
                                                        </div>

                                                        {/* Dynamic Content Input based on Type */}
                                                        {lesson.type === 'VIDEO' && (
                                                            <div className="bg-background rounded p-2 border">
                                                                <VideoUpload
                                                                    label={`Video Source`}
                                                                    initialUrl={lesson.videoUrl}
                                                                    onUploadComplete={(url) => {
                                                                        const newModules = [...modules]
                                                                        newModules[idx].lessons[lIdx].videoUrl = url
                                                                        setModules(newModules)
                                                                    }}
                                                                />
                                                            </div>
                                                        )}

                                                        {(lesson.type === 'TEXT' || lesson.type === 'PDF' || lesson.type === 'ASSIGNMENT') && (
                                                            <div className="space-y-2">
                                                                <label className="text-xs font-medium">
                                                                    {lesson.type === 'PDF' ? 'PDF URL' : 'Content / Instructions'}
                                                                </label>
                                                                <Textarea
                                                                    className="min-h-[100px]"
                                                                    placeholder={lesson.type === 'PDF' ? 'Paste PDF link here...' : 'Write content details...'}
                                                                    value={lesson.content || ''}
                                                                    onChange={(e) => {
                                                                        const newModules = [...modules]
                                                                        newModules[idx].lessons[lIdx].content = e.target.value
                                                                        setModules(newModules)
                                                                    }}
                                                                />
                                                            </div>
                                                        )}

                                                        {lesson.type === 'QUIZ' && (
                                                            <div className="p-3 bg-yellow-50 text-yellow-800 text-xs rounded border border-yellow-200">
                                                                Quiz configuration is handled in the dedicated Quiz Builder after saving.
                                                            </div>
                                                        )}
                                                    </div>
                                                ))}
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            )}

                            <div className="flex justify-between mt-8 pt-4 border-t">
                                <Button variant="ghost" onClick={() => setStep(1)}>Back</Button>
                                <Button onClick={handleSaveCurriculum} disabled={modules.length === 0 || isLoading}>
                                    {isLoading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                                    Save & Continue
                                </Button>
                            </div>
                        </CardContent>
                    </Card>
                </div>
            )}

            {/* STEP 3: REVIEW & DEPLOY */}
            {step === 3 && (
                <Card>
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2 text-green-600">
                            <CheckCircle className="h-6 w-6" />
                            Ready to Deploy!
                        </CardTitle>
                        <CardDescription>
                            Review your course details and choose how to publish.
                        </CardDescription>
                    </CardHeader>
                    <CardContent className="space-y-6">
                        {/* Course Summary */}
                        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-sm">
                            <div>
                                <span className="text-muted-foreground">Title:</span>
                                <p className="font-medium">{basicData.title}</p>
                            </div>
                            <div>
                                <span className="text-muted-foreground">Category:</span>
                                <p className="font-medium">{basicData.category}</p>
                            </div>
                            <div>
                                <span className="text-muted-foreground">Course Type:</span>
                                <p className="font-medium">{basicData.courseType}</p>
                            </div>
                            <div>
                                <span className="text-muted-foreground">Difficulty:</span>
                                <p className="font-medium">{basicData.difficulty}</p>
                            </div>
                            <div>
                                <span className="text-muted-foreground">Modules:</span>
                                <p className="font-medium">{modules.length}</p>
                            </div>
                            <div>
                                <span className="text-muted-foreground">Total Lessons:</span>
                                <p className="font-medium">{modules.reduce((acc, m) => acc + m.lessons.length, 0)}</p>
                            </div>
                            <div>
                                <span className="text-muted-foreground">Price:</span>
                                <p className="font-medium">₹{basicData.price}</p>
                            </div>
                            <div>
                                <span className="text-muted-foreground">Interview Prep:</span>
                                <p className="font-medium">{basicData.hasInterviewPrep ? 'Yes' : 'No'}</p>
                            </div>
                        </div>

                        {/* Deployment Options */}
                        <div className="border-t pt-6">
                            <h4 className="font-medium mb-4">Choose Deployment Option</h4>
                            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                                <button
                                    type="button"
                                    onClick={() => handleStatusUpdate('DRAFT')}
                                    className="p-4 border rounded-lg text-left hover:border-primary transition-colors"
                                >
                                    <div className="font-medium text-muted-foreground">Save as Draft</div>
                                    <p className="text-xs text-muted-foreground mt-1">Save for later editing. Not visible to students.</p>
                                </button>
                                <button
                                    type="button"
                                    onClick={() => handleStatusUpdate('IN_REVIEW')}
                                    className="p-4 border rounded-lg text-left hover:border-primary transition-colors"
                                >
                                    <div className="font-medium text-orange-600">Submit for Review</div>
                                    <p className="text-xs text-muted-foreground mt-1">Send to admin for approval before publishing.</p>
                                </button>
                                <button
                                    type="button"
                                    onClick={() => handleStatusUpdate('PUBLISHED')}
                                    className="p-4 border-2 border-primary rounded-lg text-left bg-primary/5"
                                >
                                    <div className="font-medium text-primary">Publish Now</div>
                                    <p className="text-xs text-muted-foreground mt-1">Make visible to all students immediately.</p>
                                </button>
                            </div>
                        </div>

                        {/* Actions */}
                        <div className="flex gap-4 pt-4 border-t">
                            <Button variant="outline" onClick={() => setStep(2)}>
                                <ArrowLeft className="mr-2 h-4 w-4" />
                                Back to Curriculum
                            </Button>
                            <Button variant="outline" className="flex-1" onClick={() => router.push(`/courses/${courseId}`)}>
                                Preview Course
                            </Button>
                        </div>
                    </CardContent>
                </Card>
            )}
        </div>
    )
}

"use client"

import * as React from 'react'
import Image from 'next/image'
import { useRouter } from 'next/navigation'
import { courseApi } from '@/lib/api'
import { useAuth } from '@/lib/auth-context'
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { GraduationCap, Search, Loader2 } from 'lucide-react'
import { getFullImageUrl } from '@/lib/image-utils'

interface Course {
    id: string
    title: string
    description: string
    category: string
    difficulty: string
    duration: number
    price: number
    thumbnail?: string
    bannerUrl?: string
    instructor?: { name: string }
    _count?: { enrollments: number }
    isEnrolled?: boolean
}

const categories = [
    { value: '', label: 'All Categories' },
    { value: 'WEB_DEV', label: 'Web Development' },
    { value: 'DATA_SCIENCE', label: 'Data Science' },
    { value: 'MOBILE', label: 'Mobile Development' },
    { value: 'CLOUD', label: 'Cloud Computing' },
    { value: 'AI_ML', label: 'AI & Machine Learning' },
]

const difficulties = [
    { value: '', label: 'All Levels' },
    { value: 'BEGINNER', label: 'Beginner' },
    { value: 'INTERMEDIATE', label: 'Intermediate' },
    { value: 'ADVANCED', label: 'Advanced' },
]

export default function CourseList() {
    const router = useRouter()
    const { isAuthenticated } = useAuth()

    const [courses, setCourses] = React.useState<Course[]>([])
    const [isLoading, setIsLoading] = React.useState(true)
    const [search, setSearch] = React.useState('')
    const [category, setCategory] = React.useState('')
    const [difficulty, setDifficulty] = React.useState('')
    const [_enrollingId, setEnrollingId] = React.useState<string | null>(null)

    React.useEffect(() => {
        const abortController = new AbortController()
        
        const fetchCourses = async () => {
            try {
                setIsLoading(true)
                const response = await courseApi.getAll({
                    search: search || undefined,
                    category: category || undefined
                })
                if (!abortController.signal.aborted) {
                    setCourses(response.data.courses || [])
                }
            } catch (error) {
                if (!abortController.signal.aborted) {
                    console.error('Failed to fetch courses:', error)
                }
            } finally {
                if (!abortController.signal.aborted) {
                    setIsLoading(false)
                }
            }
        }

        const debounce = setTimeout(fetchCourses, 300)
        return () => {
            clearTimeout(debounce)
            abortController.abort()
        }
    }, [search, category])

    const _handleEnroll = async (courseId: string) => {
        if (!isAuthenticated) {
            router.push('/login')
            return
        }

        setEnrollingId(courseId)
        try {
            await courseApi.enroll(courseId)
            setCourses(courses.map(c =>
                c.id === courseId ? { ...c, isEnrolled: true } : c
            ))
        } catch (error) {
            console.error('Failed to enroll:', error)
        } finally {
            setEnrollingId(null)
        }
    }

    const filteredCourses = difficulty
        ? courses.filter(c => c.difficulty === difficulty)
        : courses

    const getDifficultyColor = (diff: string) => {
        switch (diff) {
            case 'BEGINNER': return 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400'
            case 'INTERMEDIATE': return 'bg-yellow-100 text-yellow-700 dark:bg-yellow-900/30 dark:text-yellow-400'
            case 'ADVANCED': return 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400'
            default: return 'bg-gray-100 text-gray-700'
        }
    }

    return (
        <div className="container py-8">
            {/* Header */}
            <div className="mb-8">
                <h1 className="text-4xl font-extrabold tracking-tight mb-2">Explore AI-Adaptive Courses</h1>
                <p className="text-xl text-muted-foreground">
                    Master the most in-demand tech skills with our personalized learning paths.
                </p>
            </div>

            {/* Filters */}
            <div className="flex flex-col md:flex-row gap-4 mb-8">
                <div className="relative md:w-1/2">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                    <Input
                        placeholder="Search courses (e.g., React, AI, Python)..."
                        value={search}
                        onChange={(e) => setSearch(e.target.value)}
                        className="pl-10 h-10"
                    />
                </div>
                <select
                    title="Filter by Category"
                    value={category}
                    onChange={(e) => setCategory(e.target.value)}
                    className="h-10 px-3 rounded-md border border-input bg-background text-sm min-w-[150px]"
                >
                    {categories.map(cat => (
                        <option key={cat.value} value={cat.value}>{cat.label}</option>
                    ))}
                </select>
                <select
                    title="Filter by Difficulty"
                    value={difficulty}
                    onChange={(e) => setDifficulty(e.target.value)}
                    className="h-10 px-3 rounded-md border border-input bg-background text-sm min-w-[150px]"
                >
                    {difficulties.map(diff => (
                        <option key={diff.value} value={diff.value}>{diff.label}</option>
                    ))}
                </select>
            </div>

            {/* Course Grid */}
            {isLoading ? (
                <div className="flex items-center justify-center py-20">
                    <Loader2 className="h-8 w-8 animate-spin text-primary" />
                </div>
            ) : filteredCourses.length === 0 ? (
                <div className="text-center py-20 bg-muted/30 rounded-3xl">
                    <GraduationCap className="h-12 w-12 mx-auto text-muted-foreground mb-4 opacity-20" />
                    <h3 className="text-lg font-medium">No courses found matching your criteria</h3>
                    <p className="text-muted-foreground">Try adjusting your search or filters to see more results.</p>
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                    {filteredCourses.map((course) => (
                        <Card
                            key={course.id}
                            className="flex flex-col group hover:shadow-2xl transition-all duration-300 rounded-2xl overflow-hidden border-border/50 cursor-pointer"
                            onClick={() => router.push(`/courses/${course.id}`)}
                        >
                            <div className="h-48 relative bg-gradient-to-br from-primary/10 via-purple-500/10 to-blue-500/10 flex items-center justify-center overflow-hidden">
                                {course.bannerUrl || course.thumbnail ? (
                                    <Image
                                        src={getFullImageUrl(course.bannerUrl || course.thumbnail)}
                                        alt={course.title}
                                        width={400}
                                        height={192}
                                        className="absolute inset-0 w-full h-full object-cover"
                                        onError={(e) => {
                                            const target = e.target as HTMLImageElement;
                                            target.style.display = "none";
                                        }}
                                    />
                                ) : null}
                                <GraduationCap className={`h-20 w-20 text-primary/30 ${(course.bannerUrl || course.thumbnail) ? 'hidden' : ''}`} />
                            </div>
                            <CardHeader className="pb-2">
                                <div className="flex items-center justify-between mb-3">
                                    <span className={`text-[10px] uppercase tracking-widest font-bold px-2 py-1 rounded-md ${getDifficultyColor(course.difficulty)}`}>
                                        {course.difficulty}
                                    </span>
                                    <span className="text-xs font-semibold text-primary/70">{course.category}</span>
                                </div>
                                <CardTitle className="text-xl line-clamp-1 group-hover:text-primary transition-colors">{course.title}</CardTitle>
                                <CardDescription className="line-clamp-2 text-sm leading-relaxed">{course.description}</CardDescription>
                            </CardHeader>

                            <CardFooter className="pt-4 border-t border-border/10 flex items-center justify-between bg-muted/5">
                                <div className="flex flex-col">
                                    <span className="text-[10px] text-muted-foreground font-bold uppercase tracking-tight">Price</span>
                                    <span className="text-2xl font-black text-foreground">
                                        {course.price === 0 ? 'Free' : `₹${course.price}`}
                                    </span>
                                </div>
                                {course.isEnrolled && (
                                    <span className="text-xs px-3 py-1.5 bg-green-50 text-green-700 border border-green-200 rounded-full font-semibold dark:bg-green-900/30 dark:text-green-400 dark:border-green-800">
                                        ✓ Enrolled
                                    </span>
                                )}
                            </CardFooter>
                        </Card>
                    ))}
                </div>
            )}
        </div>
    )
}

