'use client'

import React, { useState } from 'react'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from '@/components/ui/dialog'
import { useToast } from '@/components/ui/use-toast'
import { employerRequestApi } from '@/lib/api'
import { Briefcase } from 'lucide-react'

// Personal email domains to reject
const PERSONAL_DOMAINS = [
  'gmail.com',
  'yahoo.com',
  'hotmail.com',
  'outlook.com',
  'aol.com',
  'mail.com',
  'windows.live.com',
  'yandex.com',
  'protonmail.com',
  'icloud.com',
  'mail.ru',
]

function isBusinessEmail(email: string): boolean {
  console.log('[isBusinessEmail] Checking email:', email)
  if (!email || !email.includes('@')) {
    console.log('[isBusinessEmail] Invalid email format (no @)')
    return false
  }
  const domain = email.split('@')[1].toLowerCase()
  console.log('[isBusinessEmail] Extracted domain:', domain)
  console.log('[isBusinessEmail] PERSONAL_DOMAINS:', PERSONAL_DOMAINS)
  const isPersonal = PERSONAL_DOMAINS.includes(domain)
  console.log('[isBusinessEmail] Is personal domain:', isPersonal)
  const result = !isPersonal
  console.log('[isBusinessEmail] Result (is business):', result)
  return result
}

interface FormData {
  name: string
  designation: string
  email: string
  phone: string
}

export default function EmployerRequestDialog() {
  const { toast } = useToast()
  const [isOpen, setIsOpen] = useState(false)
  const [isLoading, setIsLoading] = useState(false)
  const [errors, setErrors] = useState<{ [key: string]: string }>({})
  const [formData, setFormData] = useState<FormData>({
    name: '',
    designation: '',
    email: '',
    phone: '',
  })

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target
    setFormData(prev => ({
      ...prev,
      [name]: value
    }))
  }

  const validateForm = (): { [key: string]: string } => {
    const newErrors: { [key: string]: string } = {}

    if (!formData.name.trim()) {
      newErrors.name = 'Name is required'
    }

    if (!formData.designation.trim()) {
      newErrors.designation = 'Designation is required'
    }

    if (!formData.email.trim()) {
      newErrors.email = 'Email is required'
    } else {
      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/
      if (!emailRegex.test(formData.email)) {
        newErrors.email = 'Invalid email format'
      } else {
        const isValidBusiness = isBusinessEmail(formData.email)
        console.log('[Validation] Email:', formData.email, 'Is Business Email:', isValidBusiness)
        
        if (!isValidBusiness) {
          newErrors.email = 'Please use your company email. Personal email domains (Gmail, Yahoo, Outlook, etc.) are not allowed.'
        }
      }
    }

    setErrors(newErrors)
    return newErrors
  }
  const handleSubmit = async (e: React.FormEvent) => {
    console.log('[EmployerRequest] handleSubmit called', e)
    e.preventDefault()
    console.log('[EmployerRequest] preventDefault called')

    const validationErrors = validateForm()
    console.log('[EmployerRequest] Validation Errors:', validationErrors)
    console.log('[EmployerRequest] Form Data:', formData)
    
    if (Object.keys(validationErrors).length > 0) {
      console.log('[EmployerRequest] Showing validation error toast')
      // Show the first error in toast
      const firstErrorKey = Object.keys(validationErrors)[0]
      const firstErrorMessage = validationErrors[firstErrorKey]
      
      toast({
        title: 'Validation Error',
        description: firstErrorMessage,
        variant: 'destructive',
      })
      return
    }

    setIsLoading(true)
    try {
      console.log('[EmployerRequest] Submitting form with data:', {
        name: formData.name.trim(),
        designation: formData.designation.trim(),
        email: formData.email.trim(),
        phone: formData.phone.trim() || undefined,
      })

      const response = await employerRequestApi.submit({
        name: formData.name.trim(),
        designation: formData.designation.trim(),
        email: formData.email.trim(),
        phone: formData.phone.trim() || undefined,
      })

      console.log('[EmployerRequest] Success response:', response)

      toast({
        title: 'Success',
        description: response.data.message || 'Employer request submitted successfully. Admin will review and contact you soon.',
        variant: 'default',
      })

      // Reset form and close dialog
      setFormData({
        name: '',
        designation: '',
        email: '',
        phone: '',
      })
      setErrors({})
      setIsOpen(false)
    } catch (error: any) {
      console.error('[EmployerRequest] Error:', error)
      console.error('[EmployerRequest] Error Response:', error.response?.data)
      
      const errorMessage = error.response?.data?.message || error.message || 'Failed to submit employer request'
      toast({
        title: 'Error',
        description: errorMessage,
        variant: 'destructive',
      })
    } finally {
      setIsLoading(false)
    }
  }

  return (
    <Dialog open={isOpen} onOpenChange={setIsOpen}>
      <DialogTrigger asChild>
        <Button variant="outline" size="sm" className="gap-2">
          <Briefcase className="h-4 w-4" />
          Request Employer
        </Button>
      </DialogTrigger>
      <DialogContent className="sm:max-w-[500px]">
        <DialogHeader>
          <DialogTitle>Request Employer to Post Jobs</DialogTitle>
          <DialogDescription>
            Tell us about the employer you'd like to see posting jobs on TechWell
          </DialogDescription>
        </DialogHeader>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="space-y-2">
            <label htmlFor="name" className="text-sm font-medium">
              Employer Name <span className="text-red-500">*</span>
            </label>
            <Input
              id="name"
              name="name"
              placeholder="e.g., Acme Corp"
              value={formData.name}
              onChange={handleInputChange}
              disabled={isLoading}
              className={errors.name ? 'border-red-500 border-2' : ''}
            />
            {errors.name && (
              <p className="text-sm font-medium text-red-600">{errors.name}</p>
            )}
          </div>

          <div className="space-y-2">
            <label htmlFor="designation" className="text-sm font-medium">
              Your Designation <span className="text-red-500">*</span>
            </label>
            <Input
              id="designation"
              name="designation"
              placeholder="e.g., Hiring Manager"
              value={formData.designation}
              onChange={handleInputChange}
              disabled={isLoading}
              className={errors.designation ? 'border-red-500 border-2' : ''}
            />
            {errors.designation && (
              <p className="text-sm font-medium text-red-600">{errors.designation}</p>
            )}
          </div>

          <div className="space-y-2">
            <label htmlFor="email" className="text-sm font-medium">
              Company Email <span className="text-red-500">*</span>
            </label>
            <Input
              id="email"
              name="email"
              type="email"
              placeholder="your.name@company.com"
              value={formData.email}
              onChange={handleInputChange}
              disabled={isLoading}
              className={errors.email ? 'border-red-500 border-2' : ''}
            />
            {errors.email && (
              <p className="text-sm font-medium text-red-600">{errors.email}</p>
            )}
            {!errors.email && (
              <p className="text-xs text-muted-foreground">
                Please use your company email address (not Gmail, Yahoo, Outlook, etc.)
              </p>
            )}
          </div>

          <div className="space-y-2">
            <label htmlFor="phone" className="text-sm font-medium">
              Phone (Optional)
            </label>
            <Input
              id="phone"
              name="phone"
              type="tel"
              placeholder="+1 (555) 123-4567"
              value={formData.phone}
              onChange={handleInputChange}
              disabled={isLoading}
            />
          </div>

          <div className="bg-blue-50 dark:bg-blue-950/20 border border-blue-200 dark:border-blue-900 rounded-lg p-3">
            <p className="text-sm text-blue-900 dark:text-blue-200">
              <span className="font-semibold">What happens next?</span> Your request will be reviewed by our admin team. Once approved, the employer will be able to post jobs on TechWell.
            </p>
          </div>

          <div className="flex justify-end gap-3 pt-4">
            <Button
              type="button"
              variant="outline"
              onClick={() => setIsOpen(false)}
              disabled={isLoading}
            >
              Cancel
            </Button>
            <Button
              type="submit"
              disabled={isLoading}
            >
              {isLoading ? 'Submitting...' : 'Submit Request'}
            </Button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  )
}

import React, { useState, useEffect } from 'react'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import {
    Mail,
    Bell,
    Clock,
    Loader2,
    AlertCircle,
    CheckCircle2,
    Trash2,
    Eye,
} from 'lucide-react'
import api from '@/lib/api'

interface AdminMessage {
    id: string
    message: {
        id: string
        title: string
        content: string
        priority: string
        sender: {
            id: string
            name: string
            email: string
            avatar?: string
        }
        createdAt: string
    }
    isRead: boolean
    readAt?: string
}

export function StudentMessages() {
    const [messages, setMessages] = useState<AdminMessage[]>([])
    const [unreadCount, setUnreadCount] = useState(0)
    const [loading, setLoading] = useState(true)
    const [expandedId, setExpandedId] = useState<string | null>(null)
    const [filterRead, setFilterRead] = useState<'all' | 'unread'>('all')
    const [error, setError] = useState<string | null>(null)

    useEffect(() => {
        fetchMessages()
        fetchUnreadCount()

        // Set up polling to refresh messages every 30 seconds
        const interval = setInterval(() => {
            fetchMessages()
            fetchUnreadCount()
        }, 30000)

        return () => clearInterval(interval)
    }, [])

    const fetchMessages = async () => {
        try {
            setError(null)
            const response = await api.get('/messages/my-messages?skip=0&take=20')
            setMessages(response.data.data || [])
        } catch (err) {
            setError('Failed to load messages. Please try again later.')
            setMessages([])
        } finally {
            setLoading(false)
        }
    }

    const fetchUnreadCount = async () => {
        try {
            const response = await api.get('/messages/unread-count')
            setUnreadCount(response.data.unreadCount || 0)
        } catch (error) {
            console.error('Error fetching unread count:', error)
        }
    }

    const handleMarkAsRead = async (messageId: string) => {
        try {
            await api.put(`/messages/${messageId}/read`)
            fetchMessages()
            fetchUnreadCount()
        } catch (error) {
            console.error('Error marking message as read:', error)
        }
    }

    const filteredMessages = filterRead === 'unread' 
        ? messages.filter(m => !m.isRead)
        : messages

    const getPriorityColor = (priority: string) => {
        switch (priority) {
            case 'URGENT':
                return 'bg-red-100 text-red-800 hover:bg-red-200'
            case 'HIGH':
                return 'bg-orange-100 text-orange-800 hover:bg-orange-200'
            case 'NORMAL':
                return 'bg-blue-100 text-blue-800 hover:bg-blue-200'
            case 'LOW':
                return 'bg-gray-100 text-gray-800 hover:bg-gray-200'
            default:
                return 'bg-slate-100 text-slate-800'
        }
    }

    return (
        <Card className="col-span-1 md:col-span-2">
            <CardHeader className="flex flex-row items-center justify-between space-y-0">
                <div className="space-y-1">
                    <CardTitle className="flex items-center gap-2">
                        <Bell className="w-5 h-5 text-blue-600" />
                        Messages
                    </CardTitle>
                    <CardDescription>
                        Instructions and announcements from your instructors
                    </CardDescription>
                </div>
                {unreadCount > 0 && (
                    <Badge variant="destructive" className="rounded-full px-3 py-1">
                        {unreadCount} New
                    </Badge>
                )}
            </CardHeader>

            <CardContent>
                {error ? (
                    <div className="text-center py-8">
                        <AlertCircle className="mx-auto h-12 w-12 text-red-400 mb-3" />
                        <p className="text-red-500 font-medium">{error}</p>
                    </div>
                ) : loading ? (
                    <div className="flex items-center justify-center py-12">
                        <Loader2 className="h-6 w-6 animate-spin text-blue-600" />
                    </div>
                ) : filteredMessages.length === 0 ? (
                    <div className="text-center py-8">
                        <Mail className="mx-auto h-12 w-12 text-gray-400 mb-3" />
                        <p className="text-gray-500 font-medium">
                            {filterRead === 'unread' ? 'No unread messages' : 'No messages yet'}
                        </p>
                        <p className="text-gray-400 text-sm">
                            {filterRead === 'unread'
                                ? 'All caught up! Check back soon.'
                                : "You don't have any messages yet."}
                        </p>
                    </div>
                ) : (
                    <div className="space-y-4">
                        {/* Filter Buttons */}
                        <div className="flex gap-2 mb-4">
                            <Button
                                variant={filterRead === 'all' ? 'default' : 'outline'}
                                size="sm"
                                onClick={() => setFilterRead('all')}
                            >
                                All ({messages.length})
                            </Button>
                            <Button
                                variant={filterRead === 'unread' ? 'default' : 'outline'}
                                size="sm"
                                onClick={() => setFilterRead('unread')}
                            >
                                Unread ({unreadCount})
                            </Button>
                        </div>

                        {/* Messages List */}
                        <div className="space-y-3 max-h-96 overflow-y-auto">
                            {filteredMessages.map((messageItem) => {
                                const msg = messageItem.message
                                const isExpanded = expandedId === msg.id
                                const isUnread = !messageItem.isRead

                                return (
                                    <div
                                        key={msg.id}
                                        className={`border rounded-lg p-4 transition-all ${
                                            isUnread
                                                ? 'bg-blue-50 border-blue-200'
                                                : 'bg-white border-gray-200 hover:border-gray-300'
                                        }`}
                                    >
                                        {/* Message Header */}
                                        <div className="flex items-start justify-between gap-3">
                                            <div className="flex-1 min-w-0">
                                                <div className="flex items-center gap-2 mb-1">
                                                    {isUnread && (
                                                        <div className="w-2 h-2 rounded-full bg-blue-600 flex-shrink-0" />
                                                    )}
                                                    <h3 className="font-semibold text-slate-900 truncate">
                                                        {msg.title}
                                                    </h3>
                                                    <Badge className={`flex-shrink-0 ${getPriorityColor(msg.priority)}`}>
                                                        {msg.priority}
                                                    </Badge>
                                                </div>
                                                <div className="flex items-center gap-2 text-sm text-slate-600">
                                                    <span className="font-medium">{msg.sender.name}</span>
                                                    <span>•</span>
                                                    <div className="flex items-center gap-1">
                                                        <Clock className="w-3 h-3" />
                                                        {new Date(msg.createdAt).toLocaleDateString()}
                                                    </div>
                                                </div>
                                            </div>

                                            {/* Action Buttons */}
                                            <div className="flex gap-1 flex-shrink-0">
                                                <Button
                                                    variant="ghost"
                                                    size="sm"
                                                    onClick={() => setExpandedId(isExpanded ? null : msg.id)}
                                                    className="text-gray-600"
                                                >
                                                    <Eye className="w-4 h-4" />
                                                </Button>
                                                {isUnread && (
                                                    <Button
                                                        variant="ghost"
                                                        size="sm"
                                                        onClick={() => handleMarkAsRead(msg.id)}
                                                        className="text-green-600 hover:text-green-700"
                                                    >
                                                        <CheckCircle2 className="w-4 h-4" />
                                                    </Button>
                                                )}
                                            </div>
                                        </div>

                                        {/* Expanded Content */}
                                        {isExpanded && (
                                            <div className="mt-3 pt-3 border-t border-gray-200 space-y-2">
                                                <div className="prose prose-sm max-w-none text-slate-700 whitespace-pre-wrap">
                                                    {msg.content}
                                                </div>
                                                {messageItem.readAt && (
                                                    <div className="text-xs text-slate-500">
                                                        Read on {new Date(messageItem.readAt).toLocaleString()}
                                                    </div>
                                                )}
                                            </div>
                                        )}
                                    </div>
                                )
                            })}
                        </div>
                    </div>
                )}
            </CardContent>
        </Card>
    )
}

import React, { useState } from 'react'
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Textarea } from '@/components/ui/textarea'
import api from '@/lib/api'

export function StudentSendMessage() {
    const [title, setTitle] = useState('')
    const [content, setContent] = useState('')
    const [loading, setLoading] = useState(false)
    const [success, setSuccess] = useState('')
    const [error, setError] = useState('')

    const handleSend = async () => {
        setLoading(true)
        setError('')
        setSuccess('')
        try {
            await api.post('/messages/send-to-admin', { title, content })
            setSuccess('Message sent to admin successfully!')
            setTitle('')
            setContent('')
        } catch (err) {
            setError('Failed to send message. Please try again later.')
        } finally {
            setLoading(false)
        }
    }

    return (
        <Card className="my-6">
            <CardHeader>
                <CardTitle>Contact Admin</CardTitle>
                <CardDescription>Send a message to the superadmin</CardDescription>
            </CardHeader>
            <CardContent>
                <div className="space-y-4">
                    <Textarea
                        placeholder="Title"
                        value={title}
                        onChange={e => setTitle(e.target.value)}
                        className="mb-2"
                    />
                    <Textarea
                        placeholder="Your message"
                        value={content}
                        onChange={e => setContent(e.target.value)}
                        rows={4}
                    />
                    {error && <div className="text-red-500 text-sm">{error}</div>}
                    {success && <div className="text-green-600 text-sm">{success}</div>}
                    <Button onClick={handleSend} disabled={loading || !title || !content}>
                        {loading ? 'Sending...' : 'Send Message'}
                    </Button>
                </div>
            </CardContent>
        </Card>
    )
}

