"use client";

import React, { useState } from "react";
import axios from "axios";
import html2pdf from "html2pdf.js";

import ModernTemplate from "./templates/ModernTemplate";
import ProfessionalTemplate from "./templates/ProfessionalTemplate";
import MinimalTemplate from "./templates/MinimalTemplate";

type TemplateType = "modern" | "professional" | "minimal";

/**
 * IMPORTANT:
 * Using unified type for templates to avoid TS mismatch errors
 */
type ResumeFormData = any;

const TEMPLATES: Record<TemplateType, React.FC<ResumeFormData>> = {
  modern: ModernTemplate,
  professional: ProfessionalTemplate,
  minimal: MinimalTemplate,
};

const API_URL =
  process.env.NEXT_PUBLIC_API_URL || "http://localhost:5000/api";

const initialState = {
  fullName: "",
  professionalTitle: "",
  phone: "",
  email: "",
  linkedIn: "",
  github: "",
  portfolio: "",
  summary: "",

  skills: [{ name: "", proficiency: "" }],

  experience: [
    {
      jobTitle: "",
      companyName: "",
      location: "",
      employmentType: "",
      startDate: "",
      endDate: "",
      currentlyWorking: false,
      description: "",
    },
  ],

  education: [
    {
      degree: "",
      fieldOfStudy: "",
      institution: "",
      location: "",
      startYear: "",
      endYear: "",
      percentage: "",
    },
  ],

  projects: [
    {
      name: "",
      technologies: "",
      description: "",
      role: "",
      github: "",
      liveUrl: "",
      startDate: "",
      endDate: "",
    },
  ],

  certifications: [
    {
      name: "",
      organization: "",
      issueDate: "",
    },
  ],

  languages: [{ name: "", proficiency: "" }],

  internships: [
    {
      companyName: "",
      role: "",
      startDate: "",
      endDate: "",
      description: "",
    },
  ],

  template: "modern" as TemplateType,
};

export default function ResumeBuilder() {
  const [form, setForm] = useState(initialState);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [aiResume, setAiResume] = useState<string | null>(null);

  const TemplateComponent =
    TEMPLATES[form.template as TemplateType];

  const API_URL =
    process.env.NEXT_PUBLIC_API_URL || "http://localhost:5000/api";

  // -----------------------------
  // BASIC CHANGE HANDLER
  // -----------------------------
  const handleChange = (
    e: React.ChangeEvent<
      HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement
    >
  ) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  // -----------------------------
  // ARRAY HANDLERS
  // -----------------------------
  const handleArrayChange = (
    section: keyof typeof initialState,
    idx: number,
    field: string,
    value: any
  ) => {
    setForm((prev: any) => ({
      ...prev,
      [section]: prev[section].map((item: any, i: number) =>
        i === idx ? { ...item, [field]: value } : item
      ),
    }));
  };

  const handleAddItem = (
    section: keyof typeof initialState,
    emptyObj: any
  ) => {
    setForm((prev: any) => ({
      ...prev,
      [section]: [...prev[section], emptyObj],
    }));
  };

  const handleRemoveItem = (
    section: keyof typeof initialState,
    idx: number
  ) => {
    setForm((prev: any) => ({
      ...prev,
      [section]: prev[section].filter(
        (_: any, i: number) => i !== idx
      ),
    }));
  };

  const handleTemplateChange = (
    e: React.ChangeEvent<HTMLSelectElement>
  ) => {
    setForm({
      ...form,
      template: e.target.value as TemplateType,
    });
  };

  // -----------------------------
  // SAVE RESUME
  // -----------------------------
  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError("");

    try {
      await axios.post(`${API_URL}/resume`, {
        ...form,
        userId: 1,
      });
      alert("Resume saved!");
    } catch {
      setError("Failed to save resume.");
    } finally {
      setLoading(false);
    }
  };

  // -----------------------------
  // PDF DOWNLOAD
  // -----------------------------
  const handleDownload = () => {
    const element = document.getElementById("resume-preview");
    if (!element) return;

    html2pdf()
      .set({
        margin: 0.5,
        filename: "resume.pdf",
        html2canvas: { scale: 2 },
        jsPDF: { unit: "in", format: "a4", orientation: "portrait" },
      })
      .from(element)
      .save();
  };

  // -----------------------------
  // AI RESUME
  // -----------------------------
  const handleGenerateAIResume = async () => {
    setLoading(true);
    setError("");
    setAiResume(null);

    try {
      const response = await axios.post(
        `${API_URL}/interviews/ai-resume`,
        form
      );

      if (response.data?.resume) {
        setAiResume(response.data.resume);
      } else {
        setError("AI did not return a resume.");
      }
    } catch {
      setError("Failed to generate AI resume.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col md:flex-row gap-8 p-4 md:p-8 w-full">
      {/* FORM */}
      <form
        className="w-full md:w-1/2 bg-white rounded-lg shadow p-6 space-y-4 overflow-y-auto max-h-[90vh]"
        onSubmit={handleSubmit}
      >
        <h2 className="text-2xl font-bold mb-4">
          Resume Builder
        </h2>

        <input
          name="fullName"
          value={form.fullName}
          onChange={handleChange}
          placeholder="Full Name"
          className="border p-2 w-full"
        />

        <textarea
          name="summary"
          value={form.summary}
          onChange={handleChange}
          className="border p-2 w-full"
          placeholder="Summary"
        />

        <button
          type="submit"
          disabled={loading}
          className="bg-blue-600 text-white px-4 py-2"
        >
          {loading ? "Saving..." : "Save Resume"}
        </button>

        <button
          type="button"
          onClick={handleDownload}
          className="bg-green-600 text-white px-4 py-2 ml-2"
        >
          Download PDF
        </button>

        <button
          type="button"
          onClick={handleGenerateAIResume}
          className="bg-purple-600 text-white px-4 py-2 ml-2"
        >
          Generate AI Resume
        </button>

        {error && (
          <p className="text-red-500">{error}</p>
        )}
      </form>

      {/* PREVIEW */}
      <div className="w-full md:w-1/2 bg-gray-50 p-6">
        <h2 className="text-xl font-semibold mb-4">
          Live Preview
        </h2>

        <div id="resume-preview">
          {aiResume ? (
            <div className="whitespace-pre-line">
              {aiResume}
            </div>
          ) : (
            <TemplateComponent {...form} />
          )}
        </div>
      </div>
    </div>
  );
}

"use client"

import * as React from "react"
import { useRouter } from "next/navigation"
import { Search, Loader2, BookOpen, User } from "lucide-react"
import { Input } from "@/components/ui/input"
import { Button } from "@/components/ui/button"
import { searchApi } from "@/lib/api"


interface SearchCourse {
    id: string
    title: string
}

interface SearchInstructor {
    id: string
    name: string
}

export function GlobalSearch() {
    const router = useRouter()
    const [query, setQuery] = React.useState("")
    const [results, setResults] = React.useState<{ courses: SearchCourse[]; instructors: SearchInstructor[] } | null>(null)
    const [isLoading, setIsLoading] = React.useState(false)
    const [isOpen, setIsOpen] = React.useState(false)
    const searchRef = React.useRef<HTMLDivElement>(null)

    // Quick debounce implementation if hook missing
    React.useEffect(() => {
        const timer = setTimeout(() => {
            if (query.length >= 2) {
                performSearch(query)
            } else {
                setResults(null)
                setIsOpen(false)
            }
        }, 400)
        return () => clearTimeout(timer)
    }, [query])

    const performSearch = async (q: string) => {
        setIsLoading(true)
        try {
            const res = await searchApi.global(q)
            setResults(res.data)
            setIsOpen(true)
        } catch (err) {
            console.error(err)
        } finally {
            setIsLoading(false)
        }
    }

    // Close on click outside
    React.useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (searchRef.current && !searchRef.current.contains(event.target as Node)) {
                setIsOpen(false)
            }
        }
        document.addEventListener("mousedown", handleClickOutside)
        return () => document.removeEventListener("mousedown", handleClickOutside)
    }, [])

    const handleSelect = (url: string) => {
        setIsOpen(false)
        setQuery("")
        router.push(url)
    }

    return (
        <div className="relative w-full max-w-sm ml-4 hidden md:block" ref={searchRef}>
            <div className="relative">
                <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
                <Input
                    type="search"
                    placeholder="Search courses, mentors..."
                    className="pl-8 w-[250px] lg:w-[320px] bg-background"
                    value={query}
                    onChange={(e) => setQuery(e.target.value)}
                    onFocus={() => { if (results) setIsOpen(true) }}
                />
                {isLoading && (
                    <Loader2 className="absolute right-2.5 top-2.5 h-4 w-4 animate-spin text-muted-foreground" />
                )}
            </div>

            {isOpen && results && (
                <div className="absolute top-full mt-2 w-full bg-popover text-popover-foreground shadow-md rounded-md border p-2 z-50">
                    {results.courses.length === 0 && results.instructors.length === 0 ? (
                        <div className="p-4 text-center text-sm text-muted-foreground">No results found.</div>
                    ) : (
                        <div className="max-h-[300px] overflow-y-auto space-y-4">
                            {/* Courses */}
                            {results.courses.length > 0 && (
                                <div>
                                    <h4 className="text-xs font-semibold text-muted-foreground mb-2 px-2">Courses</h4>
                                    <div className="space-y-1">
                                        {results.courses.map((c) => (
                                            <div
                                                key={c.id}
                                                className="flex items-center gap-2 p-2 hover:bg-muted rounded cursor-pointer text-sm"
                                                onClick={() => handleSelect(`/courses/${c.id}`)}
                                            >
                                                <BookOpen className="h-4 w-4 text-primary" />
                                                <span>{c.title}</span>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            )}

                            {/* Instructors */}
                            {results.instructors.length > 0 && (
                                <div>
                                    <h4 className="text-xs font-semibold text-muted-foreground mb-2 px-2 mt-2">Mentors</h4>
                                    <div className="space-y-1">
                                        {results.instructors.map((i) => (
                                            <div
                                                key={i.id}
                                                className="flex items-center gap-2 p-2 hover:bg-muted rounded cursor-pointer text-sm"
                                                onClick={() => handleSelect(`/mentors/${i.id}`)} // Assuming mentor profile page
                                            >
                                                <User className="h-4 w-4 text-blue-500" />
                                                <span>{i.name}</span>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            )}
                        </div>
                    )}
                </div>
            )}
        </div>
    )
}

